   311	struct atombios_display_path {
   312		uint8_t  connector_type;	/* 1=HDMI, 2=DP/eDP, 3=DVI, 4=VGA, 5=DVI-I */
   313		uint8_t  encoder_obj_id;	/* ENCODER_OBJECT_ID_* */
   314		uint8_t  encoder_type;		/* GRAPH_OBJECT_ENUM_ID */
   315		uint8_t  i2c_line;		/* ATOM I2C line ID for DDC */
   316		uint8_t  i2c_valid;		/* DDC line was found in connector records */
   317		uint8_t  hpd_id;		/* normalized HPD pin (0-5, ATOMBIOS_HPD_NONE if none) */
   318		uint8_t  dig_encoder;		/* DIG index (0=DIG1, ...) for digital */
   319		uint8_t  phy_id;		/* UNIPHY ID (0=A, 1=B, ...) for digital */
   320		uint8_t  encoder_mode;		/* ATOM_ENCODER_MODE_* */
   321		uint8_t  dp_lane_count;		/* negotiated DP lane count */
   322		uint8_t  dp_link_bw;		/* DPCD DP_LINK_BW_* code */
   323		uint8_t  dp_panel_mode;		/* DP_PANEL_MODE_* */
   324		uint8_t  pll_id;			/* PPLL/refclock selected for this path */
   325		uint8_t  tx_refclk;		/* Transmitter reference-clock source */
   326		uint16_t connector_obj_id;	/* Full connector object ID */
   327		uint8_t  is_dac;		/* 1 if DAC encoder (VGA/CRT), 0 if digital */
   328		uint8_t  is_legacy_tmds;	/* 1 for pre-UNIPHY TMDS/LVTMA encoders */
   329		uint8_t  is_legacy_lvds;	/* 1 for LVDSEncoderControl/LCD1OutputControl */
   330		uint8_t  lcd_misc;		/* normalized ATOM_PANEL_MISC_* flags */
   331		uint8_t  dac_type;		/* ATOM_DAC_A or ATOM_DAC_B */
   332		uint16_t device_tag;		/* ATOM_DEVICE_*_SUPPORT bit */
   333	};
