   403	static struct atombios_gpu_profile atombios_get_gpu_profile(uint16_t device_id)
   404	{
   405		struct atombios_gpu_profile profile = {
   406			.mc = ATOMBIOS_MC_R700,
   407			.scanout = ATOMBIOS_SCANOUT_EVERGREEN,
   408			.si_pipe = ATOMBIOS_SI_PIPE_NONE,
   409			.dispclk_ppll = ATOM_DCPLL,
   410			.pixel_clock_ppll = ATOM_PPLL1,
   411			.use_set_dce_clock = false,
   412			.use_combo_phy_pixel_clock = false,
   413			.use_cik_desktop_height = false,
   414			.use_tile_mode_pipe_config = false,
   415			.use_crtc_mem_req = true,
   416			.dp_refclk_dcpll = false,
   417			.dce61 = false,
   418			.config_memsize_in_mb = true,
   419			.integrated = false,
   420			.has_display = true,
   421			.supported = true,
   422		};
   423	
   424		switch (device_id) {
   425		/* R600/RV6xx/RS780/RS880 use R600 MC registers and AVIVO scanout. */
   426		case 0x9400: case 0x9401: case 0x9402: case 0x9403:
   427		case 0x9405: case 0x940A: case 0x940B: case 0x940F:
   428		case 0x94C0: case 0x94C1: case 0x94C3: case 0x94C4:
   429		case 0x94C5: case 0x94C6: case 0x94C7: case 0x94C8:
   430		case 0x94C9: case 0x94CB: case 0x94CC: case 0x94CD:
   431		case 0x9580: case 0x9581: case 0x9583: case 0x9586:
   432		case 0x9587: case 0x9588: case 0x9589: case 0x958A:
   433		case 0x958B: case 0x958C: case 0x958D: case 0x958E: case 0x958F:
   434		case 0x95C0: case 0x95C2: case 0x95C4: case 0x95C5:
   435		case 0x95C6: case 0x95C7: case 0x95C9: case 0x95CC:
   436		case 0x95CD: case 0x95CE: case 0x95CF:
   437		case 0x9590: case 0x9591: case 0x9593: case 0x9595:
   438		case 0x9596: case 0x9597: case 0x9598: case 0x9599: case 0x959B:
   439		case 0x9500: case 0x9501: case 0x9504: case 0x9505:
   440		case 0x9506: case 0x9507: case 0x9508: case 0x9509:
   441		case 0x950F: case 0x9511: case 0x9515: case 0x9517: case 0x9519:
   442		case 0x9610: case 0x9611: case 0x9612: case 0x9613:
   443		case 0x9614: case 0x9615: case 0x9616:
   444		case 0x9710: case 0x9711: case 0x9712: case 0x9713:
   445		case 0x9714: case 0x9715:
   446			profile.mc = ATOMBIOS_MC_R600;
   447			profile.scanout = ATOMBIOS_SCANOUT_AVIVO;
   448			profile.config_memsize_in_mb = false;
   449			break;
   450	
   451		/* RV7xx uses the R700 MC location but keeps the AVIVO display registers. */
   452		case 0x9440: case 0x9441: case 0x9442: case 0x9443:
   453		case 0x9444: case 0x9446: case 0x944A: case 0x944B:
   454		case 0x944C: case 0x944E: case 0x9450: case 0x9452:
   455		case 0x9456: case 0x945A: case 0x945B: case 0x945E:
   456		case 0x9460: case 0x9462: case 0x946A: case 0x946B:
   457		case 0x947A: case 0x947B:
   458		case 0x9480: case 0x9487: case 0x9488: case 0x9489:
   459		case 0x948A: case 0x948F: case 0x9490: case 0x9491:
   460		case 0x9495: case 0x9498: case 0x949C: case 0x949E: case 0x949F:
   461		case 0x9540: case 0x9541: case 0x9542: case 0x954E:
   462		case 0x954F: case 0x9552: case 0x9553: case 0x9555:
   463		case 0x9557: case 0x955F:
   464		case 0x94A0: case 0x94A1: case 0x94A3: case 0x94B1:
   465		case 0x94B3: case 0x94B4: case 0x94B5: case 0x94B9:
   466			profile.scanout = ATOMBIOS_SCANOUT_AVIVO;
   467			profile.config_memsize_in_mb = false;
   468			break;
   469	
   470		/* Palm/Sumo report the VRAM size register in bytes, not MiB. */
   471		case 0x9802: case 0x9803: case 0x9804: case 0x9805:
   472		case 0x9806: case 0x9807: case 0x9808: case 0x9809: case 0x980A:
   473		case 0x9640: case 0x9641: case 0x9642: case 0x9643:
   474		case 0x9644: case 0x9645: case 0x9647: case 0x9648:
   475		case 0x9649: case 0x964A: case 0x964B: case 0x964C:
   476		case 0x964E: case 0x964F:
   477			profile.config_memsize_in_mb = false;
   478			break;
   479	
   480		/* Southern Islands needs the SI pipe field in GRPH_CONTROL. */
   481		case 0x6780: case 0x6784: case 0x6788: case 0x678A:
   482		case 0x6790: case 0x6791: case 0x6792: case 0x6798:
   483		case 0x6799: case 0x679A: case 0x679B: case 0x679E: case 0x679F:
   484		case 0x6800: case 0x6801: case 0x6802: case 0x6806:
   485		case 0x6808: case 0x6809: case 0x6810: case 0x6811:
   486		case 0x6816: case 0x6817: case 0x6818: case 0x6819:
   487			profile.si_pipe = ATOMBIOS_SI_PIPE_P8_32X32_8X16;
   488			profile.dispclk_ppll = ATOM_PPLL0;
   489			profile.pixel_clock_ppll = ATOM_PPLL0;
   490			break;
   491		case 0x6820: case 0x6821: case 0x6822: case 0x6823:
   492		case 0x6824: case 0x6825: case 0x6826: case 0x6827:
   493		case 0x6828: case 0x6829: case 0x682A: case 0x682B:
   494		case 0x682C: case 0x682D: case 0x682F: case 0x6830:
   495		case 0x6831: case 0x6835: case 0x6837: case 0x6838:
   496		case 0x6839: case 0x683B: case 0x683D: case 0x683F:
   497		case 0x6600: case 0x6601: case 0x6602: case 0x6603:
   498		case 0x6604: case 0x6605: case 0x6606: case 0x6607:
   499		case 0x6608: case 0x6610: case 0x6611: case 0x6613:
   500		case 0x6617: case 0x6620: case 0x6621: case 0x6623: case 0x6631:
   501			profile.si_pipe = ATOMBIOS_SI_PIPE_P4_8X16;
   502			profile.dispclk_ppll = ATOM_PPLL0;
   503			profile.pixel_clock_ppll = ATOM_PPLL0;
   504			break;
   505		case 0x6660: case 0x6663: case 0x6664: case 0x6665:
   506		case 0x6667: case 0x666F:
   507			profile.has_display = false;
   508			profile.supported = false;
   509			break;
   510	
   511		/* CIK/DCE8 and VI/DCE10 use the CIK desktop-height register. */
   512		case 0x6640: case 0x6641: case 0x6646: case 0x6647: case 0x6649:
   513		case 0x6650: case 0x6651: case 0x6658: case 0x665C: case 0x665D: case 0x665F:
   514		case 0x1304: case 0x1305: case 0x1306: case 0x1307: case 0x1309: case 0x130A: case 0x130B:
   515		case 0x130C: case 0x130D: case 0x130E: case 0x130F: case 0x1310: case 0x1311: case 0x1312:
   516		case 0x1313: case 0x1315: case 0x1316: case 0x1317: case 0x1318: case 0x131B: case 0x131C: case 0x131D:
   517			profile.si_pipe = ATOMBIOS_SI_PIPE_P4_8X16;
   518			profile.dispclk_ppll = ATOM_EXT_PLL1;
   519			profile.pixel_clock_ppll = ATOM_PPLL2;
   520			profile.use_cik_desktop_height = true;
   521			profile.use_tile_mode_pipe_config = true;
   522			break;
   523		case 0x67A0: case 0x67A1: case 0x67A2: case 0x67A8: case 0x67A9: case 0x67AA:
   524		case 0x67B0: case 0x67B1: case 0x67B8: case 0x67B9: case 0x67BA: case 0x67BE:
   525		case 0x6920: case 0x6921: case 0x6928: case 0x6929: case 0x692B: case 0x692F:
   526		case 0x6930: case 0x6938: case 0x6939: case 0x7300: case 0x730F:
   527			profile.si_pipe = ATOMBIOS_SI_PIPE_P8_32X32_8X16;
   528			profile.dispclk_ppll = ATOM_EXT_PLL1;
   529			profile.pixel_clock_ppll = ATOM_PPLL2;
   530			profile.use_cik_desktop_height = true;
   531			profile.use_tile_mode_pipe_config = true;
   532			break;
   533		case 0x9830: case 0x9831: case 0x9832: case 0x9833: case 0x9834: case 0x9835: case 0x9836: case 0x9837:
   534		case 0x9838: case 0x9839: case 0x983A: case 0x983B: case 0x983C: case 0x983D: case 0x983E: case 0x983F:
   535		case 0x9850: case 0x9851: case 0x9852: case 0x9853: case 0x9854: case 0x9855: case 0x9856: case 0x9857:
   536		case 0x9858: case 0x9859: case 0x985A: case 0x985B: case 0x985C: case 0x985D: case 0x985E: case 0x985F:
   537			profile.dispclk_ppll = ATOM_EXT_PLL1;
   538			profile.pixel_clock_ppll = ATOM_PPLL2;
   539			profile.use_cik_desktop_height = true;
   540			profile.use_tile_mode_pipe_config = true;
   541			break;
   542		/* DCE11.0 uses the DCE clock manager but still programs DISPCLK via
   543		 * SetPixelClock, with DFS selected as ATOM_EXT_PLL1. */
   544		case 0x9870: case 0x9874: case 0x9875: case 0x9876: case 0x9877:
   545		case 0x98E4:
   546			profile.dispclk_ppll = ATOM_EXT_PLL1;
   547			profile.pixel_clock_ppll = ATOM_PPLL0;
   548			profile.use_cik_desktop_height = true;
   549			profile.use_tile_mode_pipe_config = true;
   550			break;
   551		case 0x67C0: case 0x67C1: case 0x67C2: case 0x67C4: case 0x67C7: case 0x67C8: case 0x67C9:
   552		case 0x67CA: case 0x67CC: case 0x67CF: case 0x67D0: case 0x67DF: case 0x6FDF:
   553		case 0x694C: case 0x694E: case 0x694F:
   554			profile.si_pipe = ATOMBIOS_SI_PIPE_P8_32X32_8X16;
   555			profile.dispclk_ppll = ATOM_GCK_DFS;
   556			profile.pixel_clock_ppll = ATOM_COMBOPHY_PLL0;
   557			profile.use_set_dce_clock = true;
   558			profile.use_combo_phy_pixel_clock = true;
   559			profile.use_cik_desktop_height = true;
   560			profile.use_tile_mode_pipe_config = true;
   561			break;
   562		case 0x67E0: case 0x67E1: case 0x67E3: case 0x67E7: case 0x67E8: case 0x67E9:
   563		case 0x67EB: case 0x67EF: case 0x67FF:
   564		case 0x6980: case 0x6981: case 0x6985: case 0x6986: case 0x6987: case 0x6995: case 0x6997: case 0x699F:
   565			profile.si_pipe = ATOMBIOS_SI_PIPE_P4_8X16;
   566			profile.dispclk_ppll = ATOM_GCK_DFS;
   567			profile.pixel_clock_ppll = ATOM_COMBOPHY_PLL0;
   568			profile.use_set_dce_clock = true;
   569			profile.use_combo_phy_pixel_clock = true;
   570			profile.use_cik_desktop_height = true;
   571			profile.use_tile_mode_pipe_config = true;
   572			break;
   573		/* Topaz has no DCE in Linux amdgpu. */
   574		case 0x6900: case 0x6901: case 0x6902: case 0x6903: case 0x6907:
   575			profile.has_display = false;
   576			profile.supported = false;
   577			break;
   578		}
   579	
   580		/* Linux only uses EnableCRTCMemReq on DCE3 through DCE5. */
   581		if (profile.si_pipe != ATOMBIOS_SI_PIPE_NONE ||
   582		    profile.use_cik_desktop_height || profile.use_set_dce_clock)
   583			profile.use_crtc_mem_req = false;
   584	
   585		profile.integrated =
   586			(device_id >= 0x9610 && device_id <= 0x9616) ||
   587			(device_id >= 0x9710 && device_id <= 0x9715) ||
   588			(device_id >= 0x9802 && device_id <= 0x980a) ||
   589			(device_id >= 0x9640 && device_id <= 0x964f) ||
   590			(device_id >= 0x1304 && device_id <= 0x131d) ||
   591			(device_id >= 0x9830 && device_id <= 0x983f) ||
   592			(device_id >= 0x9850 && device_id <= 0x985f) ||
   593			(device_id >= 0x9870 && device_id <= 0x9877) ||
   594			(device_id >= 0x9900 && device_id <= 0x99a4) ||
   595			device_id == 0x98e4;
   596	
   597		/* DCE5 uses DCPLL as the DP transmitter reference clock. */
   598		profile.dp_refclk_dcpll =
   599			(device_id >= 0x6700 && device_id <= 0x677b) ||
   600			(device_id >= 0x6840 && device_id <= 0x6859);
   601		profile.dce61 = device_id >= 0x9900 && device_id <= 0x99a4;
   602		if (profile.dce61)
   603			profile.use_crtc_mem_req = false;
   604	
   605		return profile;
   606	}
