   609	
   610	static void cail_reg_write(struct card_info *info, uint32_t reg, uint32_t val)
   611	{
   612		write32((uint8_t *)info->mmio_base + reg * 4, val);
   613	}
   614	
   615	static uint32_t cail_reg_read(struct card_info *info, uint32_t reg)
   616	{
   617		return read32((uint8_t *)info->mmio_base + reg * 4);
   618	}
