--- dcn10 320-700 ---
   320		dcn10_write(mmio, OTG_V_TOTAL, v_total - 1);
   321		dcn10_write(mmio, OTG_V_TOTAL_MIN, v_total - 1);
   322		dcn10_write(mmio, OTG_V_TOTAL_MAX, v_total - 1);
   323		dcn10_write(mmio, OTG_V_SYNC_A, (uint32_t)timing->v_sync_width << 16);
   324		dcn10_write(mmio, OTG_V_BLANK_START_END,
   325			    v_blank_start | (v_blank_end << 16));
   326		dcn10_update(mmio, OTG_V_SYNC_A_CNTL, 1,
   327			     timing->vsync_positive ? 0 : 1);
   328		dcn10_write(mmio, OTG_INTERLACE_CONTROL, 0);
   329		dcn10_write(mmio, OTG_VSTARTUP_PARAM, calc.vstartup);
   330		dcn10_write(mmio, OTG_VUPDATE_PARAM, calc.vupdate);
   331		dcn10_write(mmio, OTG_VREADY_PARAM, calc.vready);
   332		dcn10_update(mmio, OTG_CONTROL, 0x7000, 1U << 12);
   333		dcn10_update(mmio, VTG_CONTROL, 0x3fff8000,
   334			     (v_total - timing->v_front_porch) << 15);
   335		dcn10_update(mmio, OPTC_DATA_SOURCE_SELECT, 0x700, 0);
   336		dcn10_update(mmio, VTG_CONTROL, 0x80000000, 0x80000000);
   337		dcn10_update(mmio, OTG_CONTROL, 0x301, 0x301);
   338		if (dcn10_wait(mmio, OTG_CONTROL, OTG_CURRENT_MASTER_EN,
   339				 OTG_CURRENT_MASTER_EN, 20000))
   340			return -1;
   341		frame = dcn10_read(mmio, OTG_STATUS_FRAME_COUNT);
   342		mdelay(20);
   343		if (frame == dcn10_read(mmio, OTG_STATUS_FRAME_COUNT))
   344			return -1;
   345		return 0;
   346	}
