   418	static void dcn10_fill_test_pattern(void *address, uint32_t pitch,
   419					    uint16_t width, uint16_t height)
   420	{
   421		static const uint32_t colors[] = {
   422			0xffff0000, 0xffffff00, 0xff00ff00,
   423			0xff00ffff, 0xff0000ff, 0xffff00ff,
   424		};
   425		uint16_t x, y;
   426	
   427		for (y = 0; y < height; y++) {
   428			uint32_t *row = (uint32_t *)((uint8_t *)address + y * pitch);
   429	
   430			for (x = 0; x < width; x++)
   431				row[x] = colors[(x * 6U) / width];
   432		}
   433	}
   434	
   435	int dcn10_program_scanout(void *mmio, uint64_t gpu_address,
   436				  void *cpu_address, size_t aperture_size,
   437				  const struct dcn10_timing *timing,
   438				  uint32_t *pitch_bytes)
   439	{
   440		struct dcn10_plane_regs calc;
   441		uint32_t pitch_pixels, pitch, dimensions, hubp_cntl;
   442		uint32_t fb_base, fb_top, addr_config;
   443		unsigned int i;
   444	
   445		if (!mmio || !cpu_address || !gpu_address || !timing || !pitch_bytes ||
   446		    (gpu_address & 0xff))
   447			return -1;
   448		pitch_pixels = (timing->h_active + 63U) & ~63U;
   449		pitch = pitch_pixels * 4;
   450		if (dcn10_calculate_plane(timing, pitch_pixels, &calc) ||
   451		    aperture_size < (size_t)pitch * timing->v_active)
   452			return -1;
   453		fb_base = dcn10_read(mmio, DCHUBBUB_SDPIF_FB_BASE) & 0xffffff;
   454		fb_top = dcn10_read(mmio, DCHUBBUB_SDPIF_FB_TOP) & 0xffffff;
   455		if (!dcn10_surface_in_local_fb(gpu_address,
   456						(size_t)pitch * timing->v_active,
   457						fb_base, fb_top)) {
   458			printk(BIOS_ERR,
   459			       "ATOMBIOS: DCN1 surface outside local FB (%06x-%06x)\n",
   460			       fb_base, fb_top);
   461			return -1;
   462		}
   463		if (dcn10_addr_config(mmio, &addr_config)) {
   464			printk(BIOS_ERR, "ATOMBIOS: unsupported GFX9 address topology\n");
   465			return -1;
   466		}
   467	
   468		/* Linux FRAME_BUFFER_MODE_LOCAL_ONLY; preserve VBIOS FB base/top/offset. */
   469		dcn10_write(mmio, DCHUBBUB_SDPIF_AGP_BASE, 0);
   470		dcn10_write(mmio, DCHUBBUB_SDPIF_AGP_BOT, 0x03ffff);
   471		dcn10_write(mmio, DCHUBBUB_SDPIF_AGP_TOP, 0);
   472		dcn10_program_watermarks(mmio, &calc);
   473	
   474		if (dcn10_lock(mmio, 1))
   475			return -1;
   476		if (dcn10_power_on_plane(mmio))
   477			goto fail_unlock;
   478		hubp_cntl = dcn10_read(mmio, DCHUBP_CNTL);
   479		hubp_cntl &= ~HUBP_VTG_SEL_MASK;
   480		hubp_cntl |= HUBP_BLANK_EN | HUBP_TTU_DISABLE;
   481		dcn10_write(mmio, DCHUBP_CNTL, hubp_cntl);
   482		if (dcn10_wait(mmio, DCHUBP_CNTL, HUBP_NO_OUTSTANDING_REQ,
   483				 HUBP_NO_OUTSTANDING_REQ, 1000))
   484			goto fail_unlock;
   485	
   486		dcn10_update(mmio, HUBP_CLK_CNTL, HUBP_CLOCK_ENABLE, HUBP_CLOCK_ENABLE);
   487		dcn10_update(mmio, DPP_CONTROL, DPP_CLOCK_ENABLE, DPP_CLOCK_ENABLE);
   488		dcn10_update(mmio, OPP_PIPE_CONTROL,
   489			     OPP_PIPE_CLOCK_ENABLE, OPP_PIPE_CLOCK_ENABLE);
   490		/* Physical local-FB addresses: disable page-table and metadata requests. */
   491		dcn10_write(mmio, DCN_VM_MX_L1_TLB_CNTL, 0);
   492		dcn10_write(mmio, DCSURF_SURFACE_CONTROL, 0);
   493		dcn10_program_deadlines(mmio, &calc);
   494	
   495		/* Complete fixed RGB bypass state. */
   496		dcn10_write(mmio, CNVC_SURFACE_PIXEL_FORMAT, 8);
   497		dcn10_write(mmio, CNVC_FORMAT_CONTROL, 1U << 8);
   498		dcn10_write(mmio, CM_IGAM_CONTROL, 2U << 26);
   499		dcn10_write(mmio, CM_ICSC_CONTROL, 0);
   500		dcn10_write(mmio, CM_GAMUT_REMAP_CONTROL, 0);
   501		dcn10_write(mmio, CM_OCSC_CONTROL, 0);
   502		dcn10_write(mmio, CM_RGAM_CONTROL, 0);
   503		dcn10_write(mmio, CM_HDR_MULT_COEF, CM_HDR_MULT_ONE);
   504		dcn10_write(mmio, CM_BNS_VALUES_R, CM_BNS_SCALE_UNITY);
   505		dcn10_write(mmio, CM_BNS_VALUES_G, CM_BNS_SCALE_UNITY);
   506		dcn10_write(mmio, CM_BNS_VALUES_B, CM_BNS_SCALE_UNITY);
   507		dcn10_write(mmio, CNVC_CURSOR0_CONTROL, 0);
   508		dcn10_write(mmio, HUBP_CURSOR_CONTROL, 0);
   509		dcn10_write(mmio, DSCL_AUTOCAL, 0);
   510		dcn10_write(mmio, DSCL_CONTROL, 0);
   511		dcn10_write(mmio, DSCL_RECOUT_START, 0);
   512		dimensions = ((uint32_t)timing->v_active << 16) | timing->h_active;
   513		dcn10_write(mmio, DSCL_RECOUT_SIZE, dimensions);
   514		dcn10_write(mmio, DSCL_MPC_SIZE, dimensions);
   515		dcn10_write(mmio, DSCL_LB_DATA_FORMAT,
   516			    LB_PIXEL_DEPTH_36BPP | LB_PIXEL_REDUCE_MODE);
   517		dcn10_write(mmio, DSCL_LB_MEMORY_CTRL,
   518			    LB_MEMORY_CONFIG_1 | LB_MAX_PARTITIONS);
   519		dcn10_update(mmio, DSCL_SCL_MODE, 0x7,
   520			     DSCL_MODE_SCALING_444_BYPASS);
   521	
   522		/* Known disconnected MPCC0, then DPP0 -> MPCC0 -> OPP0. */
   523		if (dcn10_wait(mmio, MPCC0_STATUS, 1, 1, 1000))
   524			goto fail_unlock;
   525		dcn10_update(mmio, MPCC0_BOT_SEL, 0xf, 0xf);
   526		dcn10_write(mmio, MPCC0_CONTROL, 2 | (0xffU << 16) | (0xffU << 24));
   527		dcn10_update(mmio, MPCC0_TOP_SEL, 0xf, 0);
   528		dcn10_update(mmio, MPCC0_OPP_ID, 0xf, 0);
   529		dcn10_update(mmio, MPCC0_UPDATE_LOCK_SEL, 0xf, 0);
   530		dcn10_update(mmio, MPC_OUT0_MUX, 0xf, 0);
   531		/* Linux leaves DCN1 FMT defaults for 8-bpc RGB; clear stale dither/clamp. */
   532		dcn10_write(mmio, FMT_CONTROL, 0);
   533		dcn10_write(mmio, FMT_BIT_DEPTH_CONTROL, 0);
   534		dcn10_write(mmio, FMT_CLAMP_CNTL, 0);
   535	
   536		dcn10_write(mmio, DCSURF_ADDR_CONFIG, addr_config);
   537		dcn10_write(mmio, DCSURF_TILING_CONFIG, 0);
   538		dcn10_update(mmio, DCSURF_SURFACE_CONFIG, 0x0000077f, 8);
   539		dcn10_write(mmio, DCSURF_SURFACE_PITCH, pitch_pixels - 1);
   540		dcn10_write(mmio, DCSURF_PRI_VIEWPORT_START, 0);
   541		dcn10_write(mmio, DCSURF_PRI_VIEWPORT_DIMENSION, dimensions);
   542		dcn10_write(mmio, DCSURF_PRI_VIEWPORT_START_C, 0);
   543		dcn10_write(mmio, DCSURF_PRI_VIEWPORT_DIMENSION_C, 0);
   544		dcn10_write(mmio, DCSURF_SEC_VIEWPORT_START, 0);
   545		dcn10_write(mmio, DCSURF_SEC_VIEWPORT_DIMENSION, dimensions);
   546		dcn10_write(mmio, DCSURF_SEC_VIEWPORT_START_C, 0);
   547		dcn10_write(mmio, DCSURF_SEC_VIEWPORT_DIMENSION_C, 0);
   548		dcn10_update(mmio, DCSURF_FLIP_CONTROL, 0x7, 0);
   549		dcn10_update(mmio, HUBPRET_CONTROL, 0x00f00fff, 0x00e00000);
   550	
   551		dcn10_fill_test_pattern(cpu_address, pitch,
   552					timing->h_active, timing->v_active);
   553		dcn10_write(mmio, DCSURF_PRIMARY_ADDRESS_HIGH, gpu_address >> 32);
   554		dcn10_write(mmio, DCSURF_PRIMARY_ADDRESS, gpu_address);
   555		hubp_cntl = dcn10_read(mmio, DCHUBP_CNTL);
   556		hubp_cntl &= ~(HUBP_BLANK_EN | HUBP_DISABLE | HUBP_TTU_DISABLE |
   557			       HUBP_VTG_SEL_MASK | HUBP_UNDERFLOW_STATUS);
   558		dcn10_write(mmio, DCHUBP_CNTL, hubp_cntl);
   559		if (dcn10_lock(mmio, 0))
   560			return -1;
   561	
   562		/* Plane is committed; now permit stream pixels. */
   563		dcn10_update(mmio, OTG_BLANK_CONTROL, 0x00010100, 0);
   564		for (i = 0; i < 50; i++) {
   565			uint64_t earliest;
   566	
   567			mdelay(1);
   568			earliest = ((uint64_t)dcn10_read(mmio, DCSURF_EARLIEST_INUSE_HIGH) << 32) |
   569				dcn10_read(mmio, DCSURF_EARLIEST_INUSE);
   570			if (!(dcn10_read(mmio, DCHUBP_CNTL) & HUBP_IN_BLANK) &&
   571			    earliest == gpu_address)
   572				break;
   573		}
   574		if (i == 50 || (dcn10_read(mmio, DCHUBP_CNTL) & HUBP_UNDERFLOW_STATUS)) {
   575			printk(BIOS_ERR,
   576			       "ATOMBIOS: DCN1 plane commit failed cntl=0x%08x earliest=0x%08x%08x\n",
   577			       dcn10_read(mmio, DCHUBP_CNTL),
   578			       dcn10_read(mmio, DCSURF_EARLIEST_INUSE_HIGH),
   579			       dcn10_read(mmio, DCSURF_EARLIEST_INUSE));
   580			dcn10_update(mmio, OTG_BLANK_CONTROL, 0x00010100, 0x00000100);
   581			dcn10_update(mmio, DCHUBP_CNTL,
   582				     HUBP_BLANK_EN | HUBP_TTU_DISABLE,
   583				     HUBP_BLANK_EN | HUBP_TTU_DISABLE);
   584			return -1;
   585		}
   586		*pitch_bytes = pitch;
   587		printk(BIOS_INFO,
   588		       "ATOMBIOS: DCN1 native plane active addr=0x%016llx pitch=%u fb=%06x-%06x off=%06x\n",
   589		       (unsigned long long)gpu_address, pitch, fb_base, fb_top,
   590		       dcn10_read(mmio, DCHUBBUB_SDPIF_FB_OFFSET) & 0xffffff);
   591		return 0;
   592	
   593	fail_unlock:
   594		dcn10_lock(mmio, 0);
   595		return -1;
   596	}

