  2488	
  2489	struct atombios_pll_params {
  2490		uint32_t reference_freq;
  2491		uint32_t pll_out_min;
  2492		uint32_t pll_out_max;
  2493	};
  2494	
  2495	static void atombios_get_pll_params(struct atom_context *ctx,
  2496						    struct atombios_pll_params *pll)
  2497	{
  2498		uint16_t data_offset;
  2499		uint8_t frev, crev;
  2500		ATOM_FIRMWARE_INFO *info;
  2501	
  2502		pll->reference_freq = 2700;
  2503		pll->pll_out_min = 64800;
  2504		pll->pll_out_max = 200000;
  2505	
  2506		if (!atom_parse_data_header(ctx, cmd_idx.data_firmware_info,
  2507					    NULL, &frev, &crev, &data_offset))
  2508			return;
  2509	
  2510		info = (ATOM_FIRMWARE_INFO *)((uint8_t *)ctx->bios + data_offset);
  2511		if (info->usReferenceClock)
  2512			pll->reference_freq = info->usReferenceClock;
  2513		if (info->ulMaxPixelClockPLL_Output)
  2514			pll->pll_out_max = info->ulMaxPixelClockPLL_Output;
  2515	
  2516		if (frev < 2 && crev < 2) {
  2517			if (info->usMinPixelClockPLL_Output)
  2518				pll->pll_out_min = info->usMinPixelClockPLL_Output;
  2519		} else {
  2520			ATOM_FIRMWARE_INFO_V1_2 *info12 = (ATOM_FIRMWARE_INFO_V1_2 *)info;
  2521			if (info12->ulMinPixelClockPLL_Output)
  2522				pll->pll_out_min = info12->ulMinPixelClockPLL_Output;
  2523		}
  2524	}
  2525	
  2526	static uint32_t atombios_abs_diff_u32(uint32_t a, uint32_t b)
  2527	{
  2528		return a > b ? a - b : b - a;
  2529	}
  2530	
  2531	static uint32_t atombios_gcd_u32(uint32_t a, uint32_t b)
  2532	{
  2533		while (b) {
  2534			uint32_t t = b;
  2535			b = a % b;
  2536			a = t;
  2537		}
  2538		return a ? a : 1;
  2539	}
  2540	
  2541	static uint32_t atombios_div_round_up(uint32_t n, uint32_t d)
  2542	{
  2543		return (n + d - 1) / d;
  2544	}
  2545	
  2546	static uint32_t atombios_div_round_closest(uint64_t n, uint32_t d)
  2547	{
  2548		return (uint32_t)((n + d / 2) / d);
  2549	}
  2550	
  2551	static uint32_t atombios_clamp_u32(uint32_t v, uint32_t min, uint32_t max)
  2552	{
  2553		if (v < min)
  2554			return min;
  2555		if (v > max)
  2556			return max;
  2557		return v;
  2558	}
  2559	
  2560	static void atombios_avivo_reduce_ratio(uint32_t *nom, uint32_t *den,
  2561						uint32_t nom_min, uint32_t den_min)
  2562	{
  2563		uint32_t tmp = atombios_gcd_u32(*nom, *den);
  2564	
  2565		*nom /= tmp;
  2566		*den /= tmp;
  2567	
  2568		if (*nom < nom_min) {
  2569			tmp = atombios_div_round_up(nom_min, *nom);
  2570			*nom *= tmp;
  2571			*den *= tmp;
  2572		}
  2573	
  2574		if (*den < den_min) {
  2575			tmp = atombios_div_round_up(den_min, *den);
  2576			*nom *= tmp;
  2577			*den *= tmp;
  2578		}
  2579	}
  2580	
  2581	static void atombios_avivo_get_fb_ref_div(uint32_t nom, uint32_t den,
  2582						  uint32_t post_div,
  2583						  uint32_t fb_div_max,
  2584						  uint32_t ref_div_max,
  2585						  uint32_t *fb_div,
  2586						  uint32_t *ref_div)
  2587	{
  2588		ref_div_max = atombios_clamp_u32(100 / post_div, 1, ref_div_max);
  2589		*ref_div = atombios_clamp_u32(den / post_div, 1, ref_div_max);
  2590		*fb_div = atombios_div_round_closest((uint64_t)nom * *ref_div * post_div,
  2591						      den);
  2592	
  2593		if (*fb_div > fb_div_max) {
  2594			*ref_div = (*ref_div * fb_div_max) / *fb_div;
  2595			*fb_div = fb_div_max;
  2596		}
  2597	}
  2598	
  2599	static void atombios_compute_avivo_pll(struct atom_context *ctx,
  2600						       uint32_t target_clock,
  2601						       uint32_t *dot_clock,
  2602						       uint32_t *fb_div,
  2603						       uint32_t *frac_fb_div,
  2604						       uint32_t *ref_div,
  2605						       uint32_t *post_div)
  2606	{
  2607		struct atombios_pll_params pll;
  2608		uint32_t fb_div_min = 4;
  2609		uint32_t fb_div_max = 0x7ff;
  2610		uint32_t ref_div_min = 2;
  2611		uint32_t ref_div_max = 7;
  2612		uint32_t post_min, post_max, post;
  2613		uint32_t post_best, diff_best = 0xffffffff;
  2614		uint32_t nom, den;
  2615	
  2616		atombios_get_pll_params(ctx, &pll);
  2617	
  2618		post_min = pll.pll_out_min / target_clock;
  2619		if (target_clock * post_min < pll.pll_out_min)
  2620			post_min++;
  2621		if (post_min < 2)
  2622			post_min = 2;
  2623	
  2624		post_max = pll.pll_out_max / target_clock;
  2625		if (target_clock * post_max > pll.pll_out_max)
  2626			post_max--;
  2627		if (post_max > 0x7f)
  2628			post_max = 0x7f;
  2629		if (post_max < post_min)
  2630			post_max = post_min;
  2631	
  2632		/* Match Linux radeon_compute_pll_avivo() flags used on RV630:
  2633		 * RADEON_PLL_PREFER_LOW_REF_DIV and RADEON_PLL_PREFER_MINM_OVER_MAXP. */
  2634		nom = target_clock;
  2635		den = pll.reference_freq;
  2636		atombios_avivo_reduce_ratio(&nom, &den, fb_div_min, post_min);
  2637	
  2638		post_best = post_min;
  2639		for (post = post_min; post <= post_max; post++) {
  2640			uint32_t fb, ref, actual, diff;
  2641	
  2642			atombios_avivo_get_fb_ref_div(nom, den, post, fb_div_max,
  2643						      ref_div_max, &fb, &ref);
  2644			actual = (pll.reference_freq * fb) / (ref * post);
  2645			diff = atombios_abs_diff_u32(target_clock, actual);
  2646			if (diff < diff_best) {
  2647				post_best = post;
  2648				diff_best = diff;
  2649			}
  2650		}
  2651	
  2652		*post_div = post_best;
  2653		atombios_avivo_get_fb_ref_div(nom, den, *post_div, fb_div_max,
  2654					      ref_div_max, fb_div, ref_div);
  2655		atombios_avivo_reduce_ratio(fb_div, ref_div, fb_div_min, ref_div_min);
  2656	
  2657		*frac_fb_div = 0;
  2658		*dot_clock = (pll.reference_freq * *fb_div) / (*ref_div * *post_div);
  2659	
  2660		printk(BIOS_DEBUG,
  2661		       "ATOMBIOS: PLL ref=%u min=%u max=%u target=%u actual=%u fb=%u refdiv=%u post=%u\n",
  2662		       pll.reference_freq, pll.pll_out_min, pll.pll_out_max,
  2663		       target_clock, *dot_clock, *fb_div, *ref_div, *post_div);
  2664	}
  2665	
  2666	static uint16_t atombios_adjust_display_pll(struct atom_context *ctx,
  2667						    const struct atombios_display_path *path,
  2668						    uint16_t pixel_clock_10khz)
  2669	{
  2670		uint8_t frev, crev;
  2671		union {
  2672			ADJUST_DISPLAY_PLL_PS_ALLOCATION v1;
  2673			ADJUST_DISPLAY_PLL_PS_ALLOCATION_V3 v3;
  2674		} args;
  2675		uint16_t adjusted_clock = pixel_clock_10khz;
  2676	
  2677		/* Our DP path does not track the trained link clock yet. */
  2678		if (path->encoder_mode == ATOM_ENCODER_MODE_DP)
  2679			return adjusted_clock;
  2680	
  2681		if (cmd_idx.adjust_display_pll < 0)
  2682			return adjusted_clock;
  2683		if (!atom_parse_cmd_header(ctx, cmd_idx.adjust_display_pll, &frev, &crev))
  2684			return adjusted_clock;
  2685	
  2686		memset(&args, 0, sizeof(args));
  2687	
  2688		switch (crev) {
  2689		case 1:
  2690		case 2:
  2691			args.v1.usPixelClock = pixel_clock_10khz;
  2692			args.v1.ucTransmitterID = path->encoder_obj_id;
  2693			args.v1.ucEncodeMode = path->encoder_mode;
  2694			if (atom_execute_table(ctx, cmd_idx.adjust_display_pll,
  2695					       (uint32_t *)&args, sizeof(args)) == 0)
  2696				adjusted_clock = args.v1.usPixelClock;
  2697			break;
  2698		case 3:
  2699		default:
  2700			args.v3.sInput.usPixelClock = pixel_clock_10khz;
  2701			args.v3.sInput.ucTransmitterID = path->encoder_obj_id;
  2702			args.v3.sInput.ucEncodeMode = path->encoder_mode;
  2703			if (atombios_uses_dual_link(path, pixel_clock_10khz))
  2704				args.v3.sInput.ucDispPllConfig |= DISPPLL_CONFIG_DUAL_LINK;
  2705			if (atom_execute_table(ctx, cmd_idx.adjust_display_pll,
  2706					       (uint32_t *)&args, sizeof(args)) == 0 &&
  2707			    args.v3.sOutput.ulDispPllFreq)
  2708				adjusted_clock = args.v3.sOutput.ulDispPllFreq;
  2709			break;
  2710		}
  2711	
  2712		if (adjusted_clock != pixel_clock_10khz)
  2713			printk(BIOS_DEBUG,
  2714			       "ATOMBIOS: AdjustDisplayPll %u -> %u *10kHz\n",
  2715			       pixel_clock_10khz, adjusted_clock);
  2716	
  2717		return adjusted_clock;
  2718	}
  2719	
  2720	/*
  2721	 * Program the pixel clock PLL via the SetPixelClock ATOM command table.
  2722	 * Linux computes PLL dividers before calling SetPixelClock on table
  2723	 * revisions 1.1 through 1.3; do the same here for older AVIVO chips.
  2724	 */
  2725	static int atombios_set_pixel_clock(struct atom_context *ctx,
  2726					    const struct atombios_display_path *path,
  2727					    uint16_t pixel_clock_10khz,
  2728					    int crtc_id)
  2729	{
  2730		uint8_t frev, crev;
  2731		union {
  2732			PIXEL_CLOCK_PARAMETERS v1;
  2733			PIXEL_CLOCK_PARAMETERS_V2 v2;
  2734			PIXEL_CLOCK_PARAMETERS_V3 v3;
  2735			PIXEL_CLOCK_PARAMETERS_V5 v5;
  2736			PIXEL_CLOCK_PARAMETERS_V6 v6;
  2737			PIXEL_CLOCK_PARAMETERS_V7 v7;
  2738		} args;
  2739		uint8_t encoder_id;
  2740		uint8_t pll_id = path->pll_id;
  2741		uint16_t adjusted_clock_10khz;
  2742		uint32_t dot_clock, fb_div, frac_fb_div, ref_div, post_div;
  2743	
  2744		if (!atom_parse_cmd_header(ctx, cmd_idx.set_pixel_clock, &frev, &crev))
  2745			return -1;
  2746	
  2747		memset(&args, 0, sizeof(args));
  2748	
  2749		/* Linux passes radeon_encoder->encoder_id here. */
  2750		encoder_id = path->encoder_obj_id;
  2751		adjusted_clock_10khz = atombios_adjust_display_pll(ctx, path, pixel_clock_10khz);
  2752		atombios_compute_avivo_pll(ctx, adjusted_clock_10khz, &dot_clock,
  2753					 &fb_div, &frac_fb_div, &ref_div, &post_div);
  2754	
  2755		printk(BIOS_DEBUG,
  2756		       "ATOMBIOS: SetPixelClock frev=%d crev=%d clock=%d*10kHz crtc=%d ppll=%u\n",
  2757		       frev, crev, adjusted_clock_10khz, crtc_id, pll_id);
  2758	
  2759		switch (crev) {
  2760		case 1:
  2761			args.v1.usPixelClock = adjusted_clock_10khz;
  2762			args.v1.usRefDiv = ref_div;
