  2835	static int atombios_set_dce_clock(struct atom_context *ctx,
  2836						  const struct atombios_gpu_profile *profile)
  2837	{
  2838		uint8_t frev, crev;
  2839		union {
  2840			SET_DCE_CLOCK_PS_ALLOCATION_V1_1 v1;
  2841			SET_DCE_CLOCK_PS_ALLOCATION_V2_1 v2;
  2842		} args;
