  2849		if (frev == 1 && crev == 1) {
  2850			args.v1.asParam.ulDISPClkFreq = DEFAULT_DCE_DISPCLK_10KHZ;
  2851			printk(BIOS_DEBUG,
  2852			       "ATOMBIOS: SetDCEClock dispclk=%u*10kHz crev=%u\n",
  2853			       DEFAULT_DCE_DISPCLK_10KHZ, crev);
  2854			return atom_execute_table(ctx, cmd_idx.set_dce_clock,
  2855						  (uint32_t *)&args, sizeof(args));
