  2857	
  2858		if (frev == 2 && crev == 1) {
  2859			int ret;
  2860	
  2861			args.v2.asParam.ulDCEClkFreq = DEFAULT_DCE_DISPCLK_10KHZ;
  2862			args.v2.asParam.ucDCEClkType = DCE_CLOCK_TYPE_DISPCLK;
  2863			args.v2.asParam.ucDCEClkSrc = profile->dispclk_ppll;
  2864			printk(BIOS_DEBUG,
  2865			       "ATOMBIOS: SetDCEClock dispclk=%u*10kHz src=%u crev=%u\n",
  2866			       DEFAULT_DCE_DISPCLK_10KHZ, profile->dispclk_ppll, crev);
  2867			ret = atom_execute_table(ctx, cmd_idx.set_dce_clock,
  2868						 (uint32_t *)&args, sizeof(args));
