  2870			memset(&args, 0, sizeof(args));
  2871			args.v2.asParam.ucDCEClkType = DCE_CLOCK_TYPE_DPREFCLK;
  2872			args.v2.asParam.ucDCEClkSrc = profile->dispclk_ppll;
  2873			atom_execute_table(ctx, cmd_idx.set_dce_clock,
  2874					   (uint32_t *)&args, sizeof(args));
