  2899		memset(&args, 0, sizeof(args));
  2900	
  2901		/* Match Linux radeon/amdgpu disp_eng_pll_init(). DCE4+ needs the
  2902		 * display engine clock programmed before the CRTC pixel clock, but the
  2903		 * PLL id differs by generation. */
  2904		switch (crev) {
  2905		case 5:
  2906			args.v5.ucCRTC = ATOM_CRTC_INVALID;
  2907			args.v5.usPixelClock = DEFAULT_DCE_DISPCLK_10KHZ;
  2908			args.v5.ucPpll = ATOM_DCPLL;
  2909			break;
  2910		case 6:
  2911			args.v6.ulDispEngClkFreq = DEFAULT_DCE_DISPCLK_10KHZ;
  2912			args.v6.ucPpll = profile->dispclk_ppll;
  2913			break;
  2914		default:
  2915			return 0;
  2916		}
  2917	
  2918		printk(BIOS_DEBUG,
  2919		       "ATOMBIOS: SetPixelClock dispclk=%u*10kHz ppll=%u crev=%u\n",
  2920		       DEFAULT_DCE_DISPCLK_10KHZ,
  2920		       DEFAULT_DCE_DISPCLK_10KHZ,
  2921		       crev == 6 ? profile->dispclk_ppll : ATOM_DCPLL, crev);
  2922	
  2923		return atom_execute_table(ctx, cmd_idx.set_pixel_clock,
  2924					  (uint32_t *)&args, sizeof(args));
  2925	}
