  2927	/* ---- DAC Encoder Control (VGA/CRT) ---- */
  2928	
  2929	/*
  2930	 * Enable or disable a DAC encoder for CRT/VGA output.
  2931	 *
  2932	 * This calls DAC1EncoderControl or DAC2EncoderControl depending on which
  2933	 * DAC is associated with the display path. The DAC standard is always
  2934	 * ATOM_DAC1_PS2 (VGA/PC monitor).
