  2979	
  2980	/* ---- DAC Load Detection (VGA/CRT) ---- */
  2981	
  2982	/*
  2983	 * Perform DAC load detection to check if a CRT/VGA display is connected.
  2984	 *
  2985	 * This calls the DAC_LoadDetection ATOM command table, which physically
  2986	 * drives the DAC outputs and measures the load. A connected CRT monitor
  2987	 * presents a resistive load that the DAC can detect.
  2988	 *
  2989	 * Returns 0 on success (table executed), -1 on failure.
  2990	 * The actual detection result is in the BIOS scratch registers.
  2991	 */
  2992	static int atombios_dac_load_detect(struct atom_context *ctx,
  2993					    const struct atombios_display_path *path)
  2994	{
  2995		DAC_LOAD_DETECTION_PS_ALLOCATION args;
  2996		uint32_t connected_bit = atombios_s0_connected_bit(path->device_tag);
  2997		int ret;
  2998	
  2999		memset(&args, 0, sizeof(args));
  3000	
  3001		args.sDacload.ucDacType = path->dac_type;
  3002		args.sDacload.usDeviceID = path->device_tag &
  3003			(ATOM_DEVICE_CRT1_SUPPORT | ATOM_DEVICE_CRT2_SUPPORT);
  3004		if (!args.sDacload.usDeviceID)
  3005			args.sDacload.usDeviceID = ATOM_DEVICE_CRT1_SUPPORT;
  3006		args.sDacload.ucMisc = 0;
  3007	
  3008		printk(BIOS_DEBUG, "ATOMBIOS: DAC%c load detection\n",
  3009		       path->dac_type == ATOM_DAC_A ? 'A' : 'B');
  3010	
  3011		ret = atom_execute_table(ctx, cmd_idx.dac_load_detect,
  3012					 (uint32_t *)&args, sizeof(args));
  3013		if (ret || !connected_bit)
  3014			return -1;
  3015	
  3016		return (atombios_scratch_read(ctx, R600_BIOS_0_SCRATCH) & connected_bit) ? 0 : -1;
  3017	}
  3018	
  3019	static int atombios_device_tag_index(uint16_t device_tag)
  3020	{
  3021		int i;
  3022	
  3023		for (i = 0; i < ATOM_MAX_SUPPORTED_DEVICE; i++) {
  3024			if (device_tag & (1 << i))
  3025				return i;
  3026		}
  3027	
  3028		return -1;
  3029	}
  3030	
  3031	static int atombios_discover_supported_device_paths(struct atom_context *ctx,
  3032							     struct atombios_display_path *paths,
  3033							     int max_paths)
  3034	{
  3035		ATOM_SUPPORTED_DEVICES_INFO_2d1 *supported;
  3036		uint16_t data_offset, device_support, size;
  3037		uint8_t frev, crev;
  3038		int max_device;
  3039		int count = 0;
  3040		int i;
  3041	
  3042		if (cmd_idx.data_supported_devices < 0 ||
  3043		    !atom_parse_data_header(ctx, cmd_idx.data_supported_devices,
  3044					    &size, &frev, &crev, &data_offset))
  3045			return 0;
  3046	
  3047		max_device = (frev > 1) ? ATOM_MAX_SUPPORTED_DEVICE :
  3048			ATOM_MAX_SUPPORTED_DEVICE_INFO;
  3049		if (size < offsetof(ATOM_SUPPORTED_DEVICES_INFO_2d1, asConnInfo) +
  3050			   max_device * sizeof(ATOM_CONNECTOR_INFO_I2C))
  3051			return 0;
  3052	
  3053		supported = (ATOM_SUPPORTED_DEVICES_INFO_2d1 *)
  3054			((uint8_t *)ctx->bios + data_offset);
  3055		device_support = supported->usDeviceSupport;
  3056	
  3057		for (i = 0; i < max_device && count < max_paths; i++) {
  3058			struct atombios_display_path *path = &paths[count];
  3059			ATOM_CONNECTOR_INFO_I2C *conn = &supported->asConnInfo[i];
  3060			uint8_t conn_type;
  3061			uint8_t dac;
  3062			uint8_t connector_id;
  3063	
  3064			if (!(device_support & (1 << i)))
  3065				continue;
  3066	
  3067			conn_type = conn->sucConnectorInfo.sbfAccess.bfConnectorType;
  3068			dac = conn->sucConnectorInfo.sbfAccess.bfAssociatedDAC;
  3069			memset(path, 0, sizeof(*path));
  3070			path->device_tag = 1 << i;
  3071			path->i2c_line = conn->sucI2cId.ucAccess;
  3072			path->i2c_valid = 1;
  3073			path->hpd_id = ATOMBIOS_HPD_NONE;
  3074	
  3075			switch (i) {
  3076			case ATOM_DEVICE_CRT1_INDEX:
  3077			case ATOM_DEVICE_CRT2_INDEX:
  3078				connector_id = CONNECTOR_OBJECT_ID_VGA;
  3079				path->connector_type = 4;
  3080				path->encoder_mode = ATOM_ENCODER_MODE_CRT;
  3081				path->is_dac = 1;
  3082				path->dac_type = dac == 2 ? ATOM_DAC_B : ATOM_DAC_A;
  3083				path->encoder_obj_id = path->dac_type == ATOM_DAC_B ?
  3084					ENCODER_OBJECT_ID_INTERNAL_KLDSCP_DAC2 :
  3085					ENCODER_OBJECT_ID_INTERNAL_KLDSCP_DAC1;
  3086				break;
  3087			case ATOM_DEVICE_LCD1_INDEX:
  3088				connector_id = CONNECTOR_OBJECT_ID_LVDS;
  3089				path->connector_type = 2;
  3090				path->encoder_mode = ATOM_ENCODER_MODE_LVDS;
  3091				path->is_legacy_lvds = 1;
  3092				path->encoder_obj_id = ENCODER_OBJECT_ID_INTERNAL_LVTM1;
  3093				break;
  3094			case ATOM_DEVICE_DFP1_INDEX:
  3095				if (conn_type != 2 && conn_type != 3 && conn_type != 8 &&
  3096				    conn_type != 0x0a && conn_type != 0x0b)
  3097					continue;
  3098				connector_id = conn_type == 0x0a || conn_type == 0x0b ?
  3099					CONNECTOR_OBJECT_ID_HDMI_TYPE_A :
  3100					CONNECTOR_OBJECT_ID_SINGLE_LINK_DVI_D;
  3101				path->connector_type = conn_type == 0x0a || conn_type == 0x0b ? 1 : 3;
  3102				path->encoder_mode = ATOM_ENCODER_MODE_DVI;
  3103				path->is_legacy_tmds = 1;
  3104				path->encoder_obj_id = ENCODER_OBJECT_ID_INTERNAL_KLDSCP_TMDS1;
  3105				break;
  3106			case ATOM_DEVICE_DFP3_INDEX:
  3107				if (conn_type != 2 && conn_type != 3 && conn_type != 8)
  3108					continue;
  3109				connector_id = CONNECTOR_OBJECT_ID_SINGLE_LINK_DVI_D;
  3110				path->connector_type = 3;
  3111				path->encoder_mode = ATOM_ENCODER_MODE_DVI;
  3112				path->is_legacy_tmds = 1;
  3113				path->encoder_obj_id = ENCODER_OBJECT_ID_INTERNAL_LVTM1;
  3114				break;
  3115			default:
  3116				/* TV/CV and DVO-backed LCD2/DFP2+ need output paths that
  3117				 * this one-framebuffer backend deliberately does not implement. */
  3118				continue;
  3119			}
  3120	
  3121			path->connector_obj_id =
  3122				(GRAPH_OBJECT_TYPE_CONNECTOR << OBJECT_TYPE_SHIFT) | connector_id;
  3123			printk(BIOS_INFO,
  3124			       "ATOMBIOS: old-table path %d: dev=%d conn=0x%x i2c=0x%02x enc=0x%02x\n",
  3125			       count, i, conn_type, path->i2c_line, path->encoder_obj_id);
  3126			count++;
  3127		}
  3128	
  3129		return count;
  3130	}
  3131	
  3132	static void atombios_apply_supported_device_info(struct atom_context *ctx,
  3133							 struct atombios_display_path *paths,
  3134							 int count)
  3135	{
  3136		ATOM_SUPPORTED_DEVICES_INFO_2d1 *supported;
  3137		uint16_t data_offset, device_support, size;
  3138		uint8_t frev, crev;
  3139		int max_device;
  3140		int i;
  3141	
  3142		if (cmd_idx.data_supported_devices < 0)
  3143			return;
  3144	
  3145		if (!atom_parse_data_header(ctx, cmd_idx.data_supported_devices,
  3146					    &size, &frev, &crev, &data_offset))
  3147			return;
  3148	
  3149		max_device = (frev > 1) ? ATOM_MAX_SUPPORTED_DEVICE : ATOM_MAX_SUPPORTED_DEVICE_INFO;
  3150		if (size < offsetof(ATOM_SUPPORTED_DEVICES_INFO_2d1, asConnInfo) +
  3151			   max_device * sizeof(ATOM_CONNECTOR_INFO_I2C))
  3152			return;
  3153	
  3154		supported = (ATOM_SUPPORTED_DEVICES_INFO_2d1 *)
  3155			((uint8_t *)ctx->bios + data_offset);
  3156		device_support = supported->usDeviceSupport;
  3157	
  3158		printk(BIOS_INFO,
  3159		       "ATOMBIOS: SupportedDevicesInfo frev=%d crev=%d support=0x%04x\n",
  3160		       frev, crev, device_support);
  3161	
  3162		for (i = 0; i < count; i++) {
  3163			ATOM_CONNECTOR_INFO_I2C *conn;
  3164			uint8_t conn_type;
  3165			uint8_t dac;
  3166			int dev_index = atombios_device_tag_index(paths[i].device_tag);
  3167	
  3168			if (dev_index < 0 || dev_index >= max_device)
  3169				continue;
  3170			if (!(device_support & (1 << dev_index)))
  3171				continue;
  3172	
  3173			conn = &supported->asConnInfo[dev_index];
  3174			conn_type = conn->sucConnectorInfo.sbfAccess.bfConnectorType;
  3175			dac = conn->sucConnectorInfo.sbfAccess.bfAssociatedDAC;
  3176	
  3177			if (!paths[i].i2c_valid) {
  3178				paths[i].i2c_line = conn->sucI2cId.ucAccess;
  3179				paths[i].i2c_valid = 1;
  3180			}
  3181	
  3182			/* Linux uses SupportedDevicesInfo as an old-table fallback, not
  3183			 * as an override for Object_Header-derived connector paths. */
  3184			if (paths[i].connector_type != 0)
  3185				goto log_supported_device;
  3186	
  3187			switch (conn_type) {
  3188			case 1: /* VGA */
  3189			case 4: /* DVI-A */
  3190				paths[i].connector_type = 4;
  3191				paths[i].encoder_mode = ATOM_ENCODER_MODE_CRT;
  3192				paths[i].is_dac = 1;
  3193				paths[i].dac_type = (dac == 2) ? ATOM_DAC_B : ATOM_DAC_A;
  3194				break;
  3195			case 2: /* DVI-I */
  3196			case 3: /* DVI-D */
  3197			case 8: /* digital link */
  3198				paths[i].connector_type = 3;
  3199				paths[i].encoder_mode = ATOM_ENCODER_MODE_DVI;
  3200				break;
  3201			case 7: /* LVDS */
  3202				paths[i].connector_type = 2;
  3203				paths[i].encoder_mode = ATOM_ENCODER_MODE_LVDS;
  3204				break;
  3205			case 0x0a: /* HDMI type A */
  3206			case 0x0b: /* HDMI type B */
  3207				paths[i].connector_type = 1;
  3208				/* Linux drives HDMI as DVI/TMDS when audio/infoframes are off. */
  3209				paths[i].encoder_mode = ATOM_ENCODER_MODE_DVI;
  3210				break;
  3211			default:
  3212				break;
  3213			}
  3214	
  3215	log_supported_device:
  3216			printk(BIOS_INFO,
  3217			       "ATOMBIOS: supported dev %d tag=0x%04x conn_type=0x%x i2c=0x%02x dac=%d\n",
  3218			       dev_index, paths[i].device_tag, conn_type, paths[i].i2c_line, dac);
  3219		}
  3220	}
  3221	
  3222	static int atombios_get_panel_mode(struct atom_context *ctx,
  3223					   struct atombios_display_path *path,
