  2299	
  2300		/* Set training pattern 3 (preferred) or 2 */
  2301		if (info->tp3_supported)
  2302			dp_set_training_pattern(info, DP_TRAINING_PATTERN_3);
  2303		else
  2304			dp_set_training_pattern(info, DP_TRAINING_PATTERN_2);
  2305	
  2306		while (1) {
  2307			/* Wait for channel equalization (400us per DP spec) */
  2308			udelay(400);
  2309	
  2310			if (dp_aux_native_read(info->ctx, info->aux_id, info->hpd_id,
  2311					       DP_LANE0_1_STATUS, info->link_status,
  2312					       DP_LINK_STATUS_SIZE) < 0) {
  2313				printk(BIOS_ERR, "ATOMBIOS: DP link status read failed\n");
  2314				return -1;
  2315			}
  2316	
  2317			if (dp_channel_eq_ok(info->link_status, info->dp_lane_count)) {
  2318				printk(BIOS_INFO, "ATOMBIOS: DP channel equalization OK\n");
  2319				return 0;
  2320			}
  2321	
  2322			if (++tries > 5) {
  2323				printk(BIOS_ERR, "ATOMBIOS: DP channel EQ failed: 5 tries\n");
  2324				return -1;
  2325			}
  2326	
  2327			dp_get_adjust_train(info->link_status, info->dp_lane_count,
  2328					    info->train_set);
  2329			dp_update_vs_emph(info);
  2330		}
  2331	}
  2332	
  2333	static void dp_link_train_finish(struct dp_link_train_info *info)
  2334	{
  2335		udelay(400);
  2336	
  2337		/* Disable training pattern on sink */
  2338		dp_dpcd_writeb(info->ctx, info->aux_id, info->hpd_id,
  2339			       DP_TRAINING_PATTERN_SET, DP_TRAINING_PATTERN_DISABLE);
  2340	
  2341		/* Complete training on source */
  2342		atombios_dig_encoder_setup(info->ctx, info->path,
  2343					   info->pixel_clock_10khz,
  2344					   ATOM_ENCODER_CMD_DP_LINK_TRAINING_COMPLETE,
  2345					   PANEL_8BIT_PER_COLOR);
  2346	}
  2347	
  2348	/*
  2349	 * Full DP link training sequence.
  2350	 * Returns 0 on success, -1 on failure.
  2351	 */
  2352	static int atombios_dp_link_train(struct atom_context *ctx,
  2353					  const struct atombios_display_path *path,
  2354					  uint16_t pixel_clock_10khz,
  2355					  uint8_t aux_id, uint8_t hpd_id)
  2356	{
  2357		struct dp_link_train_info info;
  2358		struct atombios_display_path train_path = *path;
  2359		int ret;
  2360	
  2361		memset(&info, 0, sizeof(info));
  2362		info.ctx = ctx;
  2363		info.path = &train_path;
  2364		info.aux_id = aux_id;
  2365		info.hpd_id = hpd_id;
  2366		info.pixel_clock_10khz = pixel_clock_10khz;
  2367	
  2368		/* Read receiver capabilities (DPCD 0x000-0x00E) */
  2369		if (dp_aux_native_read(ctx, aux_id, hpd_id, DP_DPCD_REV,
  2370				       info.dpcd, DP_RECEIVER_CAP_SIZE) < 0) {
  2371			printk(BIOS_ERR, "ATOMBIOS: failed to read DP receiver caps\n");
  2372			return -1;
  2373		}
  2374	
  2375		printk(BIOS_INFO, "ATOMBIOS: DP DPCD rev=%d.%d max_rate=0x%02x max_lanes=%d\n",
  2376		       info.dpcd[0] >> 4, info.dpcd[0] & 0xF,
  2377		       info.dpcd[DP_MAX_LINK_RATE],
  2378		       info.dpcd[DP_MAX_LANE_COUNT] & 0x1F);
  2379	
  2380		if (path->dp_link_bw && path->dp_lane_count) {
  2380		if (path->dp_link_bw && path->dp_lane_count) {
  2381			info.dp_link_bw = path->dp_link_bw;
  2382			info.dp_lane_count = path->dp_lane_count;
  2383		} else if (atombios_dp_get_link_config(info.dpcd,
  2384						       (uint32_t)pixel_clock_10khz * 10,
  2385						       &info.dp_lane_count,
  2386						       &info.dp_link_bw)) {
  2387			printk(BIOS_WARNING,
  2388			       "ATOMBIOS: failed to choose DP link config, using sink maximum\n");
  2389			info.dp_link_bw = info.dpcd[DP_MAX_LINK_RATE];
  2390			info.dp_lane_count = info.dpcd[DP_MAX_LANE_COUNT] & 0x1F;
  2391			if (info.dp_lane_count > 4)
  2392				info.dp_lane_count = 4;
  2393		}
  2394		if (!info.dp_lane_count)
  2395			info.dp_lane_count = 1;
  2396		if (!info.dp_link_bw)
  2397			info.dp_link_bw = DP_LINK_BW_1_62;
  2398		train_path.dp_lane_count = info.dp_lane_count;
  2399		train_path.dp_link_bw = info.dp_link_bw;
  2400	
  2401		/* Only use TPS3 on HBR2 links; older sources cannot generate it. */
  2402		info.tp3_supported = info.dp_link_bw >= DP_LINK_BW_5_4 &&
  2403			!!(info.dpcd[DP_MAX_LANE_COUNT] & DP_TPS3_SUPPORTED);
  2404	
  2405		/* Init */
  2406		ret = dp_link_train_init(&info);
  2407		if (ret)
  2408			goto done;
  2409	
  2410		/* Phase 1: Clock Recovery */
  2411		ret = dp_link_train_cr(&info);
  2412		if (ret)
  2413			goto done;
  2414	
  2415		/* Phase 2: Channel Equalization */
  2416		ret = dp_link_train_ce(&info);
  2417	
  2418	done:
  2419		/* Always finish training (even on failure) */
  2420		dp_link_train_finish(&info);
  2421	
  2422		if (ret == 0) {
  2423			/* Enable video on source */
  2424			atombios_dig_encoder_setup(ctx, info.path, pixel_clock_10khz,
  2425						   ATOM_ENCODER_CMD_DP_VIDEO_ON,
  2426						   PANEL_8BIT_PER_COLOR);
  2427			printk(BIOS_INFO, "ATOMBIOS: DP link training succeeded (%d lanes @ 0x%02x)\n",
  2428			       info.dp_lane_count, info.dp_link_bw);
  2429		} else {
  2430			printk(BIOS_ERR, "ATOMBIOS: DP link training FAILED\n");
  2431		}
  2432	
  2433		return ret;
  2434	}
  2435	
  2436	static int atombios_dp_prepare_link(struct atom_context *ctx,
  2437					    struct atombios_display_path *path,
  2438					    uint32_t pixel_clock_khz)
  2439	{
  2440		uint8_t dpcd[DP_RECEIVER_CAP_SIZE];
  2441	
  2442		if (path->encoder_mode != ATOM_ENCODER_MODE_DP || !path->i2c_valid)
  2443			return 0;
  2444	
  2445		if (dp_aux_native_read(ctx, path->i2c_line, path->hpd_id, DP_DPCD_REV,
  2446				       dpcd, sizeof(dpcd)) < 0) {
  2447			printk(BIOS_WARNING, "ATOMBIOS: failed to read DP DPCD caps\n");
  2448			return -1;
  2449		}
  2450	
  2451		if (atombios_dp_get_link_config(dpcd, pixel_clock_khz,
  2452					       &path->dp_lane_count, &path->dp_link_bw)) {
  2453			printk(BIOS_WARNING,
  2454			       "ATOMBIOS: no DP link config for %u kHz pixel clock\n",
  2455			       pixel_clock_khz);
  2456			return -1;
  2457		}
  2458	
  2459		path->dp_panel_mode = DP_PANEL_MODE_EXTERNAL_DP_MODE;
  2460		if (atombios_object_id(path->connector_obj_id) == CONNECTOR_OBJECT_ID_eDP &&
  2461		    (dpcd[DP_EDP_CONFIGURATION_CAP] & 1))
  2462			path->dp_panel_mode = DP_PANEL_MODE_INTERNAL_DP2_MODE;
  2463	
  2464		printk(BIOS_INFO, "ATOMBIOS: selected DP link %d lanes @ 0x%02x\n",
  2465		       path->dp_lane_count, path->dp_link_bw);
  2466		return 0;
  2467	}
