  2791				PIXEL_CLOCK_MISC_CRTC_SEL_CRTC1;
  2792			break;
  2793		case 5:
  2794			args.v5.ucCRTC = crtc_id;
  2795			args.v5.usPixelClock = adjusted_clock_10khz;
  2796			args.v5.ucRefDiv = ref_div;
  2797			args.v5.usFbDiv = fb_div;
  2798			args.v5.ulFbDivDecFrac = frac_fb_div * 100000;
  2799			args.v5.ucPostDiv = post_div;
  2800			args.v5.ucPpll = pll_id;
  2801			args.v5.ucTransmitterID = encoder_id;
  2802			args.v5.ucEncoderMode = path->encoder_mode;
  2803			args.v5.ucMiscInfo = 0;
  2804			break;
  2805		case 6:
  2806			args.v6.ulDispEngClkFreq = ((uint32_t)crtc_id << 24) |
  2807				adjusted_clock_10khz;
  2808			args.v6.ucRefDiv = ref_div;
  2809			args.v6.usFbDiv = fb_div;
  2810			args.v6.ulFbDivDecFrac = frac_fb_div * 100000;
  2811			args.v6.ucPostDiv = post_div;
  2812			args.v6.ucPpll = pll_id;
  2813			args.v6.ucTransmitterID = encoder_id;
  2814			args.v6.ucEncoderMode = path->encoder_mode;
  2815			args.v6.ucMiscInfo = 0;
  2816			break;
  2817		case 7:
  2818		default:
  2819			args.v7.ulPixelClock = (uint32_t)adjusted_clock_10khz * 100;
  2820			args.v7.ucCRTC = crtc_id;
  2821			args.v7.ucPpll = pll_id;
  2822			args.v7.ucTransmitterID = encoder_id;
  2823			args.v7.ucEncoderMode = path->encoder_mode;
  2824			args.v7.ucMiscInfo = 0;
