  2881	static int atombios_set_disp_eng_clock(struct atom_context *ctx,
  2882						       const struct atombios_gpu_profile *profile)
  2883	{
  2884		uint8_t frev, crev;
  2885		union {
  2886			PIXEL_CLOCK_PARAMETERS_V5 v5;
  2887			PIXEL_CLOCK_PARAMETERS_V6 v6;
  2888		} args;
  2889	
  2890		if (profile->scanout != ATOMBIOS_SCANOUT_EVERGREEN)
  2891			return 0;
