  2908			args.v5.ucPpll = ATOM_DCPLL;
  2909			break;
  2910		case 6:
  2911			args.v6.ulDispEngClkFreq = DEFAULT_DCE_DISPCLK_10KHZ;
  2912			args.v6.ucPpll = profile->dispclk_ppll;
  2913			break;
  2914		default:
  2915			return 0;
  2916		}
  2917	
  2918		printk(BIOS_DEBUG,
  2919		       "ATOMBIOS: SetPixelClock dispclk=%u*10kHz ppll=%u crev=%u\n",
  2920		       DEFAULT_DCE_DISPCLK_10KHZ,
  2920		       DEFAULT_DCE_DISPCLK_10KHZ,
  2921		       crev == 6 ? profile->dispclk_ppll : ATOM_DCPLL, crev);
  2922	
  2923		return atom_execute_table(ctx, cmd_idx.set_pixel_clock,
  2924					  (uint32_t *)&args, sizeof(args));
