3222	static int atombios_get_panel_mode(struct atom_context *ctx,
3223					   struct atombios_display_path *path,
3224					   struct edid_mode *mode)
3225	{
3226		ATOM_LVDS_INFO *info;
3227		ATOM_DTD_FORMAT *dtd;
3228		uint16_t data_offset;
3229		uint16_t misc;
3230		uint8_t frev, crev;
3231	
3232		if (cmd_idx.data_lvds_info < 0 ||
3233		    !atom_parse_data_header(ctx, cmd_idx.data_lvds_info, NULL,
3234					    &frev, &crev, &data_offset) ||
3235		    frev != 1 || crev < 1 || crev > 3)
3236			return -1;
3237	
3238		info = (ATOM_LVDS_INFO *)((uint8_t *)ctx->bios + data_offset);
3239		dtd = &info->sLCDTiming;
3240		misc = dtd->susModeMiscInfo.usAccess;
3241	
3242		if (!dtd->usPixClk || !dtd->usHActive || !dtd->usVActive ||
3243		    !dtd->usHBlanking_Time || !dtd->usVBlanking_Time ||
3244		    dtd->usHSyncOffset + dtd->usHSyncWidth > dtd->usHBlanking_Time ||
3245		    dtd->usVSyncOffset + dtd->usVSyncWidth > dtd->usVBlanking_Time ||
3246		    (misc & (ATOM_COMPOSITESYNC | ATOM_INTERLACE | ATOM_DOUBLE_CLOCK_MODE)))
3247			return -1;
3248	
3249		memset(mode, 0, sizeof(*mode));
3250		mode->pixel_clock = dtd->usPixClk * 10;
3251		mode->ha = dtd->usHActive;
3252		mode->hbl = dtd->usHBlanking_Time;
3253		mode->hso = dtd->usHSyncOffset;
3254		mode->hspw = dtd->usHSyncWidth;
3255		mode->hborder = dtd->ucHBorder;
3256		mode->va = dtd->usVActive;
3257		mode->vbl = dtd->usVBlanking_Time;
3258		mode->vso = dtd->usVSyncOffset;
3259		mode->vspw = dtd->usVSyncWidth;
3260		mode->vborder = dtd->ucVBorder;
3261		mode->phsync = !(misc & ATOM_HSYNC_POLARITY);
3262		mode->pvsync = !(misc & ATOM_VSYNC_POLARITY);
3263		mode->x_mm = dtd->usImageHSize;
3264		mode->y_mm = dtd->usImageVSize;
3265	
3266		if (crev < 3) {
3267			path->lcd_misc = info->ucLVDS_Misc;
3268		} else {
3269			ATOM_LCD_INFO_V13 *info_v13 = (ATOM_LCD_INFO_V13 *)info;
3270	
3271			path->lcd_misc = 0;
3272			if (info_v13->ucLCD_Misc & ATOM_PANEL_MISC_V13_DUAL)
3273				path->lcd_misc |= ATOM_PANEL_MISC_DUAL;
3274			if ((info_v13->ucLCD_Misc & ATOM_PANEL_MISC_V13_COLOR_BIT_DEPTH_MASK) ==
3275			    ATOM_PANEL_MISC_V13_8BIT_PER_COLOR)
3276				path->lcd_misc |= ATOM_PANEL_MISC_888RGB;
3277		}
3278		mode->lvds_dual_channel = !!(path->lcd_misc & ATOM_PANEL_MISC_DUAL);
3279	
3280		printk(BIOS_INFO,
3281		       "ATOMBIOS: panel mode %ux%u @ %u kHz (LCD_Info %u.%u misc=0x%02x)\n",
3282		       mode->ha, mode->va, mode->pixel_clock, frev, crev, path->lcd_misc);
3283		return 0;
3284	}
