3286	static uint8_t atombios_hpd_from_gpio(struct atom_context *ctx, uint8_t gpio_id)
3287	{
3288		ATOM_GPIO_PIN_LUT *gpio_info;
3289		ATOM_GPIO_PIN_ASSIGNMENT *pin;
3290		uint16_t data_offset, size;
3291		int num_indices;
3292		int i;
3293	
3294		if (!atom_parse_data_header(ctx, cmd_idx.data_gpio_pin, &size, NULL,
3295					    NULL, &data_offset) ||
3296		    size < sizeof(ATOM_COMMON_TABLE_HEADER))
3297			return ATOMBIOS_HPD_NONE;
3298	
3299		gpio_info = (ATOM_GPIO_PIN_LUT *)((uint8_t *)ctx->bios + data_offset);
3300		num_indices = (size - sizeof(ATOM_COMMON_TABLE_HEADER)) /
3301			sizeof(ATOM_GPIO_PIN_ASSIGNMENT);
3302		pin = &gpio_info->asGPIO_Pin[0];
3303	
3304		for (i = 0; i < num_indices; i++) {
3305			uint32_t reg;
3306			uint32_t mask;
3307	
3308			if (pin->ucGPIO_ID != gpio_id) {
3309				pin = (ATOM_GPIO_PIN_ASSIGNMENT *)
3310					((uint8_t *)pin + sizeof(ATOM_GPIO_PIN_ASSIGNMENT));
3311				continue;
3312			}
3313	
3314			if (pin->ucGpioPinBitShift >= 32)
3315				return ATOMBIOS_HPD_NONE;
3316	
3317			reg = pin->usGpioPin_AIndex * 4;
3318			mask = 1u << pin->ucGpioPinBitShift;
3319			if (reg != AVIVO_DC_GPIO_HPD_A &&
3320			    reg != EVERGREEN_DC_GPIO_HPD_A && reg != SI_DC_GPIO_HPD_A)
3321				return ATOMBIOS_HPD_NONE;
3322	
3323			switch (mask) {
3324			case (1 << 0): return 0;
3325			case (1 << 8): return 1;
3326			case (1 << 16): return 2;
3327			case (1 << 24): return 3;
3328			case (1 << 26): return 4;
3329			case (1 << 28): return 5;
3330			default: return ATOMBIOS_HPD_NONE;
3331			}
3332		}
3333	
3334		return ATOMBIOS_HPD_NONE;
3335	}
