3337	static void atombios_read_connector_records(struct atom_context *ctx,
3338						    ATOM_OBJECT_HEADER *obj_hdr,
3339						    uint16_t data_offset,
3340						    struct atombios_display_path *path)
3341	{
3342		ATOM_OBJECT_TABLE *con_obj;
3343		uint8_t *base = (uint8_t *)ctx->bios;
3344		int i;
3345	
3346		if (!obj_hdr->usConnectorObjectTableOffset)
3347			return;
3348	
3349		con_obj = (ATOM_OBJECT_TABLE *)
3350			(base + data_offset + obj_hdr->usConnectorObjectTableOffset);
3351	
3352		for (i = 0; i < con_obj->ucNumberOfObjects; i++) {
3353			ATOM_COMMON_RECORD_HEADER *record;
3354	
3355			if (con_obj->asObjects[i].usObjectID != path->connector_obj_id)
3356				continue;
3357			if (!con_obj->asObjects[i].usRecordOffset)
3358				return;
3359	
3360			record = (ATOM_COMMON_RECORD_HEADER *)
3361				(base + data_offset + con_obj->asObjects[i].usRecordOffset);
3362	
3363			while (record->ucRecordSize > 0 &&
3364			       record->ucRecordType > 0 &&
3365			       record->ucRecordType <= ATOM_MAX_OBJECT_RECORD_NUMBER) {
3366				switch (record->ucRecordType) {
3367				case ATOM_I2C_RECORD_TYPE: {
3368					ATOM_I2C_RECORD *i2c_record = (ATOM_I2C_RECORD *)record;
3369					ATOM_I2C_ID_CONFIG_ACCESS *i2c_id =
3370						(ATOM_I2C_ID_CONFIG_ACCESS *)&i2c_record->sucI2cId;
3371					path->i2c_line = i2c_id->ucAccess;
3372					path->i2c_valid = 1;
3373					break;
3374				}
3375				case ATOM_HPD_INT_RECORD_TYPE: {
3376					ATOM_HPD_INT_RECORD *hpd_record = (ATOM_HPD_INT_RECORD *)record;
3377					path->hpd_id = atombios_hpd_from_gpio(ctx,
3378							hpd_record->ucHPDIntGPIOID);
3379					break;
3380				}
3381				}
3382	
3383				record = (ATOM_COMMON_RECORD_HEADER *)
3384					((uint8_t *)record + record->ucRecordSize);
3385			}
3386			return;
3387		}
3388	}
