3390	/* ---- Display path discovery from ATOM object tables ---- */
3391	
3392	/*
3393	 * Parse the ATOM Object_Header data table to discover display paths.
3394	 * Each path maps a connector to an encoder chain.
3395	 *
3396	 * Returns the number of display paths found, or 0 on error.
3397	 */
3398	static int atombios_discover_display_paths(struct atom_context *ctx,
3399						   struct atombios_display_path *paths,
3400						   int max_paths)
3401	{
3402		uint16_t data_offset;
3403		uint8_t frev, crev;
3404		int count = 0;
3405		ATOM_OBJECT_HEADER *obj_hdr;
3406		ATOM_DISPLAY_OBJECT_PATH_TABLE *path_tbl;
3407		uint8_t *base;
3408		int i;
3409		uint16_t path_offset;
3410	
3411		if (!atom_parse_data_header(ctx, cmd_idx.data_object_header,
3412					    NULL, &frev, &crev, &data_offset)) {
3413			printk(BIOS_WARNING,
3414			       "ATOMBIOS: Object_Header table not found, trying SupportedDevicesInfo\n");
3415			return atombios_discover_supported_device_paths(ctx, paths, max_paths);
3416		}
3417	
3418		base = (uint8_t *)ctx->bios;
3419		obj_hdr = (ATOM_OBJECT_HEADER *)(base + data_offset);
3420	
3421		if (!obj_hdr->usDisplayPathTableOffset) {
3422			printk(BIOS_WARNING,
3423			       "ATOMBIOS: no display path table, trying SupportedDevicesInfo\n");
3424			return atombios_discover_supported_device_paths(ctx, paths, max_paths);
3425		}
3426	
3427		path_tbl = (ATOM_DISPLAY_OBJECT_PATH_TABLE *)
3428			   (base + data_offset + obj_hdr->usDisplayPathTableOffset);
3429	
3430		printk(BIOS_INFO, "ATOMBIOS: found %d display paths (version %d)\n",
3431		       path_tbl->ucNumOfDispPath, path_tbl->ucVersion);
3432	
3433		/* Walk each display path */
3434		path_offset = (uint16_t)((uint8_t *)path_tbl->asDispPath - base);
3435		for (i = 0; i < path_tbl->ucNumOfDispPath && count < max_paths; i++) {
3436			ATOM_DISPLAY_OBJECT_PATH *disp_path;
3437			uint16_t conn_obj_id, enc_obj_id;
3438			uint8_t obj_type, obj_id, enc_id;
3439			int j;
3440	
3441			disp_path = (ATOM_DISPLAY_OBJECT_PATH *)(base + path_offset);
3442	
3443			conn_obj_id = disp_path->usConnObjectId;
3444			obj_type = (conn_obj_id & OBJECT_TYPE_MASK) >> OBJECT_TYPE_SHIFT;
3445	
3446			if (obj_type != GRAPH_OBJECT_TYPE_CONNECTOR ||
3447			    !(obj_hdr->usDeviceSupport & disp_path->usDeviceTag)) {
3448				/* Skip to next path using usSize */
3449				path_offset += disp_path->usSize;
3450				continue;
3451			}
3452	
3453			obj_id = (conn_obj_id & OBJECT_ID_MASK) >> OBJECT_ID_SHIFT;
3454	
3455			paths[count].connector_obj_id = conn_obj_id;
3456			paths[count].device_tag = disp_path->usDeviceTag;
3457			paths[count].hpd_id = ATOMBIOS_HPD_NONE;
3458	
3459			/* Map ATOM connector object ID to a simple type */
3460			switch (obj_id) {
3461			case CONNECTOR_OBJECT_ID_HDMI_TYPE_A:
3462				paths[count].connector_type = 1; /* HDMI */
3463				/* Linux drives HDMI as DVI/TMDS when audio/infoframes are off. */
3464				paths[count].encoder_mode = ATOM_ENCODER_MODE_DVI;
3465				break;
3466			case CONNECTOR_OBJECT_ID_DISPLAYPORT:
3467			case CONNECTOR_OBJECT_ID_eDP:
3468				paths[count].connector_type = 2; /* DP/eDP */
3469				paths[count].encoder_mode = ATOM_ENCODER_MODE_DP;
3470				break;
3471			case CONNECTOR_OBJECT_ID_LVDS:
3472			case CONNECTOR_OBJECT_ID_LVDS_eDP:
3473				paths[count].connector_type = 2; /* internal panel */
3474				paths[count].encoder_mode = ATOM_ENCODER_MODE_LVDS;
3475				break;
3476			case CONNECTOR_OBJECT_ID_SINGLE_LINK_DVI_D:
3477			case CONNECTOR_OBJECT_ID_DUAL_LINK_DVI_D:
3478			case CONNECTOR_OBJECT_ID_SINGLE_LINK_DVI_I:
3479			case CONNECTOR_OBJECT_ID_DUAL_LINK_DVI_I:
3480				paths[count].connector_type = 3; /* DVI */
3481				paths[count].encoder_mode = ATOM_ENCODER_MODE_DVI;
3482				break;
3483			case CONNECTOR_OBJECT_ID_VGA:
3484				paths[count].connector_type = 4; /* VGA */
3485				paths[count].encoder_mode = ATOM_ENCODER_MODE_CRT;
3486				break;
3487			default:
3488				paths[count].connector_type = 0;
3489				paths[count].encoder_mode = ATOM_ENCODER_MODE_DVI;
3490				break;
3491			}
3492	
3493			/* Walk graphic objects in the path to find encoder */
3494			for (j = 0; j < (disp_path->usSize - 8) / 2; j++) {
3495				enc_obj_id = disp_path->usGraphicObjIds[j];
3496				obj_type = (enc_obj_id & OBJECT_TYPE_MASK) >> OBJECT_TYPE_SHIFT;
3497	
3498				if (obj_type != GRAPH_OBJECT_TYPE_ENCODER)
3499					continue;
3500

