1202	static void atombios_output_lock(struct atom_context *ctx, bool lock)
1203	{
1204		uint32_t scratch = atombios_scratch_read(ctx, R600_BIOS_6_SCRATCH);
1205	
1206		if (lock) {
1207			scratch |= ATOM_S6_CRITICAL_STATE;
1208			scratch &= ~ATOM_S6_ACC_MODE;
1209		} else {
1210			scratch &= ~ATOM_S6_CRITICAL_STATE;
1211			scratch |= ATOM_S6_ACC_MODE;
1212		}
1213	
1214		atombios_scratch_write(ctx, R600_BIOS_6_SCRATCH, scratch);
1215	}
