1217	static void atombios_update_scratch_for_path(struct atom_context *ctx,
1218						     const struct atombios_display_path *path,
1219						     int crtc_id, bool connected, bool dpms_on)
1220	{
1221		uint32_t s0 = atombios_scratch_read(ctx, R600_BIOS_0_SCRATCH);
1222		uint32_t s2 = atombios_scratch_read(ctx, R600_BIOS_2_SCRATCH);
1223		uint32_t s3 = atombios_scratch_read(ctx, R600_BIOS_3_SCRATCH);
1224		uint32_t s6 = atombios_scratch_read(ctx, R600_BIOS_6_SCRATCH);
1225		uint32_t s0_bit = atombios_s0_connected_bit(path->device_tag);
1226		uint32_t s2_bit = atombios_s2_dpms_bit(path->device_tag);
1227		uint32_t s3_bit = atombios_s3_active_bit(path->device_tag);
1228		uint32_t s6_bit = atombios_s6_acc_req_bit(path->device_tag);
1229		uint32_t shift = atombios_s3_crtc_shift(path->device_tag);
1230	
1231		if (connected) {
1232			s0 |= s0_bit;
1233			s3 |= s3_bit;
1234			s6 |= s6_bit;
1235		} else {
1236			s0 &= ~s0_bit;
1237			s3 &= ~s3_bit;
1238			s6 &= ~s6_bit;
1239		}
1240	
1241		if (dpms_on)
1242			s2 &= ~s2_bit;
1243		else
1244			s2 |= s2_bit;
1245	
1246		if (shift) {
1247			s3 &= ~(1u << shift);
1248			s3 |= (uint32_t)crtc_id << shift;
1249		}
1250	
1251		atombios_scratch_write(ctx, R600_BIOS_0_SCRATCH, s0);
1252		atombios_scratch_write(ctx, R600_BIOS_2_SCRATCH, s2);
1253		atombios_scratch_write(ctx, R600_BIOS_3_SCRATCH, s3);
1254		atombios_scratch_write(ctx, R600_BIOS_6_SCRATCH, s6);
1255	}
