1299	/* ---- VBIOS loading ---- */
1300	
1301	/*
1302	 * Prefer a RAM copy because FSP GOP updates its ATOMBIOS tables in place.
1303	 * Otherwise load the immutable image from CBFS or the PCI expansion ROM BAR.
1304	 */
1305	static void *load_vbios(struct device *dev, size_t *size)
1306	{
1307		void *rom = NULL;
1308		size_t rom_size = 0;
1309	
1310		*size = 0;
1311		char cbfs_name[24];
1312		uint16_t vendor = dev->vendor;
1313		uint16_t device_id = dev->device;
1314		uint16_t rom_size_field;
1315		uint32_t mapped_vendev;
1316		struct rom_header *ram_rom = dev->pci_vga_option_rom;
1317	
1318		if (ram_rom && le16_to_cpu(ram_rom->signature) == PCI_ROM_HDR) {
1319			rom_size = ram_rom->size * 512;
1320			if (rom_size && rom_size <= 512 * 1024) {
1321				printk(BIOS_INFO,
1322				       "ATOMBIOS: using in-memory VBIOS (%zu bytes)\n",
1323				       rom_size);
1324				*size = rom_size;
1325				return ram_rom;
1326			}
1327		}
1328	
1329		mapped_vendev = map_oprom_vendev(((uint32_t)vendor << 16) | device_id);
1330		vendor = mapped_vendev >> 16;
1331		device_id = mapped_vendev;
1332	
1333		snprintf(cbfs_name, sizeof(cbfs_name), "pci%04x,%04x.rom",
1334			 vendor, device_id);
1335	
1336		rom = cbfs_map(cbfs_name, &rom_size);
1337		if (rom) {
1338			printk(BIOS_INFO, "ATOMBIOS: loaded VBIOS from CBFS: %s (%zu bytes)\n",
1339			       cbfs_name, rom_size);
1340			*size = rom_size;
1341			return rom;
1342		}
1343	
1344		/* Try PCI expansion ROM BAR */
1345		uint32_t rom_bar = pci_read_config32(dev, PCI_ROM_ADDRESS);
1346		if (!(rom_bar & 1)) {
1347			/* Enable ROM decode */
1348			pci_write_config32(dev, PCI_ROM_ADDRESS, rom_bar | 1);
1349			rom_bar = pci_read_config32(dev, PCI_ROM_ADDRESS);
1350		}
1351		rom_bar &= PCI_ROM_ADDRESS_MASK;
1352		if (!rom_bar) {
1353			printk(BIOS_ERR, "ATOMBIOS: no VBIOS found in CBFS or ROM BAR\n");
1354			return NULL;
1355		}
1356	
1357		/* Validate ROM magic */
1358		if (read16((void *)(uintptr_t)rom_bar) != 0xAA55) {
1359			printk(BIOS_ERR, "ATOMBIOS: ROM BAR has no valid BIOS signature\n");
1360			pci_write_config32(dev, PCI_ROM_ADDRESS, rom_bar & ~1u);
1361			return NULL;
1362		}
1363	
1364		/* Read ROM size from byte 2 (in 512-byte units) */
1365		rom_size_field = read8((void *)(uintptr_t)(rom_bar + 2));
1366		rom_size = rom_size_field * 512;
1367		if (rom_size == 0 || rom_size > 512 * 1024)
1368			rom_size = 128 * 1024; /* sane default */
1369	
1370		/* Copy to RAM so we can disable the ROM BAR */
1371		rom = malloc(rom_size);
1372		if (!rom) {
1373			printk(BIOS_ERR, "ATOMBIOS: failed to allocate %zu bytes for VBIOS\n",
1374			       rom_size);
1375			return NULL;
1376		}
1377		memcpy(rom, (void *)(uintptr_t)rom_bar, rom_size);
1378	
1379		/* Disable ROM BAR */
1380		pci_write_config32(dev, PCI_ROM_ADDRESS, rom_bar & ~1u);
1381	
1382		printk(BIOS_INFO, "ATOMBIOS: loaded VBIOS from PCI ROM BAR (%zu bytes)\n",
1383		       rom_size);
1384		*size = rom_size;
1385		return rom;
1386	}
