1406	
1407	static void atombios_gpio_i2c_lookup_quirks(ATOM_GPIO_I2C_ASSIGMENT *gpio,
1408						    uint8_t index)
1409	{
1410		/* Linux radeon has this DCE3 quirk for bad GPIO_I2C_Info data. */
1411		if (index == 4 && gpio->usClkMaskRegisterIndex == 0x1fda &&
1412		    gpio->sucI2cId.ucAccess == 0x94)
1413			gpio->sucI2cId.ucAccess = 0x14;
1414	}
1415	
1416	static void atombios_i2c_bus_from_gpio(struct atombios_i2c_bus_rec *bus,
1417					       const ATOM_GPIO_I2C_ASSIGMENT *gpio)
1418	{
1419		memset(bus, 0, sizeof(*bus));
1420	
1421		if (gpio->ucClkMaskShift >= 32 || gpio->ucDataMaskShift >= 32 ||
1422		    gpio->ucClkEnShift >= 32 || gpio->ucDataEnShift >= 32 ||
1423		    gpio->ucClkY_Shift >= 32 || gpio->ucDataY_Shift >= 32 ||
1424		    gpio->ucClkA_Shift >= 32 || gpio->ucDataA_Shift >= 32)
1425			return;
1426	
1427		bus->mask_clk_reg = gpio->usClkMaskRegisterIndex * 4;
1428		bus->mask_data_reg = gpio->usDataMaskRegisterIndex * 4;
1429		bus->en_clk_reg = gpio->usClkEnRegisterIndex * 4;
1430		bus->en_data_reg = gpio->usDataEnRegisterIndex * 4;
1431		bus->y_clk_reg = gpio->usClkY_RegisterIndex * 4;
1432		bus->y_data_reg = gpio->usDataY_RegisterIndex * 4;
1433		bus->a_clk_reg = gpio->usClkA_RegisterIndex * 4;
1434		bus->a_data_reg = gpio->usDataA_RegisterIndex * 4;
1435		bus->mask_clk_mask = 1u << gpio->ucClkMaskShift;
1436		bus->mask_data_mask = 1u << gpio->ucDataMaskShift;
1437		bus->en_clk_mask = 1u << gpio->ucClkEnShift;
1438		bus->en_data_mask = 1u << gpio->ucDataEnShift;
1439		bus->y_clk_mask = 1u << gpio->ucClkY_Shift;
1440		bus->y_data_mask = 1u << gpio->ucDataY_Shift;
1441		bus->a_clk_mask = 1u << gpio->ucClkA_Shift;
1442		bus->a_data_mask = 1u << gpio->ucDataA_Shift;
1443		bus->i2c_id = gpio->sucI2cId.ucAccess;
1444		bus->hw_capable = !!(gpio->sucI2cId.ucAccess &
1445			ATOM_DEVICE_I2C_HARDWARE_CAP_MASK);
1446		bus->valid = !!bus->mask_clk_reg;
1447	}
1448	
1449	static int atombios_lookup_i2c_gpio(struct atom_context *ctx, uint8_t i2c_id,
1450					    struct atombios_i2c_bus_rec *bus)
1451	{
1452		ATOM_GPIO_I2C_INFO *i2c_info;
1453		ATOM_GPIO_I2C_ASSIGMENT *gpio;
1454		uint16_t data_offset, size;
1455		int num_indices;
1456		int i;
1457	
1458		memset(bus, 0, sizeof(*bus));
1459	
1460		if (!atom_parse_data_header(ctx, cmd_idx.data_gpio_i2c, &size, NULL,
1461					    NULL, &data_offset) ||
1462		    size < sizeof(ATOM_COMMON_TABLE_HEADER))
1463			return -1;
1464	
1465		i2c_info = (ATOM_GPIO_I2C_INFO *)((uint8_t *)ctx->bios + data_offset);
1466		num_indices = (size - sizeof(ATOM_COMMON_TABLE_HEADER)) /
1467			sizeof(ATOM_GPIO_I2C_ASSIGMENT);
1468		gpio = &i2c_info->asGPIO_Info[0];
1469	
1470		for (i = 0; i < num_indices; i++) {
1471			atombios_gpio_i2c_lookup_quirks(gpio, i);
1472			if (gpio->sucI2cId.ucAccess == i2c_id) {
1473				atombios_i2c_bus_from_gpio(bus, gpio);
1474				return bus->valid ? 0 : -1;
1475			}
1476			gpio = (ATOM_GPIO_I2C_ASSIGMENT *)
1477				((uint8_t *)gpio + sizeof(ATOM_GPIO_I2C_ASSIGMENT));
1478		}
1479	
1480		return -1;
1481	}
1482	
1483	static void atombios_gpio_i2c_pre_xfer(struct atom_context *ctx,
1484					       const struct atombios_i2c_bus_rec *bus)
1485	{
1486		uint32_t temp;
1487	
1488		/* Linux switches DCE3 hardware-capable pads to DDC/GPIO mode. */
1489		if (bus->hw_capable) {
1490			temp = atombios_mmio_read(ctx, bus->mask_clk_reg);
1491			temp &= ~(1u << 16);
1492			atombios_mmio_write(ctx, bus->mask_clk_reg, temp);
1493		}
1494	
1495		/* Clear output values. */
1496		temp = atombios_mmio_read(ctx, bus->a_clk_reg) & ~bus->a_clk_mask;
1497		atombios_mmio_write(ctx, bus->a_clk_reg, temp);
1498		temp = atombios_mmio_read(ctx, bus->a_data_reg) & ~bus->a_data_mask;
1499		atombios_mmio_write(ctx, bus->a_data_reg, temp);
1500	
1501		/* Release pins, then mask them for software use. */
1502		temp = atombios_mmio_read(ctx, bus->en_clk_reg) & ~bus->en_clk_mask;
1503		atombios_mmio_write(ctx, bus->en_clk_reg, temp);
1504		temp = atombios_mmio_read(ctx, bus->en_data_reg) & ~bus->en_data_mask;
1505		atombios_mmio_write(ctx, bus->en_data_reg, temp);
1506		temp = atombios_mmio_read(ctx, bus->mask_clk_reg) | bus->mask_clk_mask;
1507		atombios_mmio_write(ctx, bus->mask_clk_reg, temp);
1508		(void)atombios_mmio_read(ctx, bus->mask_clk_reg);
1509		temp = atombios_mmio_read(ctx, bus->mask_data_reg) | bus->mask_data_mask;
1510		atombios_mmio_write(ctx, bus->mask_data_reg, temp);
1511		(void)atombios_mmio_read(ctx, bus->mask_data_reg);
1512	}
1513	
1514	static void atombios_gpio_i2c_post_xfer(struct atom_context *ctx,
1515						const struct atombios_i2c_bus_rec *bus)
1516	{
1517		uint32_t temp;
1518	
1519		temp = atombios_mmio_read(ctx, bus->mask_clk_reg) & ~bus->mask_clk_mask;
1520		atombios_mmio_write(ctx, bus->mask_clk_reg, temp);
1521		(void)atombios_mmio_read(ctx, bus->mask_clk_reg);
1522		temp = atombios_mmio_read(ctx, bus->mask_data_reg) & ~bus->mask_data_mask;
1523		atombios_mmio_write(ctx, bus->mask_data_reg, temp);
1524		(void)atombios_mmio_read(ctx, bus->mask_data_reg);
1525	}
