1527	static int atombios_gpio_i2c_get_clock(struct atom_context *ctx,
1528					       const struct atombios_i2c_bus_rec *bus)
1529	{
1530		return !!(atombios_mmio_read(ctx, bus->y_clk_reg) & bus->y_clk_mask);
1531	}
