1533	static int atombios_gpio_i2c_get_data(struct atom_context *ctx,
1534					      const struct atombios_i2c_bus_rec *bus)
1535	{
1536		return !!(atombios_mmio_read(ctx, bus->y_data_reg) & bus->y_data_mask);
