1563	static void atombios_gpio_i2c_delay(void)
1564	{
1565		udelay(10);
1566	}
1567	
1568	static int atombios_gpio_i2c_wait_clock_high(struct atom_context *ctx,
1569						     const struct atombios_i2c_bus_rec *bus)
1570	{
1571		int i;
1572	
1573		atombios_gpio_i2c_set_clock(ctx, bus, 1);
1574		for (i = 0; i < 100; i++) {
1575			atombios_gpio_i2c_delay();
1576			if (atombios_gpio_i2c_get_clock(ctx, bus))
1577				return 0;
1578		}
1579		return -1;
1580	}
1581	
1582	static int atombios_gpio_i2c_start(struct atom_context *ctx,
1583					   const struct atombios_i2c_bus_rec *bus)
1584	{
1585		atombios_gpio_i2c_set_data(ctx, bus, 1);
1586		if (atombios_gpio_i2c_wait_clock_high(ctx, bus))
1587			return -1;
1588		atombios_gpio_i2c_set_data(ctx, bus, 0);
1589		atombios_gpio_i2c_delay();
1590		atombios_gpio_i2c_set_clock(ctx, bus, 0);
1591		atombios_gpio_i2c_delay();
1592		return 0;
1593	}
1594	
1595	static void atombios_gpio_i2c_stop(struct atom_context *ctx,
1596					  const struct atombios_i2c_bus_rec *bus)
1597	{
1598		atombios_gpio_i2c_set_data(ctx, bus, 0);
1599		atombios_gpio_i2c_delay();
1600		atombios_gpio_i2c_wait_clock_high(ctx, bus);
1601		atombios_gpio_i2c_set_data(ctx, bus, 1);
1602		atombios_gpio_i2c_delay();
1603	}
1604	
1605	static int atombios_gpio_i2c_write_byte(struct atom_context *ctx,
1606						const struct atombios_i2c_bus_rec *bus,
1607						uint8_t val)
1608	{
1609		int i;
1610		int ack;
1611	
1612		for (i = 7; i >= 0; i--) {
1613			atombios_gpio_i2c_set_data(ctx, bus, !!(val & (1u << i)));
1614			atombios_gpio_i2c_delay();
1615			if (atombios_gpio_i2c_wait_clock_high(ctx, bus))
1616				return -1;
1617			atombios_gpio_i2c_set_clock(ctx, bus, 0);
1618			atombios_gpio_i2c_delay();
1619		}
1620	
1621		atombios_gpio_i2c_set_data(ctx, bus, 1);
1622		atombios_gpio_i2c_delay();
1623		if (atombios_gpio_i2c_wait_clock_high(ctx, bus))
1624			return -1;
1625		ack = !atombios_gpio_i2c_get_data(ctx, bus);
1626		atombios_gpio_i2c_set_clock(ctx, bus, 0);
1627		atombios_gpio_i2c_delay();
1628	
1629		return ack ? 0 : -1;
1630	}
1631	
1632	static int atombios_gpio_i2c_read_byte(struct atom_context *ctx,
1633					       const struct atombios_i2c_bus_rec *bus,
1634					       uint8_t *val, int last)
1635	{
1636		uint8_t data = 0;
1637		int i;
1638	
1639		atombios_gpio_i2c_set_data(ctx, bus, 1);
1640		for (i = 7; i >= 0; i--) {
1641			if (atombios_gpio_i2c_wait_clock_high(ctx, bus))
1642				return -1;
1643			if (atombios_gpio_i2c_get_data(ctx, bus))
1644				data |= 1u << i;
1645			atombios_gpio_i2c_set_clock(ctx, bus, 0);
1646			atombios_gpio_i2c_delay();
1647		}
1648	
1649		/* ACK every byte except the last one. */
1650		atombios_gpio_i2c_set_data(ctx, bus, last ? 1 : 0);
1651		atombios_gpio_i2c_delay();
1652		if (atombios_gpio_i2c_wait_clock_high(ctx, bus))
1653			return -1;
1654		atombios_gpio_i2c_set_clock(ctx, bus, 0);
1655		atombios_gpio_i2c_set_data(ctx, bus, 1);
1656		atombios_gpio_i2c_delay();
1657	
1658		*val = data;
1659		return 0;
1660	}
1661	
1662	static int atombios_gpio_i2c_read(struct atom_context *ctx, uint8_t i2c_line,
1663					  uint8_t slave_addr, uint8_t reg_offset,
1664					  uint8_t *buf, uint8_t len)
1665	{
1666		struct atombios_i2c_bus_rec bus;
1667		int ret = -1;
1668		int i;
1669	
1670		if (atombios_lookup_i2c_gpio(ctx, i2c_line, &bus))
1671			return -1;
1672	
1673		printk(BIOS_DEBUG,
1674		       "ATOMBIOS: GPIO DDC line=0x%02x clk=0x%04x/%08x data=0x%04x/%08x hw=%d\n",
1675		       i2c_line, bus.en_clk_reg, bus.en_clk_mask, bus.en_data_reg,
1676		       bus.en_data_mask, bus.hw_capable);
1677	
1678		atombios_gpio_i2c_pre_xfer(ctx, &bus);
1679	
1680		if (atombios_gpio_i2c_start(ctx, &bus))
1681			goto out;
1682		if (atombios_gpio_i2c_write_byte(ctx, &bus, slave_addr << 1))
1683			goto stop;
1684		if (atombios_gpio_i2c_write_byte(ctx, &bus, reg_offset))
1685			goto stop;
1686		if (atombios_gpio_i2c_start(ctx, &bus))
1687			goto stop;
1688		if (atombios_gpio_i2c_write_byte(ctx, &bus, (slave_addr << 1) | 1))
1689			goto stop;
1690		for (i = 0; i < len; i++) {
1691			if (atombios_gpio_i2c_read_byte(ctx, &bus, &buf[i], i == len - 1))
1692				goto stop;
1693		}
1694		ret = 0;
1695	
1696	stop:
1697		atombios_gpio_i2c_stop(ctx, &bus);
1698	out:
1699		atombios_gpio_i2c_post_xfer(ctx, &bus);
1700		return ret;
1701	}
