1703	/* ---- EDID reading via ATOM I2C ---- */
1704	
1705	/*
1706	 * Read a single I2C transaction via the ProcessI2cChannelTransaction
1707	 * ATOM command table. This is used for DDC/EDID reading.
1708	 *
1709	 * Returns 0 on success, -1 on failure.
1710	 */
1711	static int atombios_i2c_write_offset(struct atom_context *ctx, uint8_t i2c_line,
1712					     uint8_t slave_addr, uint8_t reg_offset)
1713	{
1714		PROCESS_I2C_CHANNEL_TRANSACTION_PARAMETERS args;
1715		int ret;
1716	
1717		memset(&args, 0, sizeof(args));
1718		args.ucI2CSpeed = 50; /* 50 kHz */
1719		args.ucRegIndex = reg_offset;
1720		args.lpI2CDataOut = 0;
1721		args.ucFlag = HW_I2C_WRITE;
1722		args.ucTransBytes = 0;
1723		args.ucSlaveAddr = slave_addr << 1;
1724		args.ucLineNumber = i2c_line;
1725	
1726		ret = atom_execute_table(ctx, cmd_idx.process_i2c, (uint32_t *)&args,
1727					 sizeof(args));
1728		if (ret || args.ucStatus != HW_ASSISTED_I2C_STATUS_SUCCESS) {
1729			printk(BIOS_DEBUG,
1730			       "ATOMBIOS: ATOM I2C offset write failed "
1731			       "(line=0x%02x addr=0x%02x status=%d)\n",
1732			       i2c_line, slave_addr, args.ucStatus);
1733			return -1;
1734		}
1735	
1736		return 0;
1737	}
1738	
1739	static int atombios_i2c_read_chunk(struct atom_context *ctx, uint8_t i2c_line,
1740					   uint8_t slave_addr, uint8_t reg_offset,
1741					   uint8_t *buf, uint8_t len)
1742	{
1743		PROCESS_I2C_CHANNEL_TRANSACTION_PARAMETERS args;
1744		int ret;
1745	
1746		if (len > ATOM_MAX_HW_I2C_READ)
1747			len = ATOM_MAX_HW_I2C_READ;
1748	
1749		memset(&args, 0, sizeof(args));
1750		args.ucI2CSpeed = 50; /* 50 kHz */
1751		args.ucRegIndex = reg_offset;
1752		args.lpI2CDataOut = 0;
1753		args.ucFlag = HW_I2C_READ;
1754		args.ucTransBytes = len;
1755		args.ucSlaveAddr = slave_addr << 1;
1756		args.ucLineNumber = i2c_line;
1757	
1758		ret = atom_execute_table(ctx, cmd_idx.process_i2c, (uint32_t *)&args,
1759					 sizeof(args));
1760		if (ret || args.ucStatus != HW_ASSISTED_I2C_STATUS_SUCCESS) {
1761			printk(BIOS_DEBUG,
1762			       "ATOMBIOS: ATOM I2C read failed "
1763			       "(line=0x%02x addr=0x%02x status=%d)\n",
1764			       i2c_line, slave_addr, args.ucStatus);
1765			return -1;
1766		}
1767	
1768		memcpy(buf, ctx->scratch, len);
1769		return 0;
1770	}
1771	
1772	static int atombios_i2c_read(struct atom_context *ctx, uint8_t i2c_line,
1773				     uint8_t slave_addr, uint8_t reg_offset,
1774				     uint8_t *buf, uint8_t len)
1775	{
1776		if (!atombios_i2c_write_offset(ctx, i2c_line, slave_addr, reg_offset))
1777			return atombios_i2c_read_chunk(ctx, i2c_line, slave_addr, 0, buf, len);
1778	
1779		/* Some older VBIOS tables combine the offset and read in one call. */
1780		return atombios_i2c_read_chunk(ctx, i2c_line, slave_addr, reg_offset,
1781					     buf, len);
1782	}
