1784	/*
1785	 * Read EDID from a display via ATOM I2C.
1786	 *
1787	 * Reads one 128-byte EDID block from DDC slave address 0x50.
1788	 * Returns 0 on success, -1 on failure.
1789	 */
1790	static int atombios_read_edid(struct atom_context *ctx, uint8_t i2c_line,
1791				      uint8_t *edid_buf)
1792	{
1793		int offset;
1794		int chunk;
1795		int ret;
1796	
1797		printk(BIOS_DEBUG, "ATOMBIOS: reading EDID on I2C line 0x%02x\n", i2c_line);
1798	
1799		/*
1800		 * Read EDID in chunks. The ProcessI2cChannelTransaction table
1801		 * can read up to 255 bytes, but some implementations are limited.
1802		 * Use 16-byte chunks for maximum compatibility.
1803		 */
1804		for (offset = 0; offset < EDID_BLOCK_SIZE; offset += chunk) {
1805			chunk = EDID_BLOCK_SIZE - offset;
1806			if (chunk > 16)
1807				chunk = 16;
1808	
1809			ret = atombios_gpio_i2c_read(ctx, i2c_line, DDC_EDID_ADDRESS,
1810						     (uint8_t)offset,
1811						     edid_buf + offset, (uint8_t)chunk);
1812			if (ret) {
1813				printk(BIOS_DEBUG,
1814				       "ATOMBIOS: GPIO DDC failed, trying ATOM I2C\n");
1815				ret = atombios_i2c_read(ctx, i2c_line, DDC_EDID_ADDRESS,
1816							(uint8_t)offset, edid_buf + offset,
1817							(uint8_t)chunk);
1818			}
1819			if (ret)
1820				return -1;
1821		}
1822	
1823		/* Validate EDID header: 00 FF FF FF FF FF FF 00 */
1824		if (edid_buf[0] != 0x00 || edid_buf[1] != 0xFF ||
1825		    edid_buf[6] != 0xFF || edid_buf[7] != 0x00) {
1826			printk(BIOS_DEBUG,
1827			       "ATOMBIOS: EDID header invalid on I2C line 0x%02x: "
1828			       "%02x %02x %02x %02x %02x %02x %02x %02x\n",
1829			       i2c_line, edid_buf[0], edid_buf[1], edid_buf[2],
1830			       edid_buf[3], edid_buf[4], edid_buf[5], edid_buf[6],
1831			       edid_buf[7]);
1832			return -1;
1833		}
1834	
1835		printk(BIOS_INFO, "ATOMBIOS: EDID read successfully on I2C line 0x%02x\n",
1836		       i2c_line);
1837		return 0;
1838	}
