1185	
1186		crtc_control = atombios_mmio_read(ctx, EVERGREEN_CRTC_CONTROL);
1187		blank_control = atombios_mmio_read(ctx, EVERGREEN_CRTC_BLANK_CONTROL);
1188	
1189		atombios_mmio_write(ctx, EVERGREEN_CRTC_UPDATE_LOCK, 1);
1190		atombios_mmio_write(ctx, EVERGREEN_CRTC_BLANK_CONTROL,
1191				   blank_control & ~EVERGREEN_CRTC_BLANK_DATA_EN);
1192		atombios_mmio_write(ctx, EVERGREEN_CRTC_CONTROL,
1193				   crtc_control & ~EVERGREEN_CRTC_DISP_READ_REQUEST_DISABLE);
1194		atombios_mmio_write(ctx, EVERGREEN_CRTC_UPDATE_LOCK, 0);
1195	
1196		printk(BIOS_DEBUG,
1197		       "ATOMBIOS: CRTC ctrl=0x%08x blank=0x%08x after unblank\n",
1198		       atombios_mmio_read(ctx, EVERGREEN_CRTC_CONTROL),
1199		       atombios_mmio_read(ctx, EVERGREEN_CRTC_BLANK_CONTROL));
1200	}
