1539	static void atombios_gpio_i2c_set_clock(struct atom_context *ctx,
1540						const struct atombios_i2c_bus_rec *bus,
1541						int high)
1542	{
1543		uint32_t val;
1544	
1545		val = atombios_mmio_read(ctx, bus->en_clk_reg) & ~bus->en_clk_mask;
1546		if (!high)
1547			val |= bus->en_clk_mask;
1548		atombios_mmio_write(ctx, bus->en_clk_reg, val);
