1551	static void atombios_gpio_i2c_set_data(struct atom_context *ctx,
1552					       const struct atombios_i2c_bus_rec *bus,
1553					       int data)
1554	{
1555		uint32_t val;
1556	
1557		val = atombios_mmio_read(ctx, bus->en_data_reg) & ~bus->en_data_mask;
1558		if (!data)
1559			val |= bus->en_data_mask;
1560		atombios_mmio_write(ctx, bus->en_data_reg, val);
1561	}
