1705	/*
1706	 * Read a single I2C transaction via the ProcessI2cChannelTransaction
1707	 * ATOM command table. This is used for DDC/EDID reading.
1708	 *
1709	 * Returns 0 on success, -1 on failure.
1710	 */
1711	static int atombios_i2c_write_offset(struct atom_context *ctx, uint8_t i2c_line,
1712					     uint8_t slave_addr, uint8_t reg_offset)
1713	{
1714		PROCESS_I2C_CHANNEL_TRANSACTION_PARAMETERS args;
1715		int ret;
1716	
1717		memset(&args, 0, sizeof(args));
1718		args.ucI2CSpeed = 50; /* 50 kHz */
1719		args.ucRegIndex = reg_offset;
1720		args.lpI2CDataOut = 0;
1721		args.ucFlag = HW_I2C_WRITE;
1722		args.ucTransBytes = 0;
1723		args.ucSlaveAddr = slave_addr << 1;
1724		args.ucLineNumber = i2c_line;
1725	
1726		ret = atom_execute_table(ctx, cmd_idx.process_i2c, (uint32_t *)&args,
1727					 sizeof(args));
1728		if (ret || args.ucStatus != HW_ASSISTED_I2C_STATUS_SUCCESS) {
1729			printk(BIOS_DEBUG,
1730			       "ATOMBIOS: ATOM I2C offset write failed "
1731			       "(line=0x%02x addr=0x%02x status=%d)\n",
1732			       i2c_line, slave_addr, args.ucStatus);
1733			return -1;
1734		}
1735	
1736		return 0;
1737	}
