1739	static int atombios_i2c_read_chunk(struct atom_context *ctx, uint8_t i2c_line,
1740					   uint8_t slave_addr, uint8_t reg_offset,
1741					   uint8_t *buf, uint8_t len)
1742	{
1743		PROCESS_I2C_CHANNEL_TRANSACTION_PARAMETERS args;
1744		int ret;
1745	
1746		if (len > ATOM_MAX_HW_I2C_READ)
1747			len = ATOM_MAX_HW_I2C_READ;
1748	
1749		memset(&args, 0, sizeof(args));
1750		args.ucI2CSpeed = 50; /* 50 kHz */
1751		args.ucRegIndex = reg_offset;
1752		args.lpI2CDataOut = 0;
1753		args.ucFlag = HW_I2C_READ;
1754		args.ucTransBytes = len;
1755		args.ucSlaveAddr = slave_addr << 1;
1756		args.ucLineNumber = i2c_line;
1757	
1758		ret = atom_execute_table(ctx, cmd_idx.process_i2c, (uint32_t *)&args,
1759					 sizeof(args));
1760		if (ret || args.ucStatus != HW_ASSISTED_I2C_STATUS_SUCCESS) {
1761			printk(BIOS_DEBUG,
1762			       "ATOMBIOS: ATOM I2C read failed "
1763			       "(line=0x%02x addr=0x%02x status=%d)\n",
1764			       i2c_line, slave_addr, args.ucStatus);
