1772	static int atombios_i2c_read(struct atom_context *ctx, uint8_t i2c_line,
1773				     uint8_t slave_addr, uint8_t reg_offset,
1774				     uint8_t *buf, uint8_t len)
1775	{
1776		if (!atombios_i2c_write_offset(ctx, i2c_line, slave_addr, reg_offset))
1777			return atombios_i2c_read_chunk(ctx, i2c_line, slave_addr, 0, buf, len);
1778	
1779		/* Some older VBIOS tables combine the offset and read in one call. */
1780		return atombios_i2c_read_chunk(ctx, i2c_line, slave_addr, reg_offset,
1781					     buf, len);
