1840	/* ---- DP AUX channel via ProcessAuxChannelTransaction ---- */
1841	
1842	/*
1843	 * Perform a DP AUX channel transaction via the ATOM command table.
1844	 *
1845	 * The ATOM table uses the scratch register area for data:
1846	 *   scratch+4:  AUX request bytes (4-byte header + write payload)
1847	 *   scratch+20: AUX reply data
1848	 *
1849	 * Returns number of reply bytes on success, -1 on failure.
1850	 */
1851	static int atombios_dp_aux_transfer(struct atom_context *ctx,
1852					    uint8_t aux_id, uint8_t hpd_id,
1853					    uint8_t request, uint32_t address,
1854					    uint8_t *send, uint8_t send_len,
1855					    uint8_t *recv, uint8_t recv_size)
1856	{
1857		PROCESS_AUX_CHANNEL_TRANSACTION_PARAMETERS_V2 args;
1858		uint8_t *base;
1859		uint8_t tx_buf[20];
1860		uint8_t request_type = request & ~DP_AUX_I2C_MOT;
1861		uint8_t transfer_len = send_len ? send_len : recv_size;
1862		bool write_request;
1863		int tx_size;
1864		int recv_bytes;
1865	
1866		write_request = request_type == DP_AUX_NATIVE_WRITE ||
1867			request_type == DP_AUX_I2C_WRITE;
1868	
1869		/* ATOM supports 12-byte writes and 16-byte reads. */
1870		if ((write_request && send_len > 12) || (!write_request && recv_size > 16))
1871			return -1;
1872	
1873		/* Build 4-byte AUX request header */
1874		tx_buf[0] = address & 0xFF;
1875		tx_buf[1] = (address >> 8) & 0xFF;
1876		tx_buf[2] = (request << 4) | ((address >> 16) & 0xF);
1877		tx_buf[3] = transfer_len ? (transfer_len - 1) : 0;
1878	
1879		if (write_request && send_len > 0) {
1880			tx_size = DP_AUX_HEADER_SIZE + send_len;
1881			tx_buf[3] |= (tx_size << 4);
1882			memcpy(tx_buf + DP_AUX_HEADER_SIZE, send, send_len);
1883		} else {
1884			tx_size = DP_AUX_HEADER_SIZE;
1885			tx_buf[3] |= ((transfer_len ? tx_size : DP_AUX_HEADER_SIZE - 1) << 4);
1886		}
1887	
1888		/* Copy request into scratch area at offset +4 (DWORD 1) */
1889		base = (uint8_t *)(ctx->scratch + 1);
1890		memcpy(base, tx_buf, tx_size);
1891	
1892		memset(&args, 0, sizeof(args));
1893		args.lpAuxRequest = 0 + 4;   /* byte offset in scratch for request */
1894		args.lpDataOut = 16 + 4;     /* byte offset in scratch for reply */
1895		args.ucDataOutLen = 0;
1896		args.ucChannelID = aux_id;
1897		args.ucDelay = 0;
1898		args.ucHPD_ID = hpd_id <= 5 ? hpd_id : 0;
1899	
1900		if (atom_execute_table(ctx, cmd_idx.process_aux,

text:
1900		if (atom_execute_table(ctx, cmd_idx.process_aux,
1901				       (uint32_t *)&args,
1902				       sizeof(args))) {
1903			return -1;
1904		}
1905	
1906		/* Check reply status: 0=ok, 1=timeout, 2=flags, 3=error */
1907		if (args.ucReplyStatus != 0) {
1908			printk(BIOS_DEBUG, "ATOMBIOS: AUX reply status %d\n",
1909			       args.ucReplyStatus);
1910			return -1;
1911		}
1912	
1913		recv_bytes = args.ucDataOutLen;
1914		if (recv && recv_size && recv_bytes > 0) {
1915			if (recv_bytes > recv_size)
1916				recv_bytes = recv_size;
1917			memcpy(recv, base + 16, recv_bytes);
1918		}
1919	
1920		return recv_bytes;
1921	}
