1965	static int atombios_dp_read_edid(struct atom_context *ctx,
1966					 uint8_t aux_id, uint8_t hpd_id,
1967					 uint8_t *edid_buf)
1968	{
1969		int offset;
1970	
1971		for (offset = 0; offset < EDID_BLOCK_SIZE; offset += 16) {
1972			uint8_t reg = offset;
1973	
1974			if (dp_aux_i2c_write(ctx, aux_id, hpd_id, DDC_EDID_ADDRESS,
1975					      &reg, 1, true) ||
1976			    dp_aux_i2c_read(ctx, aux_id, hpd_id, DDC_EDID_ADDRESS,
1977					     edid_buf + offset, 16, false))
1978				return -1;
1979		}
1980	
1981		if (edid_buf[0] != 0x00 || edid_buf[1] != 0xff ||
1982		    edid_buf[6] != 0xff || edid_buf[7] != 0x00)
1983			return -1;
1984	
1985		printk(BIOS_INFO, "ATOMBIOS: EDID read successfully over DP AUX\n");
1986		return 0;
1987	}
