1989	static int atombios_read_path_edid(struct atom_context *ctx,
1990					   struct atombios_display_path *path,
1991					   uint8_t *edid_buf)
1992	{
1993		uint8_t dpcd_rev;
1994	
1995		if (path->encoder_mode != ATOM_ENCODER_MODE_DP)
1996			return atombios_read_edid(ctx, path->i2c_line, edid_buf);
1997	
1998		if (!dp_aux_native_read(ctx, path->i2c_line, path->hpd_id,
1999					DP_DPCD_REV, &dpcd_rev, 1))
2000			return atombios_dp_read_edid(ctx, path->i2c_line,
2001						     path->hpd_id, edid_buf);
2002	
2003		/* A DP receptacle without a DPCD response may have a passive TMDS adapter. */
2004		if (atombios_object_id(path->connector_obj_id) == CONNECTOR_OBJECT_ID_DISPLAYPORT) {
2005			printk(BIOS_INFO,
2006			       "ATOMBIOS: DP path has no native sink, trying TMDS DDC\n");
2007			path->encoder_mode = ATOM_ENCODER_MODE_DVI;
2008			path->dp_lane_count = 0;
2009			path->dp_link_bw = 0;
2010			return atombios_read_edid(ctx, path->i2c_line, edid_buf);
2011		}
2012	
2013		return -1;
2014	}
