2024	
2025	static uint8_t dp_get_lane_status(const uint8_t link_status[DP_LINK_STATUS_SIZE],
2026					  int lane)
2027	{
2028		int idx = (lane >> 1); /* 0 for lanes 0,1; 1 for lanes 2,3 */
2029		int shift = (lane & 1) * 4;
2030		return (link_status[idx] >> shift) & 0xF;
2031	}
2032	
2033	static bool dp_clock_recovery_ok(const uint8_t link_status[DP_LINK_STATUS_SIZE],
2034					 int lane_count)
2035	{
2036		int lane;
2037		for (lane = 0; lane < lane_count; lane++) {
2038			if (!(dp_get_lane_status(link_status, lane) & DP_LANE_CR_DONE))
2039				return false;
2040		}
2041		return true;
2042	}
2043	
2044	static bool dp_channel_eq_ok(const uint8_t link_status[DP_LINK_STATUS_SIZE],
2045				     int lane_count)
2046	{
2047		int lane;
2048		/* Check interlane alignment */
2049		if (!(link_status[DP_LANE_ALIGN_STATUS_UPDATED - DP_LANE0_1_STATUS]
2050		      & DP_INTERLANE_ALIGN_DONE))
2051			return false;
2052		for (lane = 0; lane < lane_count; lane++) {
2053			if ((dp_get_lane_status(link_status, lane) & DP_CHANNEL_EQ_BITS)
2054			    != DP_CHANNEL_EQ_BITS)
2055				return false;
2056		}
2057		return true;
2058	}
