2060	/*
2061	 * Extract voltage swing and pre-emphasis adjustment requests from the sink.
2062	 * DPCD registers 0x206-0x207 contain the requested settings.
2063	 */
2064	static void dp_get_adjust_train(const uint8_t link_status[DP_LINK_STATUS_SIZE],
2065					int lane_count, uint8_t train_set[4])
2066	{
2067		uint8_t voltage = 0;
2068		uint8_t pre_emph = 0;
2069		int lane;
2070	
2071		for (lane = 0; lane < lane_count; lane++) {
2072			int idx = (lane >> 1) + (DP_ADJUST_REQUEST_LANE0_1 - DP_LANE0_1_STATUS);
2073			int shift = (lane & 1) * 4;
2074			uint8_t adj_req = (link_status[idx] >> shift) & 0xF;
2075			uint8_t lane_voltage = adj_req & DP_TRAIN_VOLTAGE_SWING_MASK;
2076			uint8_t lane_pre_emph = (adj_req & 0xc) << 1;
2077	
2078			if (lane_voltage > voltage)
2079				voltage = lane_voltage;
2080			if (lane_pre_emph > pre_emph)
2081				pre_emph = lane_pre_emph;
2082		}
2083	
2084		if (voltage == DP_TRAIN_VOLTAGE_SWING_MASK)
2085			voltage |= DP_TRAIN_MAX_SWING_REACHED;
2086		if (pre_emph == DP_TRAIN_PRE_EMPHASIS_MASK)
2087			pre_emph |= DP_TRAIN_MAX_PRE_REACHED;
2088	
2089		for (lane = 0; lane < 4; lane++)
2090			train_set[lane] = voltage | pre_emph;
2091	}
2092	
2093	static int atombios_dp_get_link_config(const uint8_t dpcd[DP_RECEIVER_CAP_SIZE],
2094						       uint32_t pixel_clock_khz,
2095						       uint8_t *lane_count,
2096						       uint8_t *link_bw)
2097	{
2098		static const uint8_t link_bw_codes[] = {
2099			DP_LINK_BW_1_62,
2100			DP_LINK_BW_2_7,
2101			DP_LINK_BW_5_4,
2102		};
2103		uint8_t max_link_bw = dpcd[DP_MAX_LINK_RATE];
2104		uint8_t max_lanes = dpcd[DP_MAX_LANE_COUNT] & 0x1f;
2105		int i;
2106	
2107		if (max_lanes > 4)
2108			max_lanes = 4;
2109		if (max_lanes == 0)
2110			max_lanes = 1;
2111	
2112		for (i = 0; i < ARRAY_SIZE(link_bw_codes); i++) {
2113			uint8_t bw = link_bw_codes[i];
2114			uint32_t link_clock_khz;
2115			uint8_t lanes;
2116	
2117			if (bw > max_link_bw)
2118				continue;
2119	
2120			link_clock_khz = dp_link_bw_code_to_clock_khz(bw);
2121			for (lanes = 1; lanes <= max_lanes; lanes <<= 1) {
2122				/* 8b/10b link coding, 24 bpp framebuffer. */
2123				uint32_t max_pixel_clock = (lanes * link_clock_khz * 8) / 24;
2124	
2125				if (max_pixel_clock >= pixel_clock_khz) {
2126					*lane_count = lanes;
2127					*link_bw = bw;
2128					return 0;
2129				}
2130			}
2131		}
2132	
2133		return -1;
2134	}
