2137	
2138	struct dp_link_train_info {
2139		struct atom_context *ctx;
2140		const struct atombios_display_path *path;
2141		uint8_t aux_id;
2142		uint8_t hpd_id;
2143		uint8_t dpcd[DP_RECEIVER_CAP_SIZE];
2144		uint8_t link_status[DP_LINK_STATUS_SIZE];
2145		uint8_t train_set[4];
2146		uint8_t dp_lane_count;
2147		uint8_t dp_link_bw;
2148		uint16_t pixel_clock_10khz;
2149		bool tp3_supported;
2150	};
2151	
2152	static void dp_set_training_pattern(struct dp_link_train_info *info, int pattern)
2153	{
2154		int encoder_cmd = 0;
2155	
2156		switch (pattern) {
2157		case DP_TRAINING_PATTERN_1:
2158			encoder_cmd = ATOM_ENCODER_CMD_DP_LINK_TRAINING_PATTERN1;
2159			break;
2160		case DP_TRAINING_PATTERN_2:
2161			encoder_cmd = ATOM_ENCODER_CMD_DP_LINK_TRAINING_PATTERN2;
2162			break;
2163		case DP_TRAINING_PATTERN_3:
2164			encoder_cmd = ATOM_ENCODER_CMD_DP_LINK_TRAINING_PATTERN3;
2165			break;
2166		}
2167	
2168		/* Set pattern on source */
2169		atombios_dig_encoder_setup(info->ctx, info->path,
2170					   info->pixel_clock_10khz,
2171					   encoder_cmd, PANEL_8BIT_PER_COLOR);
2172		/* Set pattern on sink */
2173		dp_dpcd_writeb(info->ctx, info->aux_id, info->hpd_id,
2174			       DP_TRAINING_PATTERN_SET, pattern);
2175	}
2176	
2177	static void dp_update_vs_emph(struct dp_link_train_info *info)
2178	{
2179		/* Set voltage swing and pre-emphasis on source transmitter. */
2180		atombios_transmitter_control(info->ctx, info->path,
2181					     info->pixel_clock_10khz,
2182					     ATOM_TRANSMITTER_ACTION_SETUP_VSEMPH,
2183					     info->dp_lane_count, info->train_set[0]);
2184	
2185		/* Set on sink (write lane training registers) */
2186		dp_aux_native_write(info->ctx, info->aux_id, info->hpd_id,
2187				    DP_TRAINING_LANE0_SET,
2188				    info->train_set, info->dp_lane_count);
2189	}
2190	
2191	static int dp_link_train_init(struct dp_link_train_info *info)
2192	{
2193		uint8_t tmp;
2194	
2195		/* Power up DP 1.1+ sinks. */
2196		if (info->dpcd[DP_DPCD_REV] >= 0x11) {
2197			dp_dpcd_writeb(info->ctx, info->aux_id, info->hpd_id,
2198				       DP_SET_POWER, DP_SET_POWER_D0);
2199			mdelay(1);
2200		}
2201	
2202		/* Enable downspread if supported */
2203		if (info->dpcd[DP_MAX_DOWNSPREAD] & 0x01)
2204			dp_dpcd_writeb(info->ctx, info->aux_id, info->hpd_id,
2205				       DP_DOWNSPREAD_CTRL, DP_SPREAD_AMP_0_5);
2206		else
2207			dp_dpcd_writeb(info->ctx, info->aux_id, info->hpd_id,
2208				       DP_DOWNSPREAD_CTRL, 0);
2209	
2210		/* Set lane count (with enhanced framing if supported) */
2211		tmp = info->dp_lane_count;
2212		if (info->dpcd[DP_MAX_LANE_COUNT] & (1 << 7)) /* enhanced frame cap */
2213			tmp |= DP_LANE_COUNT_ENHANCED_FRAME_EN;
2214		dp_dpcd_writeb(info->ctx, info->aux_id, info->hpd_id,
2215			       DP_LANE_COUNT_SET, tmp);
2216	
2217		/* Set link bandwidth */
2218		dp_dpcd_writeb(info->ctx, info->aux_id, info->hpd_id,
2219			       DP_LINK_BW_SET, info->dp_link_bw);
2220	
2221		if (info->path->dp_panel_mode == DP_PANEL_MODE_INTERNAL_DP2_MODE)
2222			dp_dpcd_writeb(info->ctx, info->aux_id, info->hpd_id,
2223				       DP_EDP_CONFIGURATION_SET, 1);
2224	
2225		/* Start training on source encoder */
2226		atombios_dig_encoder_setup(info->ctx, info->path,
2227					   info->pixel_clock_10khz,
2228					   ATOM_ENCODER_CMD_DP_LINK_TRAINING_START,
2229					   PANEL_8BIT_PER_COLOR);
2230	
2231		/* Disable training pattern on sink */
2232		dp_dpcd_writeb(info->ctx, info->aux_id, info->hpd_id,
2233			       DP_TRAINING_PATTERN_SET, DP_TRAINING_PATTERN_DISABLE);
2234	
2235		return 0;
2236	}
2237	
2238	static int dp_link_train_cr(struct dp_link_train_info *info)
2239	{
2240		uint8_t voltage;
2241		int tries = 0;
2242		int i;
2243	
2244		/* Set training pattern 1 */
2245		dp_set_training_pattern(info, DP_TRAINING_PATTERN_1);
2246		memset(info->train_set, 0, sizeof(info->train_set));
2247		dp_update_vs_emph(info);
2248		udelay(400);
2249	
2250		voltage = 0xFF;
2251		while (1) {
2252			/* Wait for clock recovery (100us per DP spec) */
2253			udelay(100);
2254	
2255			/* Read link status */
2256			if (dp_aux_native_read(info->ctx, info->aux_id, info->hpd_id,
2257					       DP_LANE0_1_STATUS, info->link_status,
2258					       DP_LINK_STATUS_SIZE) < 0) {
2259				printk(BIOS_ERR, "ATOMBIOS: DP link status read failed\n");
2260				return -1;
2261			}
2262	
2263			if (dp_clock_recovery_ok(info->link_status, info->dp_lane_count)) {
2264				printk(BIOS_INFO, "ATOMBIOS: DP clock recovery OK\n");
2265				return 0;
2266			}
2267	
2268			/* Check if all lanes hit max swing */
2269			for (i = 0; i < info->dp_lane_count; i++) {
2270				if (!(info->train_set[i] & DP_TRAIN_MAX_SWING_REACHED))
2271					break;
2272			}
2273			if (i == info->dp_lane_count) {
2274				printk(BIOS_ERR, "ATOMBIOS: DP CR failed: max voltage reached\n");
2275				return -1;
2276			}
2277	
2278			/* Check for no progress */
2279			if ((info->train_set[0] & DP_TRAIN_VOLTAGE_SWING_MASK) == voltage) {
2280				if (++tries >= 5) {
2281					printk(BIOS_ERR, "ATOMBIOS: DP CR failed: 5 tries\n");
2282					return -1;
2283				}
2284			} else {
2285				tries = 0;
2286			}
2287			voltage = info->train_set[0] & DP_TRAIN_VOLTAGE_SWING_MASK;
2288	
2289			/* Adjust based on sink request */
2290			dp_get_adjust_train(info->link_status, info->dp_lane_count,
2291					    info->train_set);
2292			dp_update_vs_emph(info);
2293		}
2294	}
2295	
2296	static int dp_link_train_ce(struct dp_link_train_info *info)
2297	{
2298		int tries = 0;
2299	
2300		/* Set training pattern 3 (preferred) or 2 */
2301		if (info->tp3_supported)
2302			dp_set_training_pattern(info, DP_TRAINING_PATTERN_3);
2303		else
2304			dp_set_training_pattern(info, DP_TRAINING_PATTERN_2);
2305	
2306		while (1) {
2307			/* Wait for channel equalization (400us per DP spec) */
2308			udelay(400);
2309	
2310			if (dp_aux_native_read(info->ctx, info->aux_id, info->hpd_id,
2311					       DP_LANE0_1_STATUS, info->link_status,
2312					       DP_LINK_STATUS_SIZE) < 0) {
2313				printk(BIOS_ERR, "ATOMBIOS: DP link status read failed\n");
2314				return -1;
2315			}
2316	
2317			if (dp_channel_eq_ok(info->link_status, info->dp_lane_count)) {
2318				printk(BIOS_INFO, "ATOMBIOS: DP channel equalization OK\n");
2319				return 0;
2320			}
2321	
2322			if (++tries > 5) {
2323				printk(BIOS_ERR, "ATOMBIOS: DP channel EQ failed: 5 tries\n");
2324				return -1;
2325			}
2326	
2327			dp_get_adjust_train(info->link_status, info->dp_lane_count,
2328					    info->train_set);
2329			dp_update_vs_emph(info);
2330		}
2331	}
2332	
2333	static void dp_link_train_finish(struct dp_link_train_info *info)
2334	{
2335		udelay(400);
2336	
2337		/* Disable training pattern on sink */
2338		dp_dpcd_writeb(info->ctx, info->aux_id, info->hpd_id,
2339			       DP_TRAINING_PATTERN_SET, DP_TRAINING_PATTERN_DISABLE);
2340	
2341		/* Complete training on source */
2342		atombios_dig_encoder_setup(info->ctx, info->path,
2343					   info->pixel_clock_10khz,
2344					   ATOM_ENCODER_CMD_DP_LINK_TRAINING_COMPLETE,
2345					   PANEL_8BIT_PER_COLOR);
2346	}
2347	
2348	/*
2349	 * Full DP link training sequence.
2350	 * Returns 0 on success, -1 on failure.
2351	 */
2352	static int atombios_dp_link_train(struct atom_context *ctx,
2353					  const struct atombios_display_path *path,
2354					  uint16_t pixel_clock_10khz,
2355					  uint8_t aux_id, uint8_t hpd_id)
2356	{
2357		struct dp_link_train_info info;
2358		struct atombios_display_path train_path = *path;
2359		int ret;
2360	
2361		memset(&info, 0, sizeof(info));
2362		info.ctx = ctx;
2363		info.path = &train_path;
2364		info.aux_id = aux_id;
2365		info.hpd_id = hpd_id;
2366		info.pixel_clock_10khz = pixel_clock_10khz;
2367	
2368		/* Read receiver capabilities (DPCD 0x000-0x00E) */
2369		if (dp_aux_native_read(ctx, aux_id, hpd_id, DP_DPCD_REV,
2370				       info.dpcd, DP_RECEIVER_CAP_SIZE) < 0) {
2371			printk(BIOS_ERR, "ATOMBIOS: failed to read DP receiver caps\n");
2372			return -1;
2373		}
2374	
2375		printk(BIOS_INFO, "ATOMBIOS: DP DPCD rev=%d.%d max_rate=0x%02x max_lanes=%d\n",
2376		       info.dpcd[0] >> 4, info.dpcd[0] & 0xF,
2377		       info.dpcd[DP_MAX_LINK_RATE],
2378		       info.dpcd[DP_MAX_LANE_COUNT] & 0x1F);
2379	
2380		if (path->dp_link_bw && path->dp_lane_count) {
2381			info.dp_link_bw = path->dp_link_bw;
2382			info.dp_lane_count = path->dp_lane_count;
2383		} else if (atombios_dp_get_link_config(info.dpcd,
2384						       (uint32_t)pixel_clock_10khz * 10,
2385						       &info.dp_lane_count,
2386						       &info.dp_link_bw)) {
2387			printk(BIOS_WARNING,
2388			       "ATOMBIOS: failed to choose DP link config, using sink maximum\n");
2389			info.dp_link_bw = info.dpcd[DP_MAX_LINK_RATE];
2390			info.dp_lane_count = info.dpcd[DP_MAX_LANE_COUNT] & 0x1F;
2391			if (info.dp_lane_count > 4)
2392				info.dp_lane_count = 4;
2393		}
2394		if (!info.dp_lane_count)
2395			info.dp_lane_count = 1;
2396		if (!info.dp_link_bw)
2397			info.dp_link_bw = DP_LINK_BW_1_62;
2398		train_path.dp_lane_count = info.dp_lane_count;
2399		train_path.dp_link_bw = info.dp_link_bw;
2400	
2401		/* Only use TPS3 on HBR2 links; older sources cannot generate it. */
2402		info.tp3_supported = info.dp_link_bw >= DP_LINK_BW_5_4 &&
2403			!!(info.dpcd[DP_MAX_LANE_COUNT] & DP_TPS3_SUPPORTED);
2404	
2405		/* Init */
2406		ret = dp_link_train_init(&info);
2407		if (ret)
2408			goto done;
2409	
2410		/* Phase 1: Clock Recovery */
2411		ret = dp_link_train_cr(&info);
2412		if (ret)
2413			goto done;
2414	
2415		/* Phase 2: Channel Equalization */
2416		ret = dp_link_train_ce(&info);
2417	
2418	done:
2419		/* Always finish training (even on failure) */
2420		dp_link_train_finish(&info);
2421	
2422		if (ret == 0) {
2423			/* Enable video on source */
2424			atombios_dig_encoder_setup(ctx, info.path, pixel_clock_10khz,
2425						   ATOM_ENCODER_CMD_DP_VIDEO_ON,
2426						   PANEL_8BIT_PER_COLOR);
2427			printk(BIOS_INFO, "ATOMBIOS: DP link training succeeded (%d lanes @ 0x%02x)\n",
2428			       info.dp_lane_count, info.dp_link_bw);
2429		} else {
2430			printk(BIOS_ERR, "ATOMBIOS: DP link training FAILED\n");
2431		}
2432	
2433		return ret;
2434	}
2435	
2436	static int atombios_dp_prepare_link(struct atom_context *ctx,
2437					    struct atombios_display_path *path,
2438					    uint32_t pixel_clock_khz)
2439	{
2440		uint8_t dpcd[DP_RECEIVER_CAP_SIZE];
2441	
2442		if (path->encoder_mode != ATOM_ENCODER_MODE_DP || !path->i2c_valid)
2443			return 0;
2444	
2445		if (dp_aux_native_read(ctx, path->i2c_line, path->hpd_id, DP_DPCD_REV,
2446				       dpcd, sizeof(dpcd)) < 0) {
2447			printk(BIOS_WARNING, "ATOMBIOS: failed to read DP DPCD caps\n");
2448			return -1;
2449		}
2450	
2451		if (atombios_dp_get_link_config(dpcd, pixel_clock_khz,
2452					       &path->dp_lane_count, &path->dp_link_bw)) {
2453			printk(BIOS_WARNING,
2454			       "ATOMBIOS: no DP link config for %u kHz pixel clock\n",
2455			       pixel_clock_khz);
2456			return -1;
2457		}
2458	
2459		path->dp_panel_mode = DP_PANEL_MODE_EXTERNAL_DP_MODE;
2460		if (atombios_object_id(path->connector_obj_id) == CONNECTOR_OBJECT_ID_eDP &&
2461		    (dpcd[DP_EDP_CONFIGURATION_CAP] & 1))
2462			path->dp_panel_mode = DP_PANEL_MODE_INTERNAL_DP2_MODE;
2463	
2464		printk(BIOS_INFO, "ATOMBIOS: selected DP link %d lanes @ 0x%02x\n",
2465		       path->dp_lane_count, path->dp_link_bw);
2466		return 0;
2467	}
