3392	/*
3393	 * Parse the ATOM Object_Header data table to discover display paths.
3394	 * Each path maps a connector to an encoder chain.
3395	 *
3396	 * Returns the number of display paths found, or 0 on error.
3397	 */
3398	static int atombios_discover_display_paths(struct atom_context *ctx,
3399						   struct atombios_display_path *paths,
3400						   int max_paths)
3401	{
3402		uint16_t data_offset;
3403		uint8_t frev, crev;
3404		int count = 0;
3405		ATOM_OBJECT_HEADER *obj_hdr;
3406		ATOM_DISPLAY_OBJECT_PATH_TABLE *path_tbl;
3407		uint8_t *base;
3408		int i;
3409		uint16_t path_offset;
3410	
3411		if (!atom_parse_data_header(ctx, cmd_idx.data_object_header,
3412					    NULL, &frev, &crev, &data_offset)) {
3413			printk(BIOS_WARNING,
3414			       "ATOMBIOS: Object_Header table not found, trying SupportedDevicesInfo\n");
3415			return atombios_discover_supported_device_paths(ctx, paths, max_paths);
3416		}
3417	
3418		base = (uint8_t *)ctx->bios;
3419		obj_hdr = (ATOM_OBJECT_HEADER *)(base + data_offset);
3420	
3421		if (!obj_hdr->usDisplayPathTableOffset) {
3422			printk(BIOS_WARNING,
3423			       "ATOMBIOS: no display path table, trying SupportedDevicesInfo\n");
3424			return atombios_discover_supported_device_paths(ctx, paths, max_paths);
3425		}
3426	
3427		path_tbl = (ATOM_DISPLAY_OBJECT_PATH_TABLE *)
3428			   (base + data_offset + obj_hdr->usDisplayPathTableOffset);
3429	
3430		printk(BIOS_INFO, "ATOMBIOS: found %d display paths (version %d)\n",
3431		       path_tbl->ucNumOfDispPath, path_tbl->ucVersion);
3432	
3433		/* Walk each display path */
3434		path_offset = (uint16_t)((uint8_t *)path_tbl->asDispPath - base);
3435		for (i = 0; i < path_tbl->ucNumOfDispPath && count < max_paths; i++) {
3436			ATOM_DISPLAY_OBJECT_PATH *disp_path;
3437			uint16_t conn_obj_id, enc_obj_id;
3438			uint8_t obj_type, obj_id, enc_id;
3439			int j;
3440	
3441			disp_path = (ATOM_DISPLAY_OBJECT_PATH *)(base + path_offset);
3442	
3443			conn_obj_id = disp_path->usConnObjectId;
3444			obj_type = (conn_obj_id & OBJECT_TYPE_MASK) >> OBJECT_TYPE_SHIFT;
3445	
3446			if (obj_type != GRAPH_OBJECT_TYPE_CONNECTOR ||
3447			    !(obj_hdr->usDeviceSupport & disp_path->usDeviceTag)) {
3448				/* Skip to next path using usSize */
3449				path_offset += disp_path->usSize;
3450				continue;
3451			}
3452	
3453			obj_id = (conn_obj_id & OBJECT_ID_MASK) >> OBJECT_ID_SHIFT;
3454	
3455			paths[count].connector_obj_id = conn_obj_id;
3456			paths[count].device_tag = disp_path->usDeviceTag;
3457			paths[count].hpd_id = ATOMBIOS_HPD_NONE;
3458	
3459			/* Map ATOM connector object ID to a simple type */
3460			switch (obj_id) {
3461			case CONNECTOR_OBJECT_ID_HDMI_TYPE_A:
3462				paths[count].connector_type = 1; /* HDMI */
3463				/* Linux drives HDMI as DVI/TMDS when audio/infoframes are off. */
3464				paths[count].encoder_mode = ATOM_ENCODER_MODE_DVI;
3465				break;
3466			case CONNECTOR_OBJECT_ID_DISPLAYPORT:
3467			case CONNECTOR_OBJECT_ID_eDP:
3468				paths[count].connector_type = 2; /* DP/eDP */
3469				paths[count].encoder_mode = ATOM_ENCODER_MODE_DP;
3470				break;
3471			case CONNECTOR_OBJECT_ID_LVDS:
3472			case CONNECTOR_OBJECT_ID_LVDS_eDP:
3473				paths[count].connector_type = 2; /* internal panel */
3474				paths[count].encoder_mode = ATOM_ENCODER_MODE_LVDS;
3475				break;
3476			case CONNECTOR_OBJECT_ID_SINGLE_LINK_DVI_D:
3477			case CONNECTOR_OBJECT_ID_DUAL_LINK_DVI_D:
3478			case CONNECTOR_OBJECT_ID_SINGLE_LINK_DVI_I:
3479			case CONNECTOR_OBJECT_ID_DUAL_LINK_DVI_I:
3480				paths[count].connector_type = 3; /* DVI */
3481				paths[count].encoder_mode = ATOM_ENCODER_MODE_DVI;
3482				break;
3483			case CONNECTOR_OBJECT_ID_VGA:
3484				paths[count].connector_type = 4; /* VGA */
3485				paths[count].encoder_mode = ATOM_ENCODER_MODE_CRT;
3486				break;
3487			default:
3488				paths[count].connector_type = 0;
3489				paths[count].encoder_mode = ATOM_ENCODER_MODE_DVI;
3490				break;
3491			}
3492	
3493			/* Walk graphic objects in the path to find encoder */
3494			for (j = 0; j < (disp_path->usSize - 8) / 2; j++) {
3495				enc_obj_id = disp_path->usGraphicObjIds[j];
3496				obj_type = (enc_obj_id & OBJECT_TYPE_MASK) >> OBJECT_TYPE_SHIFT;
3497	
3498				if (obj_type != GRAPH_OBJECT_TYPE_ENCODER)
3499					continue;
3500	
3501				enc_id = (enc_obj_id & OBJECT_ID_MASK) >> OBJECT_ID_SHIFT;
3502				paths[count].encoder_obj_id = enc_id;
3503	
3504				/* Determine encoder type from encoder object ID */
3505				switch (enc_id) {
3506				case ENCODER_OBJECT_ID_INTERNAL_LVDS:
3507					paths[count].is_legacy_lvds = 1;
3508					paths[count].encoder_mode = ATOM_ENCODER_MODE_LVDS;
3509					break;
3510				case ENCODER_OBJECT_ID_INTERNAL_TMDS1:
3511				case ENCODER_OBJECT_ID_INTERNAL_TMDS2:
3512				case ENCODER_OBJECT_ID_INTERNAL_KLDSCP_TMDS1:
3513					paths[count].is_legacy_tmds = 1;
3514					paths[count].encoder_mode = ATOM_ENCODER_MODE_DVI;
3515					break;
3516				case ENCODER_OBJECT_ID_INTERNAL_KLDSCP_DVO1:
3517					paths[count].encoder_mode = ATOM_ENCODER_MODE_DVI;
3518					break;
3519				case ENCODER_OBJECT_ID_INTERNAL_LVTM1:
3520					if (paths[count].device_tag & ATOM_DEVICE_LCD_SUPPORT) {
3521						paths[count].is_legacy_lvds = 1;
3522						paths[count].encoder_mode = ATOM_ENCODER_MODE_LVDS;
3523					} else {
3524						paths[count].is_legacy_tmds = 1;
3525						paths[count].encoder_mode = ATOM_ENCODER_MODE_DVI;
3526					}
3527					break;
3528				case ENCODER_OBJECT_ID_INTERNAL_KLDSCP_LVTMA:
3529					paths[count].dig_encoder = 1; /* DIG2 on DCE3 */
3530					paths[count].phy_id = 1;      /* LVTMA */
3531					if (paths[count].connector_type == 2)
3532						paths[count].encoder_mode = ATOM_ENCODER_MODE_LVDS;
3533					break;
3534				case ENCODER_OBJECT_ID_INTERNAL_UNIPHY:
3535					paths[count].dig_encoder = 0; /* DIG1 */
3536					paths[count].phy_id = 0;      /* UNIPHY_A */
3537					break;
3538				case ENCODER_OBJECT_ID_INTERNAL_UNIPHY1:
3539					paths[count].dig_encoder = 2; /* DIG3 */
3540					paths[count].phy_id = 2;      /* UNIPHY_C */
3541					break;
3542				case ENCODER_OBJECT_ID_INTERNAL_UNIPHY2:
3543					paths[count].dig_encoder = 4; /* DIG5 */
3544					paths[count].phy_id = 4;      /* UNIPHY_E */
3545					break;
3546				case ENCODER_OBJECT_ID_INTERNAL_UNIPHY3:
3547					paths[count].dig_encoder = 6; /* DIG7 */
3548					paths[count].phy_id = 6;      /* UNIPHY_G */
3549					break;
3550				case ENCODER_OBJECT_ID_INTERNAL_KLDSCP_DAC1:
3551					paths[count].is_dac = 1;
3552					paths[count].dac_type = ATOM_DAC_A;
3553					paths[count].encoder_mode = ATOM_ENCODER_MODE_CRT;
3554					break;
3555				case ENCODER_OBJECT_ID_INTERNAL_KLDSCP_DAC2:
3556					paths[count].is_dac = 1;
3557					paths[count].dac_type = ATOM_DAC_B;
3558					paths[count].encoder_mode = ATOM_ENCODER_MODE_CRT;
3559					break;
3560				default:
3561					paths[count].dig_encoder = 0;
3562					paths[count].phy_id = 0;
3563					break;
3564				}
3565	
3566				/* For DIG encoders, check link B (ENUM_ID_2) */
3567				if (!paths[count].is_dac &&
3568				    ((enc_obj_id & ENUM_ID_MASK) >> ENUM_ID_SHIFT) == GRAPH_OBJECT_ENUM_ID2) {
3569					paths[count].dig_encoder += 1;
3570					paths[count].phy_id += 1;
3571				}
3572				break; /* use first encoder found */
3573			}
3574	
3575			atombios_read_connector_records(ctx, obj_hdr, data_offset, &paths[count]);
3576	
3577			count++;
3578			path_offset += disp_path->usSize;
3579		}
3580	
3581		if (!count)
3582			return atombios_discover_supported_device_paths(ctx, paths, max_paths);
3583	
3584		atombios_apply_supported_device_info(ctx, paths, count);
3585	
3586		for (i = 0; i < count; i++) {
3587			if (paths[i].is_dac)
3588				printk(BIOS_INFO,
3589				       "ATOMBIOS: path %d: tag=0x%04x conn=0x%04x type=%d i2c=0x%02x DAC-%c mode=CRT\n",
3590				       i, paths[i].device_tag, paths[i].connector_obj_id,
3591				       paths[i].connector_type, paths[i].i2c_line,
3592				       paths[i].dac_type == ATOM_DAC_A ? 'A' : 'B');
3593			else if (paths[i].is_legacy_tmds || paths[i].is_legacy_lvds)
3594				printk(BIOS_INFO,
3595				       "ATOMBIOS: path %d: tag=0x%04x conn=0x%04x type=%d "
3596				       "i2c=0x%02x enc=0x%02x legacy %s mode=%d\n",
3597				       i, paths[i].device_tag, paths[i].connector_obj_id,
3598				       paths[i].connector_type, paths[i].i2c_line,
3599				       paths[i].encoder_obj_id,
3600				       paths[i].is_legacy_lvds ? "LVDS" : "TMDS",
3601				       paths[i].encoder_mode);
3602			else
3603				printk(BIOS_INFO,
3604				       "ATOMBIOS: path %d: tag=0x%04x conn=0x%04x type=%d "
3605				       "i2c=0x%02x enc=0x%02x dig=%d phy=%d mode=%d\n",
3606				       i, paths[i].device_tag, paths[i].connector_obj_id,
3607				       paths[i].connector_type, paths[i].i2c_line,
3608				       paths[i].encoder_obj_id, paths[i].dig_encoder,
3609				       paths[i].phy_id, paths[i].encoder_mode);
3610		}
3611	
3612		return count;
3613	}
