3617	
3618	static int atombios_legacy_lvds_encoder_setup(struct atom_context *ctx,
3619						      const struct atombios_display_path *path,
3620						      uint16_t pixel_clock_10khz,
3621						      uint8_t action)
3622	{
3623		uint8_t frev, crev;
3624		union {
3625			LVDS_ENCODER_CONTROL_PARAMETERS v1;
3626			LVDS_ENCODER_CONTROL_PARAMETERS_V2 v2;
3627		} args;
3628	
3629		if (cmd_idx.lvds_encoder_ctrl < 0 ||
3630		    !atom_parse_cmd_header(ctx, cmd_idx.lvds_encoder_ctrl, &frev, &crev) ||
3631		    (frev != 1 && frev != 2) || crev < 1 || crev > 3)
3632			return -1;
3633	
3634		memset(&args, 0, sizeof(args));
3635		args.v1.usPixelClock = pixel_clock_10khz;
3636		args.v1.ucAction = action;
3637		if (path->lcd_misc & ATOM_PANEL_MISC_DUAL)
3638			args.v1.ucMisc |= PANEL_ENCODER_MISC_DUAL;
3639	
3640		if (crev == 1) {
3641			if (path->lcd_misc & ATOM_PANEL_MISC_888RGB)
3642				args.v1.ucMisc |= ATOM_PANEL_MISC_888RGB;
3643		} else {
3644			if (path->lcd_misc & ATOM_PANEL_MISC_SPATIAL) {
3645				args.v2.ucSpatial = PANEL_ENCODER_SPATIAL_DITHER_EN;
3646				if (path->lcd_misc & ATOM_PANEL_MISC_888RGB)
3647					args.v2.ucSpatial |= PANEL_ENCODER_SPATIAL_DITHER_DEPTH;
3648			}
3649			if (path->lcd_misc & ATOM_PANEL_MISC_TEMPORAL) {
3650				args.v2.ucTemporal = PANEL_ENCODER_TEMPORAL_DITHER_EN;
3651				if (path->lcd_misc & ATOM_PANEL_MISC_888RGB)
3652					args.v2.ucTemporal |= PANEL_ENCODER_TEMPORAL_DITHER_DEPTH;
3653				if (((path->lcd_misc >> ATOM_PANEL_MISC_GREY_LEVEL_SHIFT) & 3) == 2)
3654					args.v2.ucTemporal |= PANEL_ENCODER_TEMPORAL_LEVEL_4;
3655			}
3656		}
3657	
3658		printk(BIOS_DEBUG,
3659		       "ATOMBIOS: legacy LVDS encoder frev=%d crev=%d action=%d clock=%d*10kHz\n",
3660		       frev, crev, action, pixel_clock_10khz);
3661		return atom_execute_table(ctx, cmd_idx.lvds_encoder_ctrl,
3662					  (uint32_t *)&args, sizeof(args));
3663	}
