3759	/* ---- DIG Encoder Control ---- */
3760	
3761	/*
3762	 * Configure the DIG encoder block for the specified display mode.
3763	 *
3764	 * This calls the DIGxEncoderControl ATOM command table which programs
3765	 * the DIG encoder for DP, HDMI, DVI, or LVDS mode.
3766	 */
3767	static int atombios_dig_encoder_setup(struct atom_context *ctx,
3768					      const struct atombios_display_path *path,
3769					      uint16_t pixel_clock_10khz,
3770					      uint8_t action, uint8_t bpc)
3771	{
3772		uint8_t frev, crev;
3773		uint8_t lane_num;
3774		union {
3775			DIG_ENCODER_CONTROL_PARAMETERS      v1;
3776			DIG_ENCODER_CONTROL_PARAMETERS_V2   v2;
3777			DIG_ENCODER_CONTROL_PARAMETERS_V3   v3;
3778			DIG_ENCODER_CONTROL_PARAMETERS_V4   v4;
3779			DIG_ENCODER_CONTROL_PARAMETERS_V5   v5;
3780		} args;
3781	
3782		if (!atom_parse_cmd_header(ctx, cmd_idx.dig_encoder_ctrl, &frev, &crev))
3783			return -1;
3784	
3785		memset(&args, 0, sizeof(args));
3786	
3787		if (path->encoder_mode == ATOM_ENCODER_MODE_DP && path->dp_lane_count)
3788			lane_num = path->dp_lane_count;
3789		else if (atombios_uses_dual_link(path, pixel_clock_10khz))
3790			lane_num = 8;
3791		else
3792			lane_num = 4;
3793	
3794		printk(BIOS_DEBUG,
3795		       "ATOMBIOS: DIG encoder setup frev=%d crev=%d action=0x%02x "
3796		       "mode=%d lanes=%d link_bw=0x%02x\n",
3797		       frev, crev, action, path->encoder_mode, lane_num, path->dp_link_bw);
3798	
3799		switch (crev) {
3800		case 1:
3801			args.v1.ucAction = action;
3802			args.v1.usPixelClock = pixel_clock_10khz;
3803			if (action == ATOM_ENCODER_CMD_SETUP_PANEL_MODE)
3804				args.v3.ucPanelMode = path->dp_panel_mode;
3805			else
3806				args.v1.ucEncoderMode = path->encoder_mode;
3807			args.v1.ucLaneNum = lane_num;
3808			if (path->phy_id / 2 == 1)
3809				args.v1.ucConfig |= ATOM_ENCODER_CONFIG_TRANSMITTER2;
3810			else if (path->phy_id / 2 == 2)
3811				args.v1.ucConfig |= 0x10;
3812			if (path->dig_encoder & 1)
3813				args.v1.ucConfig |= ATOM_ENCODER_CONFIG_LINKB;
3814			if (path->encoder_mode == ATOM_ENCODER_MODE_DP &&
3815			    path->dp_link_bw >= DP_LINK_BW_2_7)
3816				args.v1.ucConfig |= ATOM_ENCODER_CONFIG_DPLINKRATE_2_70GHZ;
3817			break;
3818		case 2:
3819		case 3:
3820			args.v3.ucAction = action;
3821			args.v3.usPixelClock = pixel_clock_10khz;
3822			if (action == ATOM_ENCODER_CMD_SETUP_PANEL_MODE)
3823				args.v3.ucPanelMode = path->dp_panel_mode;
3824			else
3825				args.v3.ucEncoderMode = path->encoder_mode;
3826			args.v3.ucLaneNum = lane_num;
3827			args.v3.ucBitPerColor = bpc;
3828			args.v3.acConfig.ucDigSel = path->dig_encoder;
3829			if (path->encoder_mode == ATOM_ENCODER_MODE_DP &&
3830			    path->dp_link_bw >= DP_LINK_BW_2_7)
3831				args.v3.acConfig.ucDPLinkRate = 1;
3832			break;
3833		case 4:
3834			args.v4.ucAction = action;
3835			args.v4.usPixelClock = pixel_clock_10khz;
3836			if (action == ATOM_ENCODER_CMD_SETUP_PANEL_MODE)
3837				args.v4.ucPanelMode = path->dp_panel_mode;
3838			else
3839				args.v4.ucEncoderMode = path->encoder_mode;
3840			args.v4.ucLaneNum = lane_num;
3841			args.v4.ucBitPerColor = bpc;
3842			args.v4.ucHPD_ID = path->hpd_id <= 5 ? path->hpd_id + 1 : 0;
3843			args.v4.acConfig.ucDigSel = path->dig_encoder;
3844			if (path->encoder_mode == ATOM_ENCODER_MODE_DP) {
3845				if (path->dp_link_bw >= DP_LINK_BW_5_4)
3846					args.v4.acConfig.ucDPLinkRate =
3847						ATOM_ENCODER_CONFIG_V4_DPLINKRATE_5_40GHZ;
3848				else if (path->dp_link_bw >= DP_LINK_BW_2_7)
3849					args.v4.acConfig.ucDPLinkRate =
3850						ATOM_ENCODER_CONFIG_V4_DPLINKRATE_2_70GHZ;
3851				else
3852					args.v4.acConfig.ucDPLinkRate =
3853						ATOM_ENCODER_CONFIG_V4_DPLINKRATE_1_62GHZ;
3854			}
3855			break;
3856		case 5:
3857		default:
3858			if (action == ATOM_ENCODER_CMD_SETUP_PANEL_MODE) {
3859				args.v5.asDPPanelModeParam.ucDigId = path->dig_encoder;
3860				args.v5.asDPPanelModeParam.ucAction = action;
3861				args.v5.asDPPanelModeParam.ucPanelMode = path->dp_panel_mode;
3862			} else if (action == ATOM_ENCODER_CMD_STREAM_SETUP) {
3863				args.v5.asStreamParam.ucDigId = path->dig_encoder;
3864				args.v5.asStreamParam.ucAction = action;
3865				args.v5.asStreamParam.ucDigMode = path->encoder_mode;
3866				args.v5.asStreamParam.ucLaneNum = lane_num;
3867				args.v5.asStreamParam.ulPixelClock = pixel_clock_10khz;
3868				args.v5.asStreamParam.ucBitPerColor = bpc;
3869				if (path->encoder_mode == ATOM_ENCODER_MODE_DP)
3870					args.v5.asStreamParam.ucLinkRateIn270Mhz = path->dp_link_bw;
3871			} else {
3872				args.v5.asCmdParam.ucDigId = path->dig_encoder;
3873				args.v5.asCmdParam.ucAction = action;
3874			}
3875			break;
3876		}
3877	
3878		return atom_execute_table(ctx, cmd_idx.dig_encoder_ctrl,
3879					  (uint32_t *)&args,
3880					  sizeof(args));
3881	}
3882	
3883	/* ---- UNIPHY Transmitter Control ---- */
3884	
3885	/*
3886	 * Control the UNIPHY transmitter (physical link layer).
3887	 *
3888	 * Actions: INIT, ENABLE, DISABLE, SETUP_VSEMPH, POWER_ON/OFF.
3889	 * This programs the PHY for the target link rate and drives the
3890	 * physical signals.
3891	 */
3892	static int atombios_transmitter_control(struct atom_context *ctx,
3893						const struct atombios_display_path *path,
3894						uint16_t pixel_clock_10khz,
3895						uint8_t action,
3896						uint8_t lane_num, uint8_t lane_set)
3897	{
3898		uint8_t frev, crev;
3899		uint8_t transmitter_lane_num;
3900		uint16_t sym_clock_10khz;
3901		bool dual_link = atombios_uses_dual_link(path, pixel_clock_10khz);
3902		union {
3903			DIG_TRANSMITTER_CONTROL_PARAMETERS       v1;
3904			DIG_TRANSMITTER_CONTROL_PARAMETERS_V2    v2;
3905			DIG_TRANSMITTER_CONTROL_PARAMETERS_V3    v3;
3906			DIG_TRANSMITTER_CONTROL_PARAMETERS_V4    v4;
3907			DIG_TRANSMITTER_CONTROL_PARAMETERS_V1_5  v5;
3908			struct {
3909				DIG_TRANSMITTER_CONTROL_PARAMETERS_V1_6 param;
3910				uint32_t reserved[4];
3911			} v6;
3912		} args;
3913	
3914		if (!atom_parse_cmd_header(ctx, cmd_idx.dig1_xmtr_ctrl, &frev, &crev))
3915			return -1;
3916	
3917		memset(&args, 0, sizeof(args));
3918	
3919		transmitter_lane_num = lane_num;
3920		if (!transmitter_lane_num) {
3921			if (path->encoder_mode == ATOM_ENCODER_MODE_DP && path->dp_lane_count)
3922				transmitter_lane_num = path->dp_lane_count;
3923			else if (atombios_uses_dual_link(path, pixel_clock_10khz))
3924				transmitter_lane_num = 8;
3925			else
3926				transmitter_lane_num = 4;
3927		}
3928	
3929		sym_clock_10khz = pixel_clock_10khz;
3930		if (path->encoder_mode == ATOM_ENCODER_MODE_DP && path->dp_link_bw)
3931			sym_clock_10khz = dp_link_bw_code_to_clock_10khz(path->dp_link_bw);
3932		else if (dual_link)
3933			sym_clock_10khz /= 2;
3934	
3935		printk(BIOS_DEBUG,
3936		       "ATOMBIOS: transmitter ctrl frev=%d crev=%d action=%d "
3937		       "phy=%d lanes=%d symclk=%d*10kHz\n",
3938		       frev, crev, action, path->phy_id, transmitter_lane_num,
3939		       sym_clock_10khz);
3940	
3941		switch (crev) {
3942		case 1:
3943			args.v1.ucAction = action;
3944			if (action == ATOM_TRANSMITTER_ACTION_SETUP_VSEMPH) {
3945				args.v1.asMode.ucLaneSel = transmitter_lane_num;
3946				args.v1.asMode.ucLaneSet = lane_set;
3947			} else if (action == ATOM_TRANSMITTER_ACTION_INIT) {
3948				args.v1.usInitInfo = atombios_object_id(path->connector_obj_id);
3949			} else {
3950				args.v1.usPixelClock = sym_clock_10khz;
3951			}
3952			args.v1.ucConfig = ATOM_TRANSMITTER_CONFIG_CLKSRC_PPLL;
3953			if (path->dig_encoder & 1)
3954				args.v1.ucConfig |= ATOM_TRANSMITTER_CONFIG_DIG2_ENCODER;
3955			if (path->phy_id & 1)
3956				args.v1.ucConfig |= ATOM_TRANSMITTER_CONFIG_LINKB;
3957			if (dual_link)
3958				args.v1.ucConfig |= ATOM_TRANSMITTER_CONFIG_8LANE_LINK;
3959			if (path->encoder_mode == ATOM_ENCODER_MODE_HDMI ||
3960			    path->encoder_mode == ATOM_ENCODER_MODE_DP)
3961				args.v1.ucConfig |= ATOM_TRANSMITTER_CONFIG_COHERENT;
3962			break;
3963		case 2:
3964			args.v2.ucAction = action;
3965			if (action == ATOM_TRANSMITTER_ACTION_SETUP_VSEMPH) {
3966				args.v2.asMode.ucLaneSel = transmitter_lane_num;
3967				args.v2.asMode.ucLaneSet = lane_set;
3968			} else if (action == ATOM_TRANSMITTER_ACTION_INIT) {
3969				args.v2.usInitInfo = atombios_object_id(path->connector_obj_id);
3970			} else {
3971				args.v2.usPixelClock = sym_clock_10khz;
3972			}
3973			args.v2.acConfig.ucEncoderSel = (path->dig_encoder & 1);
3974			args.v2.acConfig.ucLinkSel = path->phy_id & 1;
3975			args.v2.acConfig.ucTransmitterSel = path->phy_id / 2;
3976			args.v2.acConfig.fDualLinkConnector = dual_link;
3977			if (path->encoder_mode == ATOM_ENCODER_MODE_DP)
3978				args.v2.acConfig.fDPConnector = 1;
3979			if (path->encoder_mode == ATOM_ENCODER_MODE_HDMI ||
3980			    path->encoder_mode == ATOM_ENCODER_MODE_DP)
3981				args.v2.acConfig.fCoherentMode = 1;
3982			break;
3983		case 3:
3984			args.v3.ucAction = action;
3985			if (action == ATOM_TRANSMITTER_ACTION_SETUP_VSEMPH) {
3986				args.v3.asMode.ucLaneSel = transmitter_lane_num;
3987				args.v3.asMode.ucLaneSet = lane_set;
3988			} else if (action == ATOM_TRANSMITTER_ACTION_INIT) {
3989				args.v3.usInitInfo = atombios_object_id(path->connector_obj_id);
3990			} else {
3991				args.v3.usPixelClock = sym_clock_10khz;
3992			}
3993			args.v3.ucLaneNum = transmitter_lane_num;
3994			args.v3.acConfig.ucEncoderSel = (path->dig_encoder & 1);
3995			args.v3.acConfig.ucLinkSel = path->phy_id & 1;
3996			args.v3.acConfig.ucRefClkSource = path->tx_refclk;
3997			args.v3.acConfig.ucTransmitterSel = path->phy_id / 2;
3998			args.v3.acConfig.fDualLinkConnector = dual_link;
3999			if (path->encoder_mode == ATOM_ENCODER_MODE_HDMI ||
4000			    path->encoder_mode == ATOM_ENCODER_MODE_DP)
4001				args.v3.acConfig.fCoherentMode = 1;
4002			break;
4003		case 4:
4004			args.v4.ucAction = action;
4005			if (action == ATOM_TRANSMITTER_ACTION_SETUP_VSEMPH) {
4006				args.v4.asMode.ucLaneSel = transmitter_lane_num;
4007				args.v4.asMode.ucLaneSet = lane_set;
4008			} else if (action == ATOM_TRANSMITTER_ACTION_INIT) {
4009				args.v4.usInitInfo = atombios_object_id(path->connector_obj_id);
4010			} else {
4011				args.v4.usPixelClock = sym_clock_10khz;
4012			}
4013			args.v4.ucLaneNum = transmitter_lane_num;
4014			args.v4.acConfig.ucEncoderSel = (path->dig_encoder & 1);
4015			args.v4.acConfig.ucLinkSel = path->phy_id & 1;
4016			args.v4.acConfig.ucRefClkSource = path->tx_refclk;
4017			args.v4.acConfig.ucTransmitterSel = path->phy_id / 2;
4018			args.v4.acConfig.fDualLinkConnector = dual_link;
4019			if (path->encoder_mode == ATOM_ENCODER_MODE_HDMI ||
4020			    path->encoder_mode == ATOM_ENCODER_MODE_DP)
4021				args.v4.acConfig.fCoherentMode = 1;
4022			break;
4023		case 5:
4024			args.v5.ucAction = action;
4025			args.v5.usSymClock = sym_clock_10khz;
4026			args.v5.ucPhyId = path->phy_id;
4027			args.v5.ucLaneNum = transmitter_lane_num;
4028			args.v5.ucConnObjId = atombios_object_id(path->connector_obj_id);
4029			args.v5.ucDigMode = path->encoder_mode;
4030			args.v5.ucDigEncoderSel = (1 << path->dig_encoder);
4031			args.v5.ucDPLaneSet = lane_set;
4032			args.v5.asConfig.ucPhyClkSrcId = path->tx_refclk;
4033			if (path->hpd_id <= 5)
4034				args.v5.asConfig.ucHPDSel = path->hpd_id + 1;
4035			if (path->encoder_mode == ATOM_ENCODER_MODE_HDMI ||
4036			    path->encoder_mode == ATOM_ENCODER_MODE_DP)
4037				args.v5.asConfig.ucCoherentMode = 1;
4038			break;
4039		case 6:
4040		default:
4041			args.v6.param.ucAction = action;
4042			args.v6.param.ucPhyId = path->phy_id;
4043			if (action == ATOM_TRANSMITTER_ACTION_SETUP_VSEMPH)
4044				args.v6.param.ucDPLaneSet = lane_set;
4045			else
4046				args.v6.param.ucDigMode = path->encoder_mode;
4047			args.v6.param.ucLaneNum = transmitter_lane_num;
4048			args.v6.param.ulSymClock = sym_clock_10khz;
4049			args.v6.param.ucConnObjId = atombios_object_id(path->connector_obj_id);
4050			/* DCN connects DIG front ends directly; AtomFirmware expects no FE here. */
4051			args.v6.param.ucDigEncoderSel = cmd_idx.is_v2 ? 0 : (1 << path->dig_encoder);
4052			if (path->hpd_id <= 5)
4053				args.v6.param.ucHPDSel = path->hpd_id + 1;
4054			break;
4055		}
4056	
4057		return atom_execute_table(ctx, cmd_idx.dig1_xmtr_ctrl,
4058					  (uint32_t *)&args,
4059					  sizeof(args));
4060	}
