4063	
4064	/*
4065	 * Route a CRTC to an encoder via the SelectCRTC_Source ATOM table.
4066	 */
4067	static int atombios_select_crtc_source(struct atom_context *ctx,
4068					       const struct atombios_display_path *path,
4069					       int crtc_id)
4070	{
4071		uint8_t frev, crev;
4072		union {
4073			SELECT_CRTC_SOURCE_PARAMETERS    v1;
4074			SELECT_CRTC_SOURCE_PARAMETERS_V2 v2;
4075			SELECT_CRTC_SOURCE_PARAMETERS_V3 v3;
4076		} args;
4077		uint8_t enc_id = ASIC_INT_DIG1_ENCODER_ID;
4078		int dev_index;
4079	
4080		if (!atom_parse_cmd_header(ctx, cmd_idx.select_crtc_source,
4081					   &frev, &crev))
4082			return -1;
4083	
4084		memset(&args, 0, sizeof(args));
4085	
4086		/* Map encoder to the hardware encoder ID. Legacy TMDS paths use
4087		 * SelectCRTC_Source v1 on the hardware this driver currently targets. */
4088		if (path->is_dac) {
4089			enc_id = (path->dac_type == ATOM_DAC_A)
4090				 ? ASIC_INT_DAC1_ENCODER_ID
4091				 : ASIC_INT_DAC2_ENCODER_ID;
4092		} else if (path->is_legacy_tmds) {
4093			enc_id = ASIC_INT_DIG1_ENCODER_ID;
4094		} else {
4095			switch (path->dig_encoder) {
4096			case 0: enc_id = ASIC_INT_DIG1_ENCODER_ID; break;
4097			case 1: enc_id = ASIC_INT_DIG2_ENCODER_ID; break;
4098			case 2: enc_id = ASIC_INT_DIG3_ENCODER_ID; break;
4099			case 3: enc_id = ASIC_INT_DIG4_ENCODER_ID; break;
4100			case 4: enc_id = ASIC_INT_DIG5_ENCODER_ID; break;
4101			case 5: enc_id = ASIC_INT_DIG6_ENCODER_ID; break;
4102			default: enc_id = ASIC_INT_DIG7_ENCODER_ID; break;
4103			}
4104		}
4105	
4106		dev_index = atombios_device_tag_index(path->device_tag);
4107	
4108		switch (crev) {
4109		case 1:
4110			args.v1.ucCRTC = crtc_id;
4111			if (dev_index >= 0)
4112				args.v1.ucDevice = dev_index;
4113			else if (path->is_dac)
4114				args.v1.ucDevice = (path->dac_type == ATOM_DAC_A)
4115						   ? ATOM_DEVICE_CRT1_INDEX
4116						   : ATOM_DEVICE_CRT2_INDEX;
4117			else
4118				args.v1.ucDevice = ATOM_DEVICE_DFP1_INDEX;
4119			break;
4120		case 2:
4121			args.v2.ucCRTC = crtc_id;
4122			args.v2.ucEncoderID = enc_id;
4123			args.v2.ucEncodeMode = path->encoder_mode;
4124			break;
4125		case 3:
4126		default:
4127			args.v3.ucCRTC = crtc_id;
4128			args.v3.ucEncoderID = enc_id;
4129			args.v3.ucEncodeMode = path->encoder_mode;
4130			args.v3.ucDstBpc = PANEL_8BIT_PER_COLOR;
4131			break;
4132		}
4133	
4134		printk(BIOS_DEBUG,
4135		       "ATOMBIOS: select CRTC %d -> enc_id=0x%02x mode=%d%s\n",
4136		       crtc_id, enc_id, path->encoder_mode,
4137		       path->is_dac ? " (DAC)" : "");
4138	
4139		return atom_execute_table(ctx, cmd_idx.select_crtc_source,
4140					  (uint32_t *)&args,
4141					  sizeof(args));
4142	}
