4390	static void atomfirmware_log_registers(struct atom_context *ctx,
4391					       enum atomfirmware_display_ip ip)
4392	{
4393		/* DCE12 register indices from Linux dce_12_0_offset.h plus the Vega10
4394		 * SOC15 DCE segment-2 base. Reads are diagnostic only. */
4395		static const struct {
4396			const char *name;
4397			uint32_t offset;
4398		} regs[] = {
4399			{ "DCP0_GRPH_ENABLE", 0x3a1a * 4 },
4400			{ "DCP0_GRPH_CONTROL", 0x3a1b * 4 },
4401			{ "DCP0_GRPH_PRIMARY_SURFACE_ADDRESS", 0x3a1e * 4 },
4402			{ "DCP0_GRPH_PITCH", 0x3a20 * 4 },
4403			{ "SCL0_VIEWPORT_START", 0x3b6f * 4 },
4404			{ "SCL0_VIEWPORT_SIZE", 0x3b70 * 4 },
4405			{ "CRTC0_CRTC_H_TOTAL", 0x3b93 * 4 },
4406			{ "CRTC0_CRTC_V_TOTAL", 0x3b9a * 4 },
4407			{ "CRTC0_CRTC_CONTROL", 0x3baf * 4 },
4408			{ "CRTC0_CRTC_BLANK_CONTROL", 0x3bb0 * 4 },
4409		};
4410		unsigned int i;
4411	
4412		if (ip != ATOMFIRMWARE_DCE12 || !ctx->card->mmio_base)
4413			return;
4414	
4415		for (i = 0; i < ARRAY_SIZE(regs); i++)
4416			printk(BIOS_INFO, "ATOMBIOS: %s[0x%05x] = 0x%08x\n",
4417			       regs[i].name, regs[i].offset,
4418			       atombios_mmio_read(ctx, regs[i].offset));
4419	}
