4421	static void atomfirmware_diagnostics(struct atom_context *ctx, size_t bios_size,
4422					     uint16_t device_id)
4423	{
4424		enum atomfirmware_display_ip ip = atomfirmware_display_ip(device_id);
4425		const void *table;
4426		size_t table_size;
4427		struct atom_v2_display_info display;
4428		struct atom_v2_firmware_info firmware;
4429		struct atom_v2_dce_info dce;
4430		unsigned int i;
4431	
4432		printk(BIOS_INFO, "ATOMBIOS: AtomFirmware v2, display IP %s\n",
4433		       atomfirmware_display_ip_name(ip));
4434	
4435		atomfirmware_log_command_revision(ctx, bios_size, "ASIC_Init", cmd_idx.asic_init);
4436		atomfirmware_log_command_revision(ctx, bios_size, "DIGxEncoderControl",
4437						  cmd_idx.dig_encoder_ctrl);
4438		atomfirmware_log_command_revision(ctx, bios_size, "DIG1TransmitterControl",
4439						  cmd_idx.dig1_xmtr_ctrl);
4440		atomfirmware_log_command_revision(ctx, bios_size, "SetPixelClock",
4441						  cmd_idx.set_pixel_clock);
4442		atomfirmware_log_command_revision(ctx, bios_size, "SetCRTC_UsingDTDTiming",
4443						  cmd_idx.set_crtc_using_dtd);
4444		atomfirmware_log_command_revision(ctx, bios_size, "SelectCRTC_Source",
4445						  cmd_idx.select_crtc_source);
4446		atomfirmware_log_command_revision(ctx, bios_size, "BlankCRTC", cmd_idx.blank_crtc);
4447		atomfirmware_log_command_revision(ctx, bios_size, "EnableCRTC", cmd_idx.enable_crtc);
4448		atomfirmware_log_command_revision(ctx, bios_size, "EnableDispPowerGating",
4449						  cmd_idx.enable_disp_power_gating);
4450		atomfirmware_log_command_revision(ctx, bios_size, "ProcessI2cChannelTransaction",
4451						  cmd_idx.process_i2c);
4452		atomfirmware_log_command_revision(ctx, bios_size, "ProcessAuxChannelTransaction",
4453						  cmd_idx.process_aux);
4454	
4455		if (!atom_v2_get_table(ctx->bios, bios_size, ctx->data_table,
4456				       cmd_idx.data_object_header, &table, &table_size) &&
4457		    !atom_v2_parse_display_object_info(table, table_size, &display)) {
4458			printk(BIOS_INFO,
4459			       "ATOMBIOS: DisplayObjectInfo %u.%u paths=%u supported=0x%04x\n",
4460			       display.format_revision, display.content_revision,
4461			       display.path_count, display.supported_devices);
4462			for (i = 0; i < display.path_count; i++) {
4463				const struct atom_v2_display_path *path = &display.paths[i];
4464	
4465				printk(BIOS_INFO,
4466				       "ATOMBIOS: v2 path %u: conn=0x%04x enc=0x%04x ext=0x%04x "
4467				       "tag=0x%04x dig=%u phy=%u i2c=%s0x%02x hpd=%s0x%02x caps=%s0x%08x\n",
4468				       i, path->display_objid, path->encoder_objid,
4469				       path->ext_encoder_objid, path->device_tag,
4470				       path->dig_encoder, path->phy_id,
4471				       path->i2c_valid ? "" : "n/a ", path->i2c_id,
4472				       path->hpd_valid ? "" : "n/a ", path->hpd_pin,
4473				       path->encoder_caps_valid ? "" : "n/a ", path->encoder_caps);
4474			}
4475		} else {
4476			printk(BIOS_WARNING, "ATOMBIOS: malformed or unsupported DisplayObjectInfo\n");
4477		}
4478	
4479		if (!atom_v2_get_table(ctx->bios, bios_size, ctx->data_table,
4480				       cmd_idx.data_firmware_info, &table, &table_size) &&
4481		    !atom_v2_parse_firmware_info(table, table_size, &firmware))
4482			printk(BIOS_INFO,
4483			       "ATOMBIOS: FirmwareInfo %u.%u fw=0x%08x sclk=%u mclk=%u "
4484			       "scratch=0x%08x mc=0x%016llx caps=0x%08x\n",
4485			       firmware.format_revision, firmware.content_revision,
4486			       firmware.firmware_revision, firmware.boot_sclk_10khz,
4487			       firmware.boot_mclk_10khz, firmware.scratch_reg_start,
4488			       (unsigned long long)firmware.mc_base, firmware.firmware_capability);
4489		else
4490			printk(BIOS_WARNING, "ATOMBIOS: malformed or unsupported FirmwareInfo\n");
4491	
4492		if (!atom_v2_get_table(ctx->bios, bios_size, ctx->data_table,
4493				       cmd_idx.data_dce_info, &table, &table_size) &&
4494		    !atom_v2_parse_dce_info(table, table_size, &dce))
4495			printk(BIOS_INFO,
4496			       "ATOMBIOS: DCE_Info %u.%u dispclk=%u refclk=%u dpphy=%u i2c=%u "
4497			       "ip=%u-%u pipes=%u vbios_pipes=%u pplls=%u phys=%u aux=%u caps=0x%08x\n",
4498			       dce.format_revision, dce.content_revision, dce.boot_dispclk_10khz,
4499			       dce.dce_refclk_10khz, dce.dpphy_refclk_10khz,
4500			       dce.i2c_refclk_10khz, dce.min_version, dce.max_version,
4501			       dce.max_pipes, dce.max_vbios_pipes, dce.max_pplls,
4502			       dce.max_phys, dce.max_aux_pairs, dce.display_caps);
4503		else
4504			printk(BIOS_WARNING, "ATOMBIOS: malformed or unsupported DCE_Info\n");
4505	
4506		atomfirmware_log_registers(ctx, ip);
4507	}
