4530	static int atomfirmware_power_edp(struct atom_context *ctx)
4531	{
4532		struct atombios_display_path path = {
4533			.connector_type = 2,
4534			.hpd_id = 0,
4535			.dig_encoder = 0,
4536			.phy_id = 0,
4537			.encoder_mode = ATOM_ENCODER_MODE_DP,
4538			.dp_lane_count = 4,
4539			.connector_obj_id = CONNECTOR_OBJECT_ID_eDP,
4540		};
4541	
4542		/* eDP T12 requires at least 500 ms between panel power cycles. */
4543		mdelay(500);
4544		if (atombios_transmitter_control(ctx, &path, 0,
4545						 ATOM_TRANSMITTER_ACTION_POWER_ON, 4, 0))
4546			return -1;
4547		mdelay(10);
4548		printk(BIOS_INFO,
4549		       "ATOMBIOS: DCN1 eDP power sequence cntl=0x%08x state=0x%08x\n",
4550		       atombios_mmio_read(ctx, DCN10_LVTMA_PWRSEQ_CNTL),
4551		       atombios_mmio_read(ctx, DCN10_LVTMA_PWRSEQ_STATE));
4552		return 0;
4553	}
