4590			.tx_refclk = ATOM_COMBOPHY_PLL0 + v2_path->phy_id,
4591			.connector_obj_id = CONNECTOR_OBJECT_ID_eDP,
4592			.device_tag = v2_path->device_tag,
4593		};
