4284	static resource_t atombios_get_bar(struct device *dev, unsigned int bar)
4285	{
4286		struct resource *res = probe_resource(dev, bar);
4287		uint32_t lo;
4288		resource_t base;
4289	
4290		if (res && res->base)
4291			return res->base;
4292	
4293		lo = pci_read_config32(dev, bar);
4294		if (lo == 0xffffffff)
4295			return 0;
4296		base = lo & ~0xfu;
4297		if ((lo & PCI_BASE_ADDRESS_MEM_LIMIT_MASK) == PCI_BASE_ADDRESS_MEM_LIMIT_64)
4298			base |= (resource_t)pci_read_config32(dev, bar + 4) << 32;
4299	
4300		return base;
4301	}
