4509	static int atomfirmware_asic_init(struct atom_context *ctx,
4510					  const struct atom_v2_firmware_info *fw)
4511	{
4512		uint32_t params[18] = { 0 };
4513		uint8_t format_revision;
4514		uint8_t content_revision;
4515	
4516		if (!atom_parse_cmd_header(ctx, cmd_idx.asic_init, &format_revision,
4517					   &content_revision) ||
4518		    format_revision != 2 || content_revision < 1)
4519			return -1;
4520	
4521		params[0] = fw->boot_sclk_10khz & 0x00ffffff;
4522		params[1] = (fw->boot_mclk_10khz & 0x00ffffff) | (0x20 << 24);
4523	
4524		return atom_execute_table(ctx, cmd_idx.asic_init, params, sizeof(params));
4525	}
