    10	#define ATOM_V2_DISPLAY_INFO_FIXED_SIZE 8
    11	#define ATOM_V2_MAX_RECORDS 256
    12	#define ATOM_ROM_HEADER_POINTER 0x48
    13	#define ATOM_ROM_HEADER_MIN_SIZE 0x22
    14	#define ATOM_ROM_COMMAND_TABLE_OFFSET 0x1e
    15	#define ATOM_ROM_DATA_TABLE_OFFSET 0x20
    16	
    17	_Static_assert(sizeof(struct atom_display_object_path_v2) == 16, "bad v2 path ABI");
    18	_Static_assert(sizeof(struct atom_display_object_path_v3) == 16, "bad v3 path ABI");
