    13	#define ATOM_ROM_HEADER_MIN_SIZE 0x22
    14	#define ATOM_ROM_COMMAND_TABLE_OFFSET 0x1e
    15	#define ATOM_ROM_DATA_TABLE_OFFSET 0x20
