    21	static uint16_t get_le16(const uint8_t *p)
    22	{
    23		return p[0] | ((uint16_t)p[1] << 8);
    24	}
    25	
    26	static uint32_t get_le32(const uint8_t *p)
    27	{
    28		return get_le16(p) | ((uint32_t)get_le16(p + 2) << 16);
    29	}
