    31	static bool range_valid(size_t offset, size_t length, size_t size)
    32	{
    33		return offset <= size && length <= size - offset;
    34	}
    35	
    36	int atom_v2_parse_rom_header(const void *bios, size_t bios_size,
    37				     struct atom_v2_rom_info *info)
    38	{
    39		const uint8_t *image = bios;
    40		uint16_t header_offset;
    41		uint16_t header_size;
    42		uint16_t command_offset;
    43		uint16_t data_offset;
    44	
    45		if (!image || !info || !range_valid(0, ATOM_ROM_HEADER_POINTER + 2, bios_size) ||
    46		    get_le16(image) != 0xaa55)
    47			return -1;
    48	
    49		header_offset = get_le16(image + ATOM_ROM_HEADER_POINTER);
    50		if (!range_valid(header_offset, ATOM_ROM_HEADER_MIN_SIZE, bios_size) ||
    51		    memcmp(image + header_offset + 4, "ATOM", 4))
    52			return -1;
    53	
    54		header_size = get_le16(image + header_offset);
    55		if (header_size < ATOM_ROM_HEADER_MIN_SIZE ||
    56		    !range_valid(header_offset, header_size, bios_size) ||
    57		    image[header_offset + 2] < 2)
    58			return -1;
    59	
    60		command_offset = get_le16(image + header_offset + ATOM_ROM_COMMAND_TABLE_OFFSET);
    61		data_offset = get_le16(image + header_offset + ATOM_ROM_DATA_TABLE_OFFSET);
    62		if (!command_offset || !data_offset || !range_valid(command_offset, 4, bios_size) ||
    63		    !range_valid(data_offset, 4, bios_size) || image[command_offset + 2] < 2 ||
    64		    image[data_offset + 2] < 2)
    65			return -1;
    66	
    67		info->command_table_offset = command_offset;
    68		info->data_table_offset = data_offset;
    69		return 0;
    70	}
