    72	int atom_v2_get_table(const void *bios, size_t bios_size,
    73			      size_t master_table_offset, size_t index,
    74			      const void **table, size_t *table_size)
    75	{
    76		const uint8_t *image = bios;
    77		size_t entry_offset;
    78		uint16_t master_size;
    79		uint16_t target_offset;
    80		uint16_t target_size;
    81	
    82		if (!bios || !table || !table_size ||
    83		    !range_valid(master_table_offset, 4, bios_size))
    84			return -1;
    85	
    86		master_size = get_le16(image + master_table_offset);
    87		if (index > (SIZE_MAX - 4) / sizeof(uint16_t))
    88			return -1;
    89		entry_offset = 4 + index * sizeof(uint16_t);
    90		if (master_size < 4 || !range_valid(master_table_offset, master_size, bios_size) ||
    91		    !range_valid(entry_offset, sizeof(uint16_t), master_size))
    92			return -1;
    93	
    94		target_offset = get_le16(image + master_table_offset + entry_offset);
    95		if (!target_offset || !range_valid(target_offset, 4, bios_size))
    96			return -1;
    97	
    98		target_size = get_le16(image + target_offset);
    99		if (target_size < 4 || !range_valid(target_offset, target_size, bios_size))
   100			return -1;
   101	
   102		*table = image + target_offset;
   103		*table_size = target_size;
   104		return 0;
   105	}
   106	
   107	static int parse_records(const uint8_t *table, size_t table_size, size_t records_start,
   108				 uint16_t offset, struct atom_v2_display_path *path)
   109	{
   110		unsigned int i;
   111	
   112		if (!offset)
   113			return 0;
   114		if (offset < records_start ||
   115		    !range_valid(offset, 1, table_size))
   116			return -1;
   117	
   118		for (i = 0; i < ATOM_V2_MAX_RECORDS; i++) {
   119			uint8_t type = table[offset];
   120			uint8_t size;
   121	
   122			if (type == ATOM_V2_RECORD_END_TYPE)
   123				return 0;
   124			if (!range_valid(offset, sizeof(struct atom_v2_common_record_header),
   125					 table_size))
   126				return -1;
   127			size = table[offset + 1];
   128			if (size < sizeof(struct atom_v2_common_record_header) ||
   129			    !range_valid(offset, size, table_size))
   130				return -1;
   131	
   132			switch (type) {
   133			case ATOM_V2_I2C_RECORD_TYPE:
   134				if (size < sizeof(struct atom_v2_i2c_record))
   135					return -1;
   136				if (!path->i2c_valid) {
   137					path->i2c_id = table[offset + 2];
   138					path->i2c_slave_addr = table[offset + 3];
   139					path->i2c_valid = true;
   140				}
   141				break;
   142			case ATOM_V2_HPD_INT_RECORD_TYPE:
   143				if (size < sizeof(struct atom_v2_hpd_int_record))
   144					return -1;
   145				if (!path->hpd_valid) {
   146					path->hpd_pin = table[offset + 2];
   147					path->hpd_active = table[offset + 3];
   148					path->hpd_valid = true;
   149				}
   150				break;
   151			case ATOM_V2_ENCODER_CAP_RECORD_TYPE:
   152				if (size < sizeof(struct atom_v2_encoder_caps_record))
   153					return -1;
   154				if (!path->encoder_caps_valid) {
   155					path->encoder_caps = get_le32(table + offset + 2);
   156					path->encoder_caps_valid = true;
   157				}
   158				break;
   159			}
   160	
   161			offset += size;
   162			if (!range_valid(offset, 1, table_size))
   163				return -1;
   164		}
   165	
   166		return -1;
   167	}
   168	
   169	static void decode_encoder(uint16_t encoder_objid, struct atom_v2_display_path *path)
   170	{
   171		uint8_t id = (encoder_objid & OBJECT_ID_MASK) >> OBJECT_ID_SHIFT;
   172		uint8_t enum_id = (encoder_objid & ENUM_ID_MASK) >> ENUM_ID_SHIFT;
   173		uint8_t base;
   174	
   175		switch (id) {
   176		case ENCODER_OBJECT_ID_INTERNAL_UNIPHY:
   177			base = 0;
   178			break;
   179		case ENCODER_OBJECT_ID_INTERNAL_UNIPHY1:
   180			base = 2;
   181			break;
   182		case ENCODER_OBJECT_ID_INTERNAL_UNIPHY2:
   183			base = 4;
   184			break;
   185		case ENCODER_OBJECT_ID_INTERNAL_UNIPHY3:
   186			base = 6;
   187			break;
   188		default:
   189			return;
   190		}
   191	
   192		if (enum_id == GRAPH_OBJECT_ENUM_ID2)
   193			base++;
   194		path->dig_encoder = base;
   195		path->phy_id = base;
   196	}
   197	
   198	int atom_v2_parse_display_object_info(const void *table_data, size_t table_size,
   199					      struct atom_v2_display_info *info)
   200	{
   201		const uint8_t *table = table_data;
   202		uint16_t structure_size;
   203		size_t path_size;
   204		size_t paths_size;
   205		unsigned int i;
   206	
   207		if (!table || !info || table_size < ATOM_V2_DISPLAY_INFO_FIXED_SIZE)
   208			return -1;
   209	
   210		structure_size = get_le16(table);
   211		if (structure_size < ATOM_V2_DISPLAY_INFO_FIXED_SIZE ||
   212		    structure_size > table_size || table[2] != 1 ||
   213		    (table[3] != 4 && table[3] != 5))
   214			return -1;
   215	
   216		path_size = table[3] == 4 ? sizeof(struct atom_display_object_path_v2) :
   217					      sizeof(struct atom_display_object_path_v3);
   218		paths_size = (size_t)table[6] * path_size;
   219		if (table[6] > ATOM_V2_MAX_DISPLAY_PATHS ||
   220		    !range_valid(ATOM_V2_DISPLAY_INFO_FIXED_SIZE, paths_size, structure_size))
   221			return -1;
   222	
   223		memset(info, 0, sizeof(*info));
   224		info->supported_devices = get_le16(table + 4);
   225		info->format_revision = table[2];
   226		info->content_revision = table[3];
   227		info->path_count = table[6];
   228	
   229		for (i = 0; i < info->path_count; i++) {
   230			const uint8_t *raw = table + ATOM_V2_DISPLAY_INFO_FIXED_SIZE + i * path_size;
   231			struct atom_v2_display_path *path = &info->paths[i];
   232			uint16_t display_record_offset = get_le16(raw + 2);
   233			uint16_t encoder_record_offset = 0;
   234			uint16_t ext_encoder_record_offset = 0;
   235	
   236			path->hpd_pin = ATOM_V2_ID_NONE;
   237			path->dig_encoder = ATOM_V2_ID_NONE;
   238			path->phy_id = ATOM_V2_ID_NONE;
   239			path->display_objid = get_le16(raw);
   240			path->encoder_objid = get_le16(raw + 4);
   241			if (table[3] == 4) {
   242				path->ext_encoder_objid = get_le16(raw + 6);
   243				encoder_record_offset = get_le16(raw + 8);
   244				ext_encoder_record_offset = get_le16(raw + 10);
   245				path->device_tag = get_le16(raw + 12);
   246				path->priority_id = raw[14];
   247			} else {
   248				path->device_tag = get_le16(raw + 12);
   249			}
   250	
   251			decode_encoder(path->encoder_objid, path);
   252			if (parse_records(table, structure_size,
   253					  ATOM_V2_DISPLAY_INFO_FIXED_SIZE + paths_size,
   254					  display_record_offset, path) ||
   255			    parse_records(table, structure_size,
   256					  ATOM_V2_DISPLAY_INFO_FIXED_SIZE + paths_size,
   257					  encoder_record_offset, path) ||
   258			    parse_records(table, structure_size,
   259					  ATOM_V2_DISPLAY_INFO_FIXED_SIZE + paths_size,
   260					  ext_encoder_record_offset, path))

