  9	#define DCN10_DEEP_SLEEP_DCFCLK_KHZ	8000
 10	#define DCN10_URGENT_LATENCY_US		4
 11	#define DCN10_PREFETCH_CALC_US		3
 12	
 13	static uint32_t div_round_up_u64(uint64_t value, uint32_t divisor)
 14	{
 15		return (value + divisor - 1) / divisor;
 16	}
 17	
 18	static uint32_t watermark_cycles(uint32_t ns, uint32_t ref_clock_khz)
 19	{
 20		uint64_t cycles = (uint64_t)ns * ref_clock_khz / 1000000;
 21	
 22		return cycles > 0x1fffff ? 0x1fffff : cycles;
 23	}
 24	
 25	int dcn10_calculate_plane(const struct dcn10_timing *timing,
 26				  uint32_t pitch_pixels,
 27				  struct dcn10_plane_regs *regs)
 28	{
 29		uint32_t h_total, v_total, h_blank_end, v_blank_start, v_blank_end;
 30		uint32_t vupdate_offset, vupdate_width, vready_dpp, vready_dcf;
 31		uint32_t vready, vstartup, delay_pixels, setup_pixels, wait_pixels;
 32		uint32_t prefetch_quarters, line_delivery, requests_per_line;
 33		uint64_t ratio, prefetch_num;
 34	
 35		if (!timing || !regs || !timing->h_active || !timing->v_active ||
 36		    timing->h_blank < 32 || timing->v_blank < 3 ||
 37		    timing->h_sync_width < 4 || !timing->v_sync_width ||
 38		    !timing->pixel_clock_khz || !timing->ref_clock_khz ||
 39		    !timing->disp_clock_khz || pitch_pixels < timing->h_active ||
 40		    (pitch_pixels & 63))
 41			return -1;
 42	
 43		h_total = timing->h_active + timing->h_blank;
 44		v_total = timing->v_active + timing->v_blank;
 45		if (h_total > 0x4000 || v_total > 0x4000 ||
 46		    timing->h_front_porch + timing->h_sync_width > timing->h_blank ||
 47		    timing->v_front_porch + timing->v_sync_width > timing->v_blank ||
 48		    (uint64_t)h_total * 1000 <
 49			(uint64_t)(DCN10_URGENT_LATENCY_US + DCN10_PREFETCH_CALC_US) *
 50			timing->pixel_clock_khz)
 51			return -1;
 52	
 53		h_blank_end = h_total - timing->h_front_porch - timing->h_active;
 54		v_blank_start = v_total - timing->v_front_porch;
 55		v_blank_end = v_blank_start - timing->v_active;
 56		vstartup = timing->v_blank > 13 ? 13 : timing->v_blank - 1;
 57		vupdate_offset = (h_total + 3) / 4;
 58		vupdate_width = div_round_up_u64(14ULL * timing->pixel_clock_khz,
 59						 DCN10_DEEP_SLEEP_DCFCLK_KHZ) +
 60			div_round_up_u64(12ULL * timing->pixel_clock_khz,
 61					 timing->disp_clock_khz);
 62		vready_dpp = div_round_up_u64(150ULL * timing->pixel_clock_khz,
 63					      timing->disp_clock_khz);
 64		vready_dcf = div_round_up_u64(20ULL * timing->pixel_clock_khz,
 65					      DCN10_DEEP_SLEEP_DCFCLK_KHZ) +
 66			div_round_up_u64(10ULL * timing->pixel_clock_khz,
 67					 timing->disp_clock_khz);
 68		vready = vready_dpp > vready_dcf ? vready_dpp : vready_dcf;
 69	
 70		ratio = ((uint64_t)timing->ref_clock_khz << 19) /
 71			timing->pixel_clock_khz;
 72		delay_pixels = (132ULL * timing->pixel_clock_khz) /
 73			timing->disp_clock_khz;
 74		setup_pixels = vupdate_offset + vupdate_width + vready + delay_pixels;
 75		wait_pixels = ((DCN10_URGENT_LATENCY_US + DCN10_PREFETCH_CALC_US) *
 76			       timing->pixel_clock_khz) / 1000;
 77		setup_pixels += wait_pixels;
 78		prefetch_num = ((uint64_t)((vstartup - 1) * 8 + 1) * h_total);
 79		if (prefetch_num <= 8ULL * setup_pixels)
 80			return -1;
 81		prefetch_quarters = (prefetch_num - 8ULL * setup_pixels) /
 82			(2ULL * h_total);
 83		if (prefetch_quarters < 8 || prefetch_quarters > 0xff)
 84			return -1;
 85	
 86		line_delivery = ((uint64_t)timing->ref_clock_khz *
 87				 timing->h_active) / timing->pixel_clock_khz;
 88		requests_per_line = (pitch_pixels * 4 + 255) / 256;
 89		if (!requests_per_line)
 90			return -1;
 91	
 92		memset(regs, 0, sizeof(*regs));
 93		regs->expansion_mode = 2 | (1U << 2) | (1U << 4) | (1U << 6);
 94		regs->request_size = (7U << 4) | (3U << 8) | (3U << 11) |
 95			(1U << 16) | (3U << 18) | (5U << 20) | (5U << 24);
 96		regs->blank_offset_0 = ((ratio * h_blank_end) >> 19) |
 97			(v_blank_end << 16);
 98		regs->blank_offset_1 = v_blank_start * 4 +
 99			((uint64_t)(DCN10_URGENT_LATENCY_US + DCN10_PREFETCH_CALC_US) *
100			 timing->pixel_clock_khz * 4 / (1000ULL * h_total));
101		regs->dst_dimensions = (ratio * h_total * 256) >> 19;
102		regs->dst_after_scaler = (ratio * delay_pixels) >> 19;
103		regs->ref_freq_to_pix_freq = ratio;
104		regs->prefetch_settings = (prefetch_quarters << 24) | (1U << 19);
105		/* No VM/DCC: Linux DML reserves 1/4 line for VM and 3/4 for row fetch. */
106		regs->vblank_parameters_0 = 1U | (3U << 8);
107		regs->per_line_delivery_pre = line_delivery;
108		regs->per_line_delivery = line_delivery;
109		regs->ttu_qos_wm = (((uint64_t)4 * h_total * timing->ref_clock_khz /
110				      timing->pixel_clock_khz) & 0x3fff) << 16;
111		regs->surf0_ttu_cntl0 = (((uint64_t)line_delivery << 10) /
112					 requests_per_line) | (8U << 24);
113		regs->surf0_ttu_cntl1 = regs->surf0_ttu_cntl0 & 0x00ffffff;
114		regs->global_ttu_cntl =
115			((DCN10_URGENT_LATENCY_US + DCN10_PREFETCH_CALC_US) *
116			 timing->ref_clock_khz / 1000) | (14U << 28);
117		regs->vstartup = vstartup;
118		regs->vupdate = vupdate_offset | (vupdate_width << 16);
119		regs->vready = vready;
120		regs->watermark_urgent = watermark_cycles(4000, timing->ref_clock_khz);
121		regs->watermark_pte_meta = regs->watermark_urgent;
122		regs->watermark_sr_enter = watermark_cycles(19000, timing->ref_clock_khz);
123		regs->watermark_sr_exit = watermark_cycles(17000, timing->ref_clock_khz);
124		regs->watermark_pstate = watermark_cycles(21000, timing->ref_clock_khz);
125		regs->arb_sat_level = 60 * (timing->ref_clock_khz / 1000);
126		return 0;
127	}
