    52	static size_t find_write(size_t start, uint32_t reg, uint32_t set, uint32_t clear)
    53	{
    54		size_t i;
    55	
    56		for (i = start; i < mmio_trace_count; i++) {
    57			if (mmio_trace[i].reg == reg &&
    58			    (mmio_trace[i].value & set) == set &&
    59			    !(mmio_trace[i].value & clear))
    60				return i;
    61		}
    62		return mmio_trace_count;
    63	}
