    65	static void assert_commit_write_order(void)
    66	{
    67		size_t high, low, hubp, unlock, unblank;
    68	
    69		high = find_write(0, DCSURF_ADDRESS_HIGH, 0xf4, 0);
    70		low = find_write(high + 1, DCSURF_ADDRESS, 0, ~0U);
    71		hubp = find_write(low + 1, DCHUBP_CNTL, 0,
    72				  HUBP_COMMIT_DISABLE_MASK);
    73		unlock = find_write(hubp + 1, OTG_LOCK, 0, 1);
    74		unblank = find_write(unlock + 1, OTG_BLANK, 0, 0x00010100);
    75		assert_true(high < low);
    76		assert_true(low < hubp);
    77		assert_true(hubp < unlock);
    78		assert_true(unlock < unblank);
    79		assert_true(unblank < mmio_trace_count);
    80	}
