    87	void udelay(unsigned int usecs)
    88	{
    89		uint32_t hubp;
    90	
    91		(void)usecs;
    92		if (!fake_mmio)
    93			return;
    94		if ((*fake_reg(INPUT_CLOCK) & 3) == 3)
    95			*fake_reg(INPUT_CLOCK) |= 1U << 2;
    96		if ((*fake_reg(OTG_CLOCK) & 3) == 3)
    97			*fake_reg(OTG_CLOCK) |= 1U << 8;
    98		if (*fake_reg(OTG_CONTROL) & 1) {
    99			*fake_reg(OTG_CONTROL) |= 1U << 16;
   100			(*fake_reg(OTG_FRAME_COUNT))++;
   101		}
   102		if (*fake_reg(OTG_LOCK) & 1)
   103			*fake_reg(OTG_LOCK) |= 1U << 8;
   104		else
   105			*fake_reg(OTG_LOCK) &= ~(1U << 8);
   106		hubp = *fake_reg(DCHUBP_CNTL) | (1U << 1);
   107		if (hubp & 1) {
   108			hubp |= 1U << 3;
   109		} else {
   110			hubp &= ~(1U << 3);
   111			*fake_reg(DCSURF_EARLIEST) = *fake_reg(DCSURF_ADDRESS);
   112			*fake_reg(DCSURF_EARLIEST_HIGH) = *fake_reg(DCSURF_ADDRESS_HIGH);
   113		}
   114		*fake_reg(DCHUBP_CNTL) = hubp;
   115	}
