   171		invalid.h_front_porch = invalid.h_blank;
   172		assert_int_equal(dcn10_calculate_plane(&invalid, 1408, &regs), -1);
   173		invalid = vilboz_mode;
   174		invalid.pixel_clock_khz = 1000000;
   175		assert_int_equal(dcn10_calculate_plane(&invalid, 1408, &regs), -1);
   176	}
   177	
   178	static void test_local_framebuffer_bounds(void **state)
   179	{
   180		(void)state;
   181		assert_true(dcn10_surface_in_local_fb(0x000000f400000000ULL,
   182						       4325376, 0xf400, 0xf4ff));
   183		assert_false(dcn10_surface_in_local_fb(0xe0000000, 4325376,
   184							0xf400, 0xf4ff));
   185		assert_false(dcn10_surface_in_local_fb(0x000000f4fff00000ULL,
   186							4325376, 0xf400, 0xf4ff));
   187	}
   188	
   189	static void test_native_sequence_and_fail_closed(void **state)
   190	{
   191		uint8_t *framebuffer;
   192		uint32_t pitch;
   193	
   194		(void)state;
   195		fake_mmio = calloc(1, 0x20000);
   196		framebuffer = malloc(1408 * 4 * 768);
   197		assert_non_null(fake_mmio);
   198		assert_non_null(framebuffer);
   199		*fake_reg(FB_BASE) = 0xf400;
   200		*fake_reg(FB_TOP) = 0xf4ff;
   201		*fake_reg(MPCC0_STATUS) = 1;
   202	
   203		assert_int_equal(dcn10_cold_init(fake_mmio, 4), 0);
   204		assert_int_equal(dcn10_program_stream(fake_mmio, &vilboz_mode), 0);
   205		mmio_trace_count = 0;
   206		assert_int_equal(dcn10_program_scanout(fake_mmio, 0x000000f400000000ULL,
   207							 framebuffer, 1408 * 4 * 768,
   208							 &vilboz_mode, &pitch), 0);
   209		assert_int_equal(pitch, 1408 * 4);
   210		assert_int_equal(*fake_reg(DCSURF_ADDRESS_HIGH), 0xf4);
   211		assert_int_equal(*fake_reg(DCSURF_ADDRESS), 0);
   212		assert_false(*fake_reg(DCHUBP_CNTL) & ((1U << 0) | (1U << 2) | (1U << 3)));
   213		assert_int_equal(*fake_reg(VBLANK_PARAMETERS_0), 0x301);
   214		assert_int_equal(*fake_reg(BNS_VALUES_R), 0x20000000);
   215		assert_int_equal(*fake_reg(HDR_MULT_COEF), 0x1f000);
   216		assert_int_equal(*fake_reg(LB_DATA_FORMAT), 0x1003);
   217		assert_int_equal(*fake_reg(LB_MEMORY_CONTROL), 0x3f01);
   218		assert_int_equal(*fake_reg(SCL_MODE) & 7, 0);
   219		assert_int_equal(*fake_reg(SEC_VIEWPORT_DIMENSION),
   220				 ((uint32_t)vilboz_mode.v_active << 16) |
   221				 vilboz_mode.h_active);
   222		assert_true(find_write(0, VM_TLB_CONTROL, 0, ~0U) < mmio_trace_count);
   223		assert_commit_write_order();
   224	
   225		/* An address outside the ASIC_Init local aperture fails before MMIO commit. */
   226		assert_int_equal(dcn10_program_scanout(fake_mmio, 0x000000e000000000ULL,
   227							 framebuffer, 1408 * 4 * 768,
   228							 &vilboz_mode, &pitch), -1);
   229		free(framebuffer);
   230		free(fake_mmio);
   231		fake_mmio = NULL;
   232	}
   233	
   234	int main(void)
   235	{
   236		const struct CMUnitTest tests[] = {
   237			cmocka_unit_test(test_vilboz_plane_calculation),
   238			cmocka_unit_test(test_rejects_unsupported_plane),
   239			cmocka_unit_test(test_local_framebuffer_bounds),
   240			cmocka_unit_test(test_native_sequence_and_fail_closed),
   241		};
   242	
   243		return cmocka_run_group_tests_name("dcn10-test", tests, NULL, NULL);
   244	}

