     9	
    10	#define DCN_REG(reg) (((0x34c0 + (reg)) * 4))
    11	#define DCHUBP_CNTL 0x0566
    12	#define DCSURF_ADDRESS 0x057d
    13	#define DCSURF_ADDRESS_HIGH 0x057e
    14	#define VM_TLB_CONTROL 0x05b5
    15	#define DCSURF_EARLIEST 0x0597
    16	#define VBLANK_PARAMETERS_0 0x05bc
    17	#define SEC_VIEWPORT_DIMENSION 0x0561
    18	#define LB_DATA_FORMAT 0x0c7d
    19	#define LB_MEMORY_CONTROL 0x0c7e
    20	#define BNS_VALUES_R 0x0cbe
    21	#define HDR_MULT_COEF 0x0d2b
    22	#define SCL_MODE 0x0c64
    23	#define DCSURF_EARLIEST_HIGH 0x0598
    24	#define FB_BASE 0x0493
    25	#define FB_TOP 0x0494
    26	#define MPCC0_STATUS 0x1634
    27	#define INPUT_CLOCK 0x1acd
    28	#define OTG_CONTROL 0x1b41
    29	#define OTG_FRAME_COUNT 0x1b4c
    30	#define OTG_CLOCK 0x1b88
    31	#define OTG_LOCK 0x1b8d
    32	#define OTG_BLANK 0x1b42
    33	#define HUBP_COMMIT_DISABLE_MASK ((1U << 0) | (1U << 2) | (1U << 12))
    34	
    35	struct mmio_write {
    36		uint32_t reg;
    37		uint32_t value;
    38	};
    39	
    40	#define MMIO_TRACE_CAPACITY 256
    41	
    42	static uint8_t *fake_mmio;
    43	static struct mmio_write mmio_trace[MMIO_TRACE_CAPACITY];
    44	static size_t mmio_trace_count;
    45	
    46	void dcn10_test_mmio_write(uint32_t reg, uint32_t value)
    47	{
    48		assert_true(mmio_trace_count < MMIO_TRACE_CAPACITY);
    49		mmio_trace[mmio_trace_count++] = (struct mmio_write){ reg, value };
    50	}
    51	
    52	static size_t find_write(size_t start, uint32_t reg, uint32_t set, uint32_t clear)
    53	{
    54		size_t i;
    55	
    56		for (i = start; i < mmio_trace_count; i++) {
    57			if (mmio_trace[i].reg == reg &&
    58			    (mmio_trace[i].value & set) == set &&
    59			    !(mmio_trace[i].value & clear))
    60				return i;
    61		}
    62		return mmio_trace_count;
    63	}
    64	
    65	static void assert_commit_write_order(void)
    66	{
    67		size_t high, low, hubp, unlock, unblank;
    68	
    69		high = find_write(0, DCSURF_ADDRESS_HIGH, 0xf4, 0);
    70		low = find_write(high + 1, DCSURF_ADDRESS, 0, ~0U);
    71		hubp = find_write(low + 1, DCHUBP_CNTL, 0,
    72				  HUBP_COMMIT_DISABLE_MASK);
    73		unlock = find_write(hubp + 1, OTG_LOCK, 0, 1);
    74		unblank = find_write(unlock + 1, OTG_BLANK, 0, 0x00010100);
    75		assert_true(high < low);
    76		assert_true(low < hubp);
    77		assert_true(hubp < unlock);
    78		assert_true(unlock < unblank);
    79		assert_true(unblank < mmio_trace_count);
    80	}
    81	
    82	static uint32_t *fake_reg(uint32_t reg)
    83	{
    84		return (uint32_t *)(fake_mmio + DCN_REG(reg));
    85	}
    86	
    87	void udelay(unsigned int usecs)
    88	{
    89		uint32_t hubp;
    90	
    91		(void)usecs;
    92		if (!fake_mmio)
    93			return;
    94		if ((*fake_reg(INPUT_CLOCK) & 3) == 3)
    95			*fake_reg(INPUT_CLOCK) |= 1U << 2;
    96		if ((*fake_reg(OTG_CLOCK) & 3) == 3)
    97			*fake_reg(OTG_CLOCK) |= 1U << 8;
    98		if (*fake_reg(OTG_CONTROL) & 1) {
    99			*fake_reg(OTG_CONTROL) |= 1U << 16;
   100			(*fake_reg(OTG_FRAME_COUNT))++;
   101		}
   102		if (*fake_reg(OTG_LOCK) & 1)
   103			*fake_reg(OTG_LOCK) |= 1U << 8;
   104		else
   105			*fake_reg(OTG_LOCK) &= ~(1U << 8);
   106		hubp = *fake_reg(DCHUBP_CNTL) | (1U << 1);
   107		if (hubp & 1) {
   108			hubp |= 1U << 3;
   109		} else {
   110			hubp &= ~(1U << 3);
   111			*fake_reg(DCSURF_EARLIEST) = *fake_reg(DCSURF_ADDRESS);
   112			*fake_reg(DCSURF_EARLIEST_HIGH) = *fake_reg(DCSURF_ADDRESS_HIGH);
   113		}
   114		*fake_reg(DCHUBP_CNTL) = hubp;
   115	}
   116	
   117	void mdelay(unsigned int msecs)
   118	{
   119		while (msecs--)
   120			udelay(1000);
   121	}
   122	
   123	static const struct dcn10_timing vilboz_mode = {
   124		.h_active = 1366,
   125		.h_blank = 160,
   126		.h_front_porch = 48,
   127		.h_sync_width = 32,
   128		.v_active = 768,
   129		.v_blank = 25,
   130		.v_front_porch = 3,
   131		.v_sync_width = 5,
   132		.pixel_clock_khz = 72700,
   133		.ref_clock_khz = 48000,
   134		.disp_clock_khz = 600000,
   135	};
   136	
   137	static void test_vilboz_plane_calculation(void **state)
   138	{
   139		struct dcn10_plane_regs regs;
   140	
   141		(void)state;
   142		assert_int_equal(dcn10_calculate_plane(&vilboz_mode, 1408, &regs), 0);
   143		assert_int_equal(regs.expansion_mode, 0x56);
   144		assert_int_equal(regs.request_size, 0x055d1b70);
   145		assert_int_equal(regs.blank_offset_0, 0x00160049);
   146		assert_int_equal(regs.blank_offset_1, 0x00000c59);
   147		assert_int_equal(regs.dst_dimensions, 0x0003ef89);
   148		assert_int_equal(regs.ref_freq_to_pix_freq, 0x0005482f);
   149		assert_int_equal(regs.prefetch_settings, 0x2d080000);
   150		assert_int_equal(regs.vblank_parameters_0, 0x301);
   151		assert_int_equal(regs.per_line_delivery, 0x385);
   152		assert_int_equal(regs.surf0_ttu_cntl0, 0x0800a3d1);
   153		assert_int_equal(regs.global_ttu_cntl, 0xe0000150);
   154		assert_int_equal(regs.vstartup, 13);
   155		assert_int_equal(regs.vupdate, 0x0082017e);
   156		assert_int_equal(regs.vready, 184);
