    13	static void put_le16(uint8_t *p, uint16_t value)
    14	{
    15		p[0] = value;
    16		p[1] = value >> 8;
    17	}
    18	
    19	static void put_le32(uint8_t *p, uint32_t value)
    20	{
    21		put_le16(p, value);
    22		put_le16(p + 2, value >> 16);
    23	}
