    25	static void make_display_info_v1_4(uint8_t *table, size_t size)
    26	{
    27		assert_true(size >= 42);
    28		memset(table, 0, size);
    29		put_le16(table, 42);
    30		table[2] = 1;
    31		table[3] = 4;
    32		put_le16(table + 4, 0x0008);
    33		table[6] = 1;
    34	
    35		put_le16(table + 8, 0x310c);  /* HDMI-A connector, enum 1 */
    36		put_le16(table + 10, 24);
    37		put_le16(table + 12, 0x211e); /* UNIPHY, enum 1 */
    38		put_le16(table + 16, 34);
    39		put_le16(table + 20, 0x0008);
    40		table[22] = 1;
    41	
    42		table[24] = ATOM_V2_I2C_RECORD_TYPE;
    43		table[25] = sizeof(struct atom_v2_i2c_record);
    44		table[26] = 0x91;
    45		table[27] = 0;
    46		table[28] = ATOM_V2_HPD_INT_RECORD_TYPE;
    47		table[29] = sizeof(struct atom_v2_hpd_int_record);
    48		table[30] = 3;
    49		table[31] = 1;
    50		table[32] = ATOM_V2_RECORD_END_TYPE;
    51	
    52		table[34] = ATOM_V2_ENCODER_CAP_RECORD_TYPE;
    53		table[35] = sizeof(struct atom_v2_encoder_caps_record);
    54		put_le32(table + 36, 0x11223344);
    55		table[40] = ATOM_V2_RECORD_END_TYPE;
    56	}
    57	
    58	static void make_display_info_v1_5(uint8_t *table, size_t size)
    59	{
