   113	static void test_display_info_rejects_malformed_tables(void **state)
   114	{
   115		uint8_t table[42];
   116		struct atom_v2_display_info info;
   117	
   118		make_display_info_v1_4(table, sizeof(table));
   119		table[3] = 6;
   120		assert_int_not_equal(atom_v2_parse_display_object_info(table, sizeof(table), &info), 0);
   121	
   122		make_display_info_v1_4(table, sizeof(table));
   123		table[6] = ATOM_V2_MAX_DISPLAY_PATHS + 1;
   124		assert_int_not_equal(atom_v2_parse_display_object_info(table, sizeof(table), &info), 0);
   125	
   126		make_display_info_v1_4(table, sizeof(table));
   127		put_le16(table + 10, sizeof(table));
   128		assert_int_not_equal(atom_v2_parse_display_object_info(table, sizeof(table), &info), 0);
   129	
   130		make_display_info_v1_4(table, sizeof(table));
   131		put_le16(table + 10, 8);
   132		assert_int_not_equal(atom_v2_parse_display_object_info(table, sizeof(table), &info), 0);
   133	
   134		make_display_info_v1_4(table, sizeof(table));
   135		table[25] = 1;
   136		assert_int_not_equal(atom_v2_parse_display_object_info(table, sizeof(table), &info), 0);
   137	
   138		make_display_info_v1_4(table, sizeof(table));
   139		put_le16(table, sizeof(table) + 1);
   140		assert_int_not_equal(atom_v2_parse_display_object_info(table, sizeof(table), &info), 0);
   141	}
