   143	static void test_bounded_master_table_lookup(void **state)
   144	{
   145		uint8_t bios[128] = {0};
   146		const void *table;
   147		size_t table_size;
   148	
   149		put_le16(bios + 16, 10);
   150		put_le16(bios + 16 + 8, 64); /* index 2 */
   151		put_le16(bios + 64, 8);
   152		bios[66] = 1;
   153		bios[67] = 4;
   154		assert_int_equal(atom_v2_get_table(bios, sizeof(bios), 16, 2,
   155						   &table, &table_size), 0);
   156		assert_ptr_equal(table, bios + 64);
   157		assert_int_equal(table_size, 8);
   158	
   159		put_le16(bios + 16 + 8, 124);
   160		assert_int_not_equal(atom_v2_get_table(bios, sizeof(bios), 16, 2,
   161						       &table, &table_size), 0);
   162	}
