   164	static void test_bounded_rom_header(void **state)
   165	{
   166		uint8_t bios[128] = {0};
   167		struct atom_v2_rom_info info;
   168	
   169		put_le16(bios, 0xaa55);
   170		put_le16(bios + 0x48, 0x50);
   171		put_le16(bios + 0x50, 0x26);
   172		bios[0x52] = 2;
   173		bios[0x53] = 2;
   174		memcpy(bios + 0x54, "ATOM", 4);
   175		put_le16(bios + 0x50 + 0x1e, 0x20);
   176		put_le16(bios + 0x50 + 0x20, 0x30);
   177		put_le16(bios + 0x20, 4);
   178		bios[0x22] = 2;
   179		put_le16(bios + 0x30, 4);
   180		bios[0x32] = 2;
   181	
   182		assert_int_equal(atom_v2_parse_rom_header(bios, sizeof(bios), &info), 0);
   183		assert_int_equal(info.command_table_offset, 0x20);
   184		assert_int_equal(info.data_table_offset, 0x30);
   185	
   186		put_le16(bios + 0x48, sizeof(bios));
   187		assert_int_not_equal(atom_v2_parse_rom_header(bios, sizeof(bios), &info), 0);
   188	}
